public class ZAddParams {
    private CommandKeyword existence;
    private CommandKeyword comparison;
    private boolean change;

    public ZAddParams() {
        this.existence = null;
        this.comparison = null;
        this.change = false;
    }

    public ZAddParams nx() {
        this.existence = CommandKeyword.NX;
        return this;
    }

    public ZAddParams xx() {
        this.existence = CommandKeyword.XX;
        return this;
    }

    public ZAddParams gt() {
        this.comparison = CommandKeyword.GT;
        return this;
    }

    public ZAddParams lt() {
        this.comparison = CommandKeyword.LT;
        return this;
    }

    public ZAddParams ch() {
        this.change = true;
        return this;
    }

    public void buildArgs(CommandArgs commandArgs) {
        if (this.existence != null) {
            commandArgs.add(this.existence);
        }

        if (this.comparison != null) {
            commandArgs.add(this.comparison);
        }

        if (this.change) {
            commandArgs.add(CommandKeyword.CH);
        }
    }
}

