    synchronized (lock) {
        // If we haven't indicated willingness to respond to this option,
        // and the current state is WONT, OR we've already requested WONT for this option,
        // then skip further processing.
        if (willResponse[option] == 0 && stateIsWont(option) || requestedWont(option)) {
            return;
        }
        setWantWont(option);
        doResponse[option] = doResponse[option] + 1;
        sendWont(option);
    }
}

