public class BadgeFixTabsIndicator {
    private BadgeFixTabsModel model = new BadgeFixTabsModel();
    private List<String> titles = new ArrayList<>();
    private double startX = 0.0;
    private double offsets = 0.0;
    private double indicatorOffset = 0.0;
    private boolean isInClick = false;
    private boolean isOnTouch = false;
    private List<BadgeType> badgeType = new ArrayList<>();
    private long newIndex = 0L;
    private Timer timeoutId = Timer.once(Duration.millisecond, () -> {});

    // @Link + @Watch[itemIndexChange] simulated via field + manual trigger
    private long itemIndex = -1L;
    private final List<Runnable> itemIndexChangeListeners = new ArrayList<>();

    public BadgeFixTabsIndicator() {
        // Register listener for itemIndex changes
        itemIndexChangeListeners.add(this::itemIndexChange);
    }

    private void itemIndexChange() {
        timeoutId.cancel();
        reset();

        if (model.isAutoCancelBadge()) {
            // Note: model.mBadgeTypes is assumed to be accessible; if not, use setter/getter
            List<BadgeType> badgeTypes = model.getBadgeTypes();
            if (itemIndex >= 0 && itemIndex < badgeTypes.size()) {
                badgeTypes.set((int) itemIndex, BadgeType.NONE);
                model.setBadgeTypes(new ArrayList<>(badgeTypes));
            }
        }

        Consumer<Integer> changeListener = model.getChangeListener();
        if (changeListener != null) {
            if ((isInClick || isOnTouch) && itemIndex != newIndex) {
                return;
            }
            changeListener.accept((int) itemIndex);
        }
    }

    private double comFontSize(long index, long itemIndex) {
        double offset = indicatorOffset / model.getWidth();
        float textSize = model.getUnselectedTextSize();
        float selectedTextSize = model.getSelectedTextSize();
        List<String> arr = titles;

        if (index == itemIndex) {
            if ((itemIndex > 0 && offset > 0.0) || (itemIndex < arr.size() - 1 && offset < 0.0)) {
                return Math.abs(offset) * textSize + (1.0 - Math.abs(offset)) * selectedTextSize;
            }
            return selectedTextSize;
        } else if (itemIndex > 0 && index == itemIndex - 1 && offset > 0.0) {
            return Math.abs(offset) * selectedTextSize + (1.0 - Math.abs(offset)) * textSize;
        } else if (itemIndex < arr.size() - 1 && index == itemIndex + 1 && offset < 0.0) {
            return Math.abs(offset) * selectedTextSize + (1.0 - Math.abs(offset)) * textSize;
        }

        return textSize;
    }

    private double getOffsetXMaxValue(long itemIndex) {
        List<Float> widths = model.getItemWidths();
        float width = widths.get((int) itemIndex);
        float nextWidth = 0.0f;

        if (indicatorOffset > 0.0) {
            if (itemIndex > 0) {
                nextWidth = widths.get((int) (itemIndex - 1));
            }
        } else {
            if (itemIndex < widths.size() - 1) {
                nextWidth = widths.get((int) (itemIndex + 1));
            }
        }

        double offsetX = 0.0;

        if (indicatorOffset > 0.0 && itemIndex > 0) {
            double ratio = indicatorOffset / model.getWidth();
            if ((ratio - 0.25) < 0.0) {
                offsetX = -ratio * 4.0 * nextWidth;
            } else {
                offsetX = -nextWidth;
            }
        } else if (indicatorOffset < 0.0 && itemIndex < titles.size() - 1) {
            double ratio = indicatorOffset / model.getWidth();
            if ((ratio + 0.25) > 0.0) {
                offsetX = 0.0;
            } else {
                if ((ratio + 0.5) > 0.0) {
                    offsetX = -(ratio + 0.25) * 4.0 * width;
                } else {
                    offsetX = width;
                }
            }
        }
        return offsetX;
    }

    private List<Double> calOffsetX() {
        List<Double> badgeOffsetX = new ArrayList<>();
        List<BadgeRule> rules = model.getXBadgeRules();
        List<Float> widths = model.getItemWidths();

        if (!rules.isEmpty()) {
            badgeOffsetX = new ArrayList<>(Collections.nCopies(rules.size(), 0.0));
            for (int i = 0; i < rules.size(); i++) {
                BadgeRule badgeRule = rules.get(i);
                BadgeAnchor anchor = badgeRule.getAnchor();
                double offset = badgeRule.getOffset();
                double x = 0.0;

                if (anchor == BadgeAnchor.LEFT && i < widths.size()) {
                    x = -widths.get(i) / 2.0;
                } else if (anchor == BadgeAnchor.CENTER_X) {
                    x = 0.0;
                } else if (anchor == BadgeAnchor.RIGHT && i < widths.size()) {
                    x = widths.get(i) / 2.0;
                }
                badgeOffsetX.set(i, x + offset);
            }
        }
        return badgeOffsetX;
    }

    private List<Double> calOffsetY() {
        List<Double> badgeOffsetY = new ArrayList<>();
        List<BadgeRule> rules = model.getYBadgeRules();

        if (!rules.isEmpty()) {
            badgeOffsetY = new ArrayList<>(Collections.nCopies(rules.size(), 0.0));
            for (int i = 0; i < rules.size(); i++) {
                BadgeRule yBadgeRules = rules.get(i);
                BadgeAnchor anchor = yBadgeRules.getAnchor();
                double offset = yBadgeRules.getOffset();
                double y = 0.0;

                if (anchor == BadgeAnchor.TOP) {
                    y = -model.getHeight() / 2.0;
                } else if (anchor == BadgeAnchor.CENTER_Y) {
                    y = 0.0;
                } else if (anchor == BadgeAnchor.BOTTOM) {
                    y = model.getHeight() / 2.0;
                }
                badgeOffsetY.set(i, y + offset);
            }
        }
        return badgeOffsetY;
    }

    protected void aboutToAppear() {
        Display displayClass = getDefaultDisplaySync();
        float displayW = px2vp(new Length(displayClass.width, LengthType.px));
        List<String> t = titles;

        if (model.getItemWidths().size() < t.size()) {
            List<Float> widths = new ArrayList<>();
            float wPerItem = displayW / t.size();
            for (int i = 0; i < t.size(); i++) {
                widths.add(wPerItem);
            }
            model.setItemWidths(widths);
        }

        if (model.getBadgeTypes().size() < t.size()) {
            List<BadgeType> types = new ArrayList<>(Collections.nCopies(t.size(), BadgeType.NONE));
            model.setBadgeTypes(types);
        }

        badgeType = new ArrayList<>(model.getBadgeTypes());

        model.setOnPageTouchListener((eventAndIndex) -> {
            onIndicatorTouch(eventAndIndex.event, eventAndIndex.currentIndex);
        });
    }

    private void onIndicatorTouch(TouchEvent event, long currentIndex) {
        long itemIndex = currentIndex;
        double startX = this.startX;
        this.offsets = 0.0;

        switch (event.getEventType()) {
            case Down:
                this.startX = event.getTouches().get(0).x;
                break;
            case Move:
                this.offsets = event.getTouches().get(0).x - startX;
                if ((this.offsets >= 0.0 && currentIndex > 0) ||
                    (this.offsets <= 0.0 && currentIndex < titles.size() - 1)) {
                    this.indicatorOffset = this.offsets;
                }
                break;
            case Up:
                if (this.indicatorOffset >= model.getWidth() / 2.0 && itemIndex > 0) {
                    itemIndex--;
                } else if (this.indicatorOffset <= -model.getWidth() / 2.0 && itemIndex < titles.size() - 1) {
                    itemIndex++;
                }

                Optional<TabsController> controller = model.getTabsController();
                if (controller.isPresent()) {
                    controller.get().changeIndex((int) itemIndex);
                }

                this.offsets = 0.0;
                this.indicatorOffset = this.offsets;
                this.itemIndex = itemIndex;
                this.newIndex = itemIndex;
                reset();
                break;
        }
    }

    private void reset() {
        this.indicatorOffset = 0.0;
        this.newIndex = this.itemIndex;
        this.isOnTouch = false;
    }

    public void build() {
        // Simulated UI building — actual rendering depends on framework
        // This is a structural translation only.

        Flex flex = new Flex(new FlexParams(FlexDirection.Row, FlexAlign.Center))
            .width(model.getWidth())
            .height(model.getHeight())
            .backgroundColor(model.getBackgroundColor());

        for (int index = 0; index < titles.size(); index++) {
            String item = titles.get(index);

            // Column
            Column column = new Column();

            // Stack
            Stack stack = new Stack();

            // Indicator Rect (only for active tab)
            if (index == this.itemIndex) {
                float w = model.getItemWidths().get(index);
                float h = model.getIndicatorHeight();
                float x;
                if (model.isIndicatorAnimation()) {
                    x = (float) getOffsetXMaxValue(this.newIndex);
                } else {
                    x = (float) (model.getItemWidths().get((int) this.newIndex) * (-this.indicatorOffset / model.getWidth()));
                }
                float y = model.getIndicatorYOffset();

                new Rect(w, h)
                    .fill(model.getIndicatorColor())
                    .offset(x, y);
            }

            // Text
            float textW = model.getItemWidths().get(index);
            float textH = model.getHeight();
            Color textColor = (index == this.itemIndex) ? model.getSelectedTextColor() : model.getUnselectedTextColor();
            float fontSize = model.isChangeTextSize() ? (float) comFontSize(index, this.newIndex) : model.getUnselectedTextSize();

            new Text(item)
                .width(textW)
                .height(textH)
                .textAlign(TextAlign.Center)
                .fontColor(textColor)
                .fontSize(fontSize);

            // Badge
            if (index < badgeType.size() && badgeType.get(index) == BadgeType.DOT) {
                List<Double> offsetXs = calOffsetX();
                List<Double> offsetYs = calOffsetY();
                double xOff = (index < offsetXs.size()) ? offsetXs.get(index) : 0.0;
                double yOff = (index < offsetYs.size()) ? offsetYs.get(index) : 0.0;

                new Circle()
                    .width(8)
                    .height(8)
                    .fill(Color.RED)
                    .offset((float) xOff, (float) yOff);
            } else if (index < badgeType.size() && badgeType.get(index) == BadgeType.COUNT) {
                List<Double> offsetXs = calOffsetX();
                List<Double> offsetYs = calOffsetY();
                double xOff = (index < offsetXs.size()) ? offsetXs.get(index) : 0.0;
                double yOff = (index < offsetYs.size()) ? offsetYs.get(index) : 0.0;

                Stack badgeStack = new Stack(Alignment.Center);
                List<String> badgeTexts = model.getBadgeTexts();
                List<float[]> badgeWH = model.getBadgeTextsWH();

                if (badgeTexts.size() <= index || badgeTexts.get(index).length() < 2) {
                    new Circle()
                        .width(8)
                        .height(8)
                        .fill(Color.RED);
                } else {
                    float[] wh = (badgeWH.size() > index) ? badgeWH.get(index) : new float[]{16f, 16f};
                    new Rect()
                        .width(wh[0] / 1.5f)
                        .height(wh[1] / 2.0f)
                        .radius(wh[0])
                        .fill(Color.RED);
                }

                String badgeText = (badgeTexts.size() <= index) ? "" :
                    (badgeTexts.get(index).length() > 2) ? "99+" : badgeTexts.get(index);
                new Text(badgeText)
                    .fontSize(9)
                    .fontWeight(FontWeight.Bold)
                    .fontColor(Color.WHITE);

                badgeStack.offset((float) xOff, (float) yOff);
            }
            // else BadgeType.NONE → no badge

            // onClick handler
            // In real Java UI, would attach lambda; here just note logic
            // .onClick(() -> {
            //     this.isInClick = true;
            //     this.newIndex = index;
            //     this.itemIndex = index;
            //     this.isInClick = false;
            //     model.getClickListener().accept((int) this.itemIndex);
            //     if (this.badgeType.size() > index) {
            //         this.badgeType.set(index, BadgeType.NONE);
            //     }
            // })

            // Split line
            if (model.isSplit() && index < titles.size() - 1) {
                new Rect(1, 40)
                    .fill(model.getUnselectedTextColor())
                    .padding(15);
            }
        }

        // Return or render flex (framework-dependent)
    }
}

