        }
        //向左滑动
        else if (this.indicatorOffset < 0.0 && itemIndex < this.titles.size - 1) {
            if ((this.indicatorOffset / this.model.getWidth() + 1.0 / 4.0) > 0.0) {
                offsetX = 0.0
            } else {
                if ((this.indicatorOffset / this.model.getWidth() + 1.0 / 2.0) > 0.0) {
                    offsetX = -(this.indicatorOffset / this.model.getWidth() + 1.0 / 4.0) * 4.0 * width
                } else {
                    offsetX = width
                }
            }
        }
        return offsetX
    }

    func calOffsetX(): Array<Float64> {
        var badgeOffsetX: Array<Float64> = Array<Float64>(this.model.getXBadgeRules().size, item: 0.0)
        if (this.model.getXBadgeRules().size != 0) {
            badgeOffsetX = Array<Float64>(this.model.getXBadgeRules().size, item: 0.0 )
            for (i in 0..this.model.getXBadgeRules().size) {
                let badgeRule = this.model.getXBadgeRules()[i]

                let anchor = badgeRule.getAnchor()
                if (anchor == BadgeAnchor.LEFT) {
                    badgeOffsetX[i] = -this.model.getItemWidths()[i] / 2.0
                } else if (anchor == BadgeAnchor.CENTER_X) {
                    badgeOffsetX[i] = 0.0
                } else if (anchor == BadgeAnchor.RIGHT) {
                    badgeOffsetX[i] = this.model.getItemWidths()[i] / 2.0
                }

                let offset = badgeRule.getOffset()
                badgeOffsetX[i] += offset

            }
        }

        return badgeOffsetX
    }

    func calOffsetY(): Array<Float64> {
        let badgeOffsetY: Array<Float64> = Array<Float64>(this.model.getYBadgeRules().size, item: 0.0)
        for (i in 0..this.model.getYBadgeRules().size) {
            let yBadgeRules = this.model.getYBadgeRules()[i]

            if (yBadgeRules.getAnchor() == BadgeAnchor.TOP) {
                badgeOffsetY[i] = -this.model.getHeight() / 2.0
            }
            if (yBadgeRules.getAnchor() == BadgeAnchor.CENTER_Y) {
                badgeOffsetY[i] = 0.0
            }
            if (yBadgeRules.getAnchor() == BadgeAnchor.BOTTOM) {
                badgeOffsetY[i] = this.model.getHeight() / 2.0
            }
            let offset = yBadgeRules.getOffset()
            badgeOffsetY[i] += offset

        }
        return badgeOffsetY
    }

    protected override func aboutToAppear() : Unit {
        let displayClass: Display = getDefaultDisplaySync()
        let displayW = px2vp(Length(Float64(Float32(displayClass.width)), unitType: LengthType.px)).getOrThrow().value
        if(this.model.getItemWidths().size < this.titles.size) {
            this.model.setItemWidths(Array<Float64>(this.titles.size, item: displayW / Float64(this.titles.size)) )
        }
        if(this.model.getBadgeTypes().size < this.titles.size) {
            this.model.setBadgeTypes(Array<BadgeType>(this.titles.size, item: BadgeType.NONE))
        }
        this.badgeType = this.model.getBadgeTypes()
        this.model.setOnPageTouchListener({event: TouchEvent, currentIndex: Int64 =>
            this.onIndicatorTouch(event, currentIndex);
        })
    }

    func onIndicatorTouch(event: TouchEvent, currentIndex: Int64) {
        var itemIndex: Int64 = currentIndex
        let startX = this.startX
        this.offsets = 0.0
        match(event.eventType) {
            case TouchType.Down =>
                this.startX = event.touches[0].x
            case TouchType.Move =>
                this.offsets = event.touches[0].x - startX
                if ((this.offsets >= 0.0 && currentIndex > 0) || (this.offsets <= 0.0 && Int64(currentIndex) < this.titles.size - 1)) {
                    this.indicatorOffset = this.offsets
                }
            case TouchType.Up =>

                 if (this.indicatorOffset >= this.model.getWidth() / 2.0 && itemIndex > 0) {
                    itemIndex--
                }
                else if (this.indicatorOffset <= -this.model.getWidth() / 2.0 && itemIndex < this.titles.size - 1
                ) {
                    itemIndex++
                }
                if(let Some(tabsController) <- this.model.getTabsController()) {
                    tabsController.changeIndex(Int32(itemIndex))
                }

                this.offsets = 0.0
                this.indicatorOffset = this.offsets
                this.itemIndex = itemIndex
                this.reset()
            case _=>()
        }

    }

    func reset() {
        this.indicatorOffset = 0.0
        this.newIndex = this.itemIndex
        this.isOnTouch = false
    }

    func build() {
        Flex( FlexParams(direction: FlexDirection.Row, justifyContent: FlexAlign.Center) ) {
            ForEach(this.titles, itemGeneratorFunc: {item: String, index: Int64 =>
                Column() {
                    Stack() {
                        if (index == this.itemIndex) {
                            Rect(width: this.model.getItemWidths()[index], height: this.model.getIndicatorHeight())
                                .fill(this.model.getIndicatorColor())
                                .offset(
                                    x: if(this.model.isIndicatorAnimation()) {
                                        this.getOffsetXMaxValue(this.newIndex)}
                                    else {
                                        this.model.getItemWidths()[this.newIndex] * (-this.indicatorOffset / this.model.getWidth())
                                    },
                                    y: if(this.model.isIndicatorAnimation()) {
                                        this.model.getIndicatorYOffset()
                                    } else {
                                        this.model.getIndicatorYOffset()
                                    })

                        }

                        Text("${this.titles[index]}")
                            .width(this.model.getItemWidths()[index])
                            .height(this.model.getHeight())
                            .textAlign(TextAlign.Center)
                            .fontColor(if(index == this.itemIndex) {this.model.getSelectedTextColor() } else { this.model.getUnselectedTextColor()})
                            .fontSize(if(this.model.isChangeTextSize()) {this.comFontSize(index, this.newIndex)} else {this.model.getUnselectedTextSize() })

                        if (this.badgeType[index] == BadgeType.DOT) {
                            Circle()
                                .width(8)
                                .height(8)
                                .fill(Color.RED)
                                .offset(
                                    x: if(index < this.calOffsetX().size) {
                                       this.calOffsetX()[index]
                                    } else {
                                         0.0
                                    },
                                     y: if(index < this.calOffsetY().size) {
                                        this.calOffsetY()[index]
                                     } else {
                                        0.0
                                     } )
                        } else if (this.badgeType[index] == BadgeType.COUNT) {
                            Stack(Alignment.Center) {
                                if(this.model.getBadgeTexts()[index].size < 2 ) {
                                    Circle()
                                    .width(8)
                                    .height(8)
                                    .fill(Color.RED)
                                } else {
                                    Rect()
                                    .width(this.model.getBadgeTextsWH()[0][index] / 1.5)
                                    .height(this.model.getBadgeTextsWH()[1][index] / 2.0)
                                    .radius(this.model.getBadgeTextsWH()[0][index])
                                    .fill(Color.RED)
                                }

                                Text(if(this.model.getBadgeTexts()[index].size > 2) {
                                    "99+"
                                } else {
                                   "${this.model.getBadgeTexts()[index]}"
                                })
                                    .fontSize(9)
                                    .fontWeight(FontWeight.Bold)
                                    .fontColor(Color.WHITE)
                            }
                             .offset(
                                x: if(index < this.calOffsetX().size) {
                                   this.calOffsetX()[index]
                                } else {
                                     0.0
                                },
                                 y: if(index < this.calOffsetY().size) {
                                    this.calOffsetY()[index]
                                 } else {
                                    0.0
                                 } )
                         } else if(this.badgeType[index] == BadgeType.NONE) {}
                   }.onClick({ evt =>
                        this.isInClick = true
                        this.newIndex = index
                        this.itemIndex = index
                        this.isInClick = false
                        this.model.getClickListener()(this.itemIndex)
                        this.badgeType[index] = BadgeType.NONE
                    })
               }.height(this.model.getHeight())

                if (this.model.isSplit()) {
                    if (index < this.titles.size - 1) {
                        Rect( width: 1, height: 40 )
                            .fill(this.model.getUnselectedTextColor())
                            .padding( top: 15 )
                    }
                }

            })
        }
         .width(this.model.getWidth())
         .height(this.model.getHeight())
        .backgroundColor(this.model.getBackgroundColor())
    }

}

