public class StringUtils {
    /**
     * Converts a C-style string buffer to a Java String, checking for null pointer first.
     * Returns null if the 'isNull' flag is true (i.e., the string is logically null).
     *
     * @param buffer Pointer to the C string (uint8_t*), may be null
     * @param isNull Pointer to a boolean indicating whether the string is null
     * @return the decoded string, or null if isNull indicates absence
     */
    public static String getString(Pointer buffer, Pointer isNull) {
        // Read the boolean flag from isNull pointer (assuming 1-byte bool)
        boolean isNullFlag = isNull.getByte(0) != 0;
        if (isNullFlag) {
            return null;
        } else {
            // Convert C string pointer to Java String; handles null-termination automatically
            return buffer != null ? buffer.getString(0) : null;
        }
    }
}

