    long start = (long) startNum;
    short len = (short) length;
    int last_val = last ? 1 : 0;
    sendBits((STORED_BLOCK << 1) + last_val, 3);
    bitsFlushAlign();
    putShort(len & 0xFFFF);
    putShort((len ^ 0xFFFF) & 0xFFFF);
