import java.util.*;

// Sliding window iterator that yields ArrayList<T> windows over an underlying Iterator<T>,
// advancing by 'stepSize' elements each time, with optional optimization for step < windowSize.
public class SlidingWindowStepIterator<T> implements Iterator<List<T>> {
    private final Iterator<T> base;
    private final long windowSize;
    private final long stepSize;
    private final RingBuffer<T> buffer; // RingBuffer is assumed to be a custom class (see below)
    private boolean initialized;
    private boolean exhausted;

    public SlidingWindowStepIterator(Iterator<T> base, long windowSize, long stepSize) {
        this.base = base;
        this.windowSize = windowSize;
        this.stepSize = stepSize;
        // Use at least size 1 to avoid zero-capacity buffer
        this.buffer = new RingBuffer<>(windowSize > 0 ? (int) windowSize : 1);
        this.initialized = false;
        this.exhausted = false;
    }

    @Override
    public boolean hasNext() {
        // Conservative: if exhausted, no more; otherwise, we need to simulate next() logic
        // Since full lookahead is expensive, we assume hasNext() is best-effort — typical for stateful iterators.
        // For strict compliance, one could precompute or cache next result, but that breaks single-consumption semantics.
        // So we follow common practice: hasNext() may return true even if next() later returns null (e.g., due to exhaustion during fill).
        return !exhausted;
    }

    @Override
    public List<T> next() {
        // Boundary cases: invalid sizes → no windows
        if (windowSize <= 0 || stepSize <= 0) {
            exhausted = true;
            return null;
        }

        if (exhausted) {
            return null;
        }

        if (!initialized) {
            // Initialize: fill first window
            long count = 0;
            while (count < windowSize) {
                if (base.hasNext()) {
                    buffer.pushBack(base.next());
                    count++;
                } else {
                    exhausted = true;
                    return null;
                }
            }
            initialized = true;
            return buffer.toArrayList();
        }

        // Sliding logic
        if (stepSize >= windowSize) {
            // Step >= windowSize: skip (step - windowSize) elements, then refill full window
            long skipCount = 0;
            long skipTarget = stepSize - windowSize;
            while (skipCount < skipTarget) {
                if (base.hasNext()) {
                    base.next();
                    skipCount++;
                } else {
                    exhausted = true;
                    return null;
                }
            }

            // Clear and refill window
            buffer.clear();
            long fillCount = 0;
            while (fillCount < windowSize) {
                if (base.hasNext()) {
                    buffer.pushBack(base.next());
                    fillCount++;
                } else {
                    exhausted = true;
                    return null;
                }
            }
            return buffer.toArrayList();
        } else {
            // step < windowSize: slide by popping 'stepSize' from front and pushing 'stepSize' from base
            long i = 0;
            while (i < stepSize) {
                buffer.popFront(); // O(1), assumes non-empty (guaranteed by prior full fill & step < size)
                if (base.hasNext()) {
                    buffer.pushBack(base.next());
                    i++;
                } else {
                    exhausted = true;
                    return null;
                }
            }
            return buffer.toArrayList();
        }
    }

    // Optional: support remove() if needed (not in original, so left unimplemented per default contract)
    @Override
    public void remove() {
        throw new UnsupportedOperationException("remove() is not supported");
    }

    // Minimal RingBuffer implementation required for compilation and semantic equivalence.
    // Note: This is an internal helper — real usage may replace with optimized version.
    private static class RingBuffer<E> {
        private final Object[] data;
        private int head;
        private int tail;
        private int size;
        private final int capacity;

        @SuppressWarnings("unchecked")
        RingBuffer(int capacity) {
            this.capacity = capacity;
            this.data = new Object[capacity];
            this.head = 0;
            this.tail = 0;
            this.size = 0;
        }

        void pushBack(E item) {
            if (size < capacity) {
                data[tail] = item;
                tail = (tail + 1) % capacity;
                size++;
            } else {
                // Overwrite oldest on overflow — consistent with sliding semantics
                data[tail] = item;
                tail = (tail + 1) % capacity;
                head = (head + 1) % capacity;
            }
        }

        @SuppressWarnings("unchecked")
        E popFront() {
            if (size == 0) {
                return null;
            }
            E item = (E) data[head];
            data[head] = null;
            head = (head + 1) % capacity;
            size--;
            return item;
        }

        void clear() {
            Arrays.fill(data, null);
            head = 0;
            tail = 0;
            size = 0;
        }

        List<E> toArrayList() {
            List<E> list = new ArrayList<>(size);
            int idx = head;
            for (int i = 0; i < size; i++) {
                @SuppressWarnings("unchecked")
                E item = (E) data[idx];
                list.add(item);
                idx = (idx + 1) % capacity;
            }
            return list;
        }
    }
}

