                token: token
            )
        }
        if (numHasLeadingZero(token.value)) {
            error(
                "invalid integer '${token.value}': cannot have leading zeros",
                token: token
            )
        }

        return match (parseInt64(token.value)) {
            case Some(v) =>
                (DataModelInt(v), typeOfPrimitive(token))
            case None =>
                error("expected integer value, but got '${token.value}' instead.")
        }
    }

