import java.util.*;
import java.util.stream.Collectors;

public class JsonHttpMetricExporter implements MetricExporter {
    private final JsonHttpTransport transport;
    private Map<String, AttributeValue> resourceAttributes;

    public JsonHttpMetricExporter(String endpoint) {
        this(endpoint, 5000L, new HashMap<>());
    }

    public JsonHttpMetricExporter(String endpoint, long timeoutMs, Map<String, String> headers) {
        this.transport = new JsonHttpTransport(endpoint, timeoutMs, headers);
        this.resourceAttributes = new HashMap<>();
    }

    public boolean export(List<MetricData> metrics) {
        if (metrics == null || metrics.isEmpty()) {
            return true;
        }
        String payload = buildPayload(metrics);
        return transport.send(payload);
    }

    public void shutdown() {
        // no-op
    }

    public void updateResourceAttributes(Map<String, AttributeValue> attributes) {
        if (attributes == null) {
            this.resourceAttributes = new HashMap<>();
        } else {
            this.resourceAttributes = new HashMap<>(attributes);
        }
    }

    private String buildPayload(List<MetricData> metrics) {
        // Convert MetricData objects to OTLP format and wrap in request envelope.
        OtlpMetricExportRequest request = new OtlpMetricExportRequest();

        if (metrics != null && !metrics.isEmpty()) {
            OtlpResource resource = new OtlpResource();
            resource.setAttributes(OtlpJsonUtils.mapAttributes(resourceAttributes).toArray(new OtlpKeyValue[0]));

            List<OtlpScopeMetrics> scopeMetrics = new ArrayList<>();
            OtlpInstrumentationScope scope = new OtlpInstrumentationScope();
            scope.setName("default");
            scope.setVersion("1.0.0");

            List<OtlpMetric> otlpMetrics = new ArrayList<>();
            for (MetricData metricData : metrics) {
                otlpMetrics.add(convertMetricData(metricData));
            }

            OtlpScopeMetrics scopeMetric = new OtlpScopeMetrics();
            scopeMetric.setScope(scope);
            scopeMetric.setMetrics(otlpMetrics);
            scopeMetrics.add(scopeMetric);

            OtlpResourceMetrics resourceMetric = new OtlpResourceMetrics();
            resourceMetric.setResource(resource);
            resourceMetric.setScopeMetrics(scopeMetrics);
            request.getResourceMetrics().add(resourceMetric);
        }

        return request.toJsonValue().toJsonString();
    }

    private OtlpMetric convertMetricData(MetricData metricData) {
        OtlpMetric metric = new OtlpMetric();
        metric.setName(metricData.getName());
        metric.setDescription(metricData.getDescription());
        metric.setUnit(metricData.getUnit());

        // Convert MetricData to a gauge OTLP metric
        OtlpGauge gauge = new OtlpGauge();
        OtlpNumberDataPoint dataPoint = new OtlpNumberDataPoint();
        dataPoint.setTimeUnixNano(String.valueOf(metricData.getTimestamp()));
        dataPoint.setAttributes(OtlpJsonUtils.mapAttributes(metricData.getAttributes()));
        dataPoint.setAsDouble(metricData.getValue()); // assuming setValue or setAsDouble exists; adjust per actual API
        gauge.getDataPoints().add(dataPoint);
        metric.setGauge(gauge);

        return metric;
    }
}

