protected <T extends SqlExpr> void writeIteratorComma(Iterator<T> iterator) {
    if (iterator.hasNext()) {
        T expr = iterator.next();
        expr.traverse(this);
    }
    while (iterator.hasNext()) {
        T expr = iterator.next();
        this.writeComma();
        expr.traverse(this);
    }
