public static <T extends Comparable<T>> java.util.List<T> clip(java.util.List<T> vector, T min, T max) {
    int size = vector.size();
    java.util.List<T> res = new java.util.ArrayList<>(size);
    for (int i = 0; i < size; i++) {
        T value = vector.get(i);
        if (value.compareTo(min) < 0) {
            res.add(min);
        } else if (value.compareTo(max) > 0) {
            res.add(max);
        } else {
            res.add(value);
        }
    }
    return res;
}

