public func clip(min: T, max: T): Vector<T> {
        let size = this.size()
        let res = empty<T>(size)
        for (i in 0..size) {
            if (this[i] < min) {
                res[i] = min
            } else if (this[i] > max) {
                res[i] = max
            } else {
                res[i] = this[i]
            }
        }
        return res
    }

