import java.time.Duration;
import java.time.Instant;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.locks.ReentrantReadWriteLock;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class InactivityMonitor extends TransportFilter {
    protected static final Logger logger = LoggerFactory.getLogger("InactivityMonitor");

    private static final Duration DEFAULT_CHECK_TIME_MILLS = Duration.ofMillis(30000);

    private static int CHECKER_COUNTER = 0;
    private static ScheduledFuture<?> CONNECT_CHECK_TIMER = null;
    private static ScheduledFuture<?> READ_CHECK_TIMER = null;
    private static ScheduledFuture<?> WRITE_CHECK_TIMER = null;

    private final AtomicBoolean monitorStarted = new AtomicBoolean(false);

    private final AtomicBoolean commandSent = new AtomicBoolean(false);
    private final AtomicBoolean inSend = new AtomicBoolean(false);
    private final AtomicBoolean failed = new AtomicBoolean(false);

    private final AtomicBoolean commandReceived = new AtomicBoolean(true);
    private final AtomicBoolean inReceive = new AtomicBoolean(false);

    private WireFormatInfo localWireFormatInfo = null;
    private WireFormatInfo remoteWireFormatInfo = null;

    private boolean ignoreRemoteWireFormat = false;
    private boolean ignoreAllWireFormatInfo = false;

    private Duration connectAttemptTimeoutVal = DEFAULT_CHECK_TIME_MILLS;
    private Duration readCheckTimeVal = DEFAULT_CHECK_TIME_MILLS;
    private Duration writeCheckTimeVal = DEFAULT_CHECK_TIME_MILLS;
    private Duration initialDelayTimeVal = DEFAULT_CHECK_TIME_MILLS;
    private boolean useKeepAliveVal = true;
    private boolean keepAliveResponseRequiredVal = false;
    private final ThreadLocal<Instant> lastReadCheckTime = ThreadLocal.withInitial(Instant::now);
    private final ThreadLocal<Instant> lastWriteCheckTime = ThreadLocal.withInitial(Instant::now);

    protected WireFormat wireFormat = null;

    private final ReentrantReadWriteLock sendLock = new ReentrantReadWriteLock();
    private final Object monitor = new Object();

    public InactivityMonitor(Transport next, WireFormat wireFormat) {
        super(next);
        this.wireFormat = wireFormat;
        if (this.wireFormat == null) {
            this.ignoreAllWireFormatInfo = true;
        }
    }

    /**
     * 分别处理接收到的KeepAliveInfo和WireFormatInfo，除了KeepAliveInfo，其他命令继续传播
     */
    @Override
    public void onCommand(Command command) {
        commandReceived.set(true);
        inReceive.set(true);
        try {
            if (command instanceof KeepAliveInfo keepAliveInfo) {
                if (logger.isTraceEnabled()) {
                    logger.trace("Receive message: {}", keepAliveInfo);
                }
                if (keepAliveInfo.isResponseRequired()) {
                    sendLock.readLock().lock();
                    try {
                        keepAliveInfo.setResponseRequired(false);
                        oneway(keepAliveInfo);
                    } catch (TransportException e) {
                        onException(e);
                    } finally {
                        sendLock.readLock().unlock();
                    }
                }
            } else {
                if (command instanceof WireFormatInfo wireFormatInfo) {
                    synchronized (monitor) {
                        try {
                            processInboundWireFormatInfo(wireFormatInfo);
                        } catch (TransportException e) {
                            onException(e);
                        }
                    }
                }
                if (transportListener != null) {
                    transportListener.onCommand(command);
                }
            }
        } finally {
            inReceive.set(false);
        }
    }

    @Override
    public void oneway(Command command) throws TransportException {
        sendLock.readLock().lock();
        inSend.set(true);
        try {
            if (failed.get()) {
                throw new TransportException("Cannot send, the connection has already failed");
            }
            if (command instanceof WireFormatInfo wireFormatInfo) {
                synchronized (monitor) {
                    processOutboundWireFormatInfo(wireFormatInfo);
                }
            }
            next.oneway(command);
        } catch (TransportException ex) {
            throw ex;
        } finally {
            commandSent.set(true);
            inSend.set(false);
            sendLock.readLock().unlock();
        }
    }

    @Override
    public void onException(TransportException error) {
        if (failed.compareAndSet(false, true)) {
            stopMonitorThreads();
            if (transportListener != null) {
                transportListener.onException(error);
            }
        }
    }

    public void start() {
        if (!isMonitorStarted()) {
            startConnectCheckTask(connectAttemptTimeoutVal);
        }
        next.start();
        startMonitorThreads();
    }

    @Override
    public void stop() {
        stopMonitorThreads();
        next.stop();
    }

    private void readCheck() {
        // 正在接收消息，跳过检查
        if (inReceive.get()) {
            logger.trace("A receive is in progress, skipping read check.");
            return;
        }
        // 接收不到消息，则抛异常，中断连接
        if (!commandReceived.get() && monitorStarted.get()) {
            logger.debug("No message received since last read check for InactivityMonitor.");

            // Simulate spawn via CompletableFuture.runAsync (non-blocking)
            CompletableFuture.runAsync(() -> {
                onException(new TransportException("The connection was inactive for too (>" + this.readCheckTimeVal + ") long: "));
            });
        } else {
            // 自上次readCheck之后又收到过消息
            if (logger.isTraceEnabled()) {
                logger.trace("Message received since last read check, resetting flag: InactivityMonitor");
            }
        }
        // 每次readCheck之后将commandReceived设置为false，而onCommand每次侦听到消息后都会将commandReceived设置为true
        // 当在readCheck时检查commandReceived为false，说明自上次readCheck后一直未收到消息
        commandReceived.set(false);
    }

    private void writeCheck() {
        // 当前正在写消息，跳过
        if (inSend.get()) {
            logger.trace("Send in progress. Skipping write check.");
            return;
        }
        // 自上次writeCheck后未发送过消息，发送一条keepAliveInfo，保持连接
        if (!commandSent.get() && useKeepAliveVal && monitorStarted.get()) {
            logger.trace("InactivityMonitor no message sent since last write check, sending a KeepAliveInfo");

            CompletableFuture.runAsync(() -> {
                logger.debug("Running InactivityMonitor");
                if (monitorStarted.get()) {
                    try {
                        if (sendLock.writeLock().tryLock(1, TimeUnit.SECONDS)) {
                            KeepAliveInfo info = new KeepAliveInfo();
                            info.setResponseRequired(this.keepAliveResponseRequiredVal);
                            oneway(info);
                        }
                    } catch (TransportException e) {
                        onException(e);
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                    } finally {
                        if (sendLock.writeLock().isHeldByCurrentThread()) {
                            sendLock.writeLock().unlock();
                        }
                    }
                }
            });
        } else {
            logger.trace("InactivityMonitor message sent since last write check, resetting flag.");
        }
        // 每次oneWay发送消息后都会将commandSent设置为true，所以writeCheck后将commandSent设置为false，便于下一周期检查
        commandSent.set(false);
    }

    /**
     * 处理wireformatInfo出栈
     */
    private void processOutboundWireFormatInfo(WireFormatInfo info) {
        localWireFormatInfo = info;
        startMonitorThreads();
    }

    /**
     * 处理wireformatInfo入栈
     */
    private void processInboundWireFormatInfo(WireFormatInfo info) throws TransportException {
        stopConnectCheckTask();
        remoteWireFormatInfo = info;
        try {
            startMonitorThreads();
        } catch (TransportException e) {
            onException(e);
        }
    }

    public void startConnectCheckTask(Duration connectAttemptTimeout) {
        // 从start开始计时，如果在connectAttemptTimeout时间内无法建立连接的话，视为连接建立失败，抛出异常
        if (connectAttemptTimeout.compareTo(Duration.ZERO) <= 0) {
            return;
        }
        logger.trace("Starting connection check task");
        synchronized (monitor) {
            Instant startTime = Instant.now();
            if (CHECKER_COUNTER == 0 && CONNECT_CHECK_TIMER == null) {
                CONNECT_CHECK_TIMER = Executors.newSingleThreadScheduledExecutor()
                        .schedule(() -> {
                            long elapsedMs = Duration.between(startTime, Instant.now()).toMillis();
                            if (Duration.between(startTime, Instant.now()).compareTo(connectAttemptTimeout) >= 0) {
                                CompletableFuture.runAsync(() -> {
                                    onException(new TransportException(
                                            "The connection was inactive (no connection attempt made) for too (> " + this.connectAttemptTimeoutVal + ") long"
                                    ));
                                });
                            }
                        }, connectAttemptTimeout.toMillis(), TimeUnit.MILLISECONDS);
            }
            CHECKER_COUNTER++;
        }
    }

    /**
     * 停止connection check，调用相应timer的cancel方法，取消该任务调度
     */
    public void stopConnectCheckTask() {
        if (CONNECT_CHECK_TIMER != null) {
            logger.trace("Stopping connection check task for: InactivityMonitor");
            synchronized (monitor) {
                CONNECT_CHECK_TIMER.cancel(true);
                CONNECT_CHECK_TIMER = null;
                CHECKER_COUNTER--;
            }
        }
    }

    private void startMonitorThreads() {
        if (monitorStarted.get()) {
            return;
        }

        if (!configuredOk()) {
            return;
        }

        if (this.readCheckTimeVal.compareTo(Duration.ZERO) > 0 || this.writeCheckTimeVal.compareTo(Duration.ZERO) > 0) {
            monitorStarted.set(true);
            synchronized (monitor) {
                CHECKER_COUNTER++;
                if (readCheckTimeVal.compareTo(Duration.ZERO) > 0) {
                    READ_CHECK_TIMER = Executors.newSingleThreadScheduledExecutor()
                            .scheduleAtFixedRate(() -> {
                                Instant lastRunTime = lastReadCheckTime.get();
                                Duration elapsed = Duration.between(lastRunTime, Instant.now());
                                logger.debug("{}ms elapsed since last read check.", elapsed.toMillis());
                                if (!allowReadCheck(elapsed)) {
                                    logger.debug("Aborting read check...Not enough time elapsed since last read check.");
                                    return;
                                }
                                lastReadCheckTime.set(Instant.now());
                                readCheck();
                            }, initialDelayTimeVal.toMillis(), readCheckTimeVal.toMillis(), TimeUnit.MILLISECONDS);
                }
                if (writeCheckTimeVal.compareTo(Duration.ZERO) > 0) {
                    WRITE_CHECK_TIMER = Executors.newSingleThreadScheduledExecutor()
                            .scheduleAtFixedRate(() -> {
                                Instant lastRunTime = lastWriteCheckTime.get();
                                long now = System.currentTimeMillis();
                                long lastRunMs = lastRunTime != null ? lastRunTime.toEpochMilli() : 0;
                                if (lastRunMs != 0) {
                                    logger.debug("InactivityMonitor: {}ms elapsed since last write check.", now - lastRunMs);
                                }
                                lastWriteCheckTime.set(Instant.now());
                                writeCheck();
                            }, initialDelayTimeVal.toMillis(), writeCheckTimeVal.toMillis(), TimeUnit.MILLISECONDS);
                }
            }
        }
    }

    private void stopMonitorThreads() {
        stopConnectCheckTask();
        if (monitorStarted.compareAndSet(true, false)) {
            CHECKER_COUNTER--;
            if (CHECKER_COUNTER == 0) {
                if (READ_CHECK_TIMER != null) {
                    READ_CHECK_TIMER.cancel(true);
                    READ_CHECK_TIMER = null;
                }
                if (WRITE_CHECK_TIMER != null) {
                    WRITE_CHECK_TIMER.cancel(true);
                    WRITE_CHECK_TIMER = null;
                }
            }
        }
    }

    private boolean configuredOk() {
        boolean configured = false;
        if (ignoreAllWireFormatInfo) {
            configured = true;
        } else if (localWireFormatInfo != null && remoteWireFormatInfo != null) {
            if (!ignoreRemoteWireFormat) {
                if (logger.isDebugEnabled()) {
                    logger.debug("Using min of local: {} and remote: {}", localWireFormatInfo, remoteWireFormatInfo);
                }
                long readCheckTime = Math.min(
                        localWireFormatInfo.getMaxInactivityDuration(),
                        remoteWireFormatInfo.getMaxInactivityDuration()
                );
                long writeCheckTime = writeCheckValueFromReadCheck(readCheckTime);

                this.readCheckTimeVal = Duration.ofMillis(readCheckTime);
                this.initialDelayTimeVal = Duration.ofMillis(Math.min(
                        localWireFormatInfo.getMaxInactivityDurationInitalDelay(),
                        remoteWireFormatInfo.getMaxInactivityDurationInitalDelay()
                ));
                this.writeCheckTimeVal = Duration.ofMillis(writeCheckTime);
            } else {
                if (logger.isDebugEnabled()) {
                    logger.debug("Using local: {}", localWireFormatInfo);
                }
                long readCheckTime = localWireFormatInfo.getMaxInactivityDuration();
                long writeCheckTime = writeCheckValueFromReadCheck(readCheckTime);

                this.readCheckTimeVal = Duration.ofMillis(readCheckTime);
                this.initialDelayTimeVal = Duration.ofMillis(localWireFormatInfo.getMaxInactivityDurationInitalDelay());
                this.writeCheckTimeVal = Duration.ofMillis(writeCheckTime);
            }
            configured = true;
        }

        return configured;
    }

    private boolean allowReadCheck(Duration elapsed) {
        return elapsed.compareTo(readCheckTimeVal.multipliedBy(9).dividedBy(10)) > 0;
    }

    private long writeCheckValueFromReadCheck(long readCheckTime) {
        if (readCheckTime > 3) {
            return readCheckTime / 3;
        } else {
            return readCheckTime;
        }
    }

    public boolean isMonitorStarted() {
        return this.monitorStarted.get();
    }

    public Duration getConnectAttemptTimeout() {
        return this.connectAttemptTimeoutVal;
    }

    public void setConnectAttemptTimeout(Duration value) {
        this.connectAttemptTimeoutVal = value;
    }

    public Duration getReadCheckTime() {
        return this.readCheckTimeVal;
    }

    public void setReadCheckTime(Duration value) {
        this.readCheckTimeVal = value;
    }

    public Duration getWriteCheckTime() {
        return this.writeCheckTimeVal;
    }

    public void setWriteCheckTime(Duration value) {
        this.writeCheckTimeVal = value;
    }

    public Duration getInitialDelayTime() {
        return this.initialDelayTimeVal;
    }

    public void setInitialDelayTime(Duration value) {
        this.initialDelayTimeVal = value;
    }

    public boolean isUseKeepAlive() {
        return this.useKeepAliveVal;
    }

    public void setUseKeepAlive(boolean value) {
        this.useKeepAliveVal = value;
    }

    public boolean isKeepAliveResponseRequired() {
        return this.keepAliveResponseRequiredVal;
    }

    public void setKeepAliveResponseRequired(boolean value) {
        this.keepAliveResponseRequiredVal = value;
    }
}

