public class FileAppender {
    // 安全检查：防止路径遍历等不安全操作
    private static boolean isPathSafe(String filePath) {
        try {
            Path path = Paths.get(filePath).toRealPath();
            String normalized = path.toString();
            return normalized.startsWith(System.getProperty("user.dir") + File.separator) &&
                   !normalized.contains("..") &&
                   Files.isWritable(path.getParent());
        } catch (Exception e) {
            return false;
        }
    }

    public static String appendToFile(String filePath, String content) {
        try {
            // 安全检查
            if (!isPathSafe(filePath)) {
                return "❌ 文件路径不安全，拒绝追加操作";
            }

            Path path = Paths.get(filePath);

            // 使用标准 Java 追加模式写入文件
            try (BufferedWriter writer = Files.newBufferedWriter(path, StandardOpenOption.CREATE, StandardOpenOption.APPEND)) {
                writer.write(content);
                writer.flush();
            }

            // 构建结果对象（模拟仓颉的 FileWriteResult）
            String result = String.format(
                "success: true, operation: \"append\", filePath: \"%s\", contentLength: %d, message: \"内容追加成功\", backupPath: null",
                filePath,
                (long) content.length()
            );

            return result;

        } catch (FileSystemException e) {
            return "❌ 文件系统错误: " + e.getMessage();
        } catch (Exception e) {
            return "❌ 追加文件失败: " + e.getMessage();
        }
    }

    // 示例 main 方法，便于直接运行测试
    public static void main(String[] args) {
        // 示例调用（可按需修改）
        System.out.println(appendToFile("test.txt", "Hello, World!\n"));
    }
}

