import java.util.*;

public class ConfigurationManager {
    private final Map<String, ActorSystemConfig> loadedConfigs;
    private final Map<String, ActorSystemConfig> configCache;

    public ConfigurationManager() {
        this.loadedConfigs = new HashMap<>();
        this.configCache = new HashMap<>();
    }

    /**
     * 加载配置文件
     */
    public ActorSystemConfig loadConfig(String filePath) {
        // 检查缓存
        ActorSystemConfig cachedConfig = configCache.get(filePath);
        if (cachedConfig != null) {
            return cachedConfig;
        }

        // 创建加载器并加载配置
        ConfigLoader loader = ConfigLoaderFactory.createLoader(filePath);
        ActorSystemConfig config = loader.loadFromFile(filePath);

        // 验证配置
        ValidationResult validationResult = loader.validateConfig(config);
        if (!validationResult.isValid()) {
            throw new RuntimeException("Configuration validation failed: " + validationResult.getErrors());
        }

        // 缓存配置
        configCache.put(filePath, config);
        loadedConfigs.put(filePath, config);

        return config;
    }

    /**
     * 从字符串加载配置
     */
    public ActorSystemConfig loadConfigFromString(String content, ConfigFormat format) {
        ConfigLoader loader = ConfigLoaderFactory.createLoaderByFormat(format);
        ActorSystemConfig config = loader.loadFromString(content);

        // 验证配置
        ValidationResult validationResult = loader.validateConfig(config);
        if (!validationResult.isValid()) {
            throw new RuntimeException("Configuration validation failed: " + validationResult.getErrors());
        }

        return config;
    }

    /**
     * 获取已加载的配置
     */
    public Optional<ActorSystemConfig> getLoadedConfig(String filePath) {
        return Optional.ofNullable(loadedConfigs.get(filePath));
    }

    /**
     * 清除缓存
     */
    public void clearCache() {
        configCache.clear();
    }

    /**
     * 重新加载配置
     */
    public ActorSystemConfig reloadConfig(String filePath) {
        // 清除缓存
        configCache.remove(filePath);
        loadedConfigs.remove(filePath);

        // 重新加载
        return loadConfig(filePath);
    }

    /**
     * 获取所有已加载的配置文件路径
     */
    public String[] getLoadedConfigPaths() {
        List<String> paths = new ArrayList<>(loadedConfigs.keySet());
        return paths.toArray(new String[0]);
    }
}

