    String query = getEncodedQuery();
    if (query == null || query.isEmpty()) {
        return "";
    }

    String encodedKey = encode(key);
    int start = 0;
    char[] queryCharBuffer = query.toCharArray();

    while (true) {
        int nextAmpersand = -1;
        int ampersandIndex = query.indexOf('&', start);
        if (ampersandIndex != -1) {
            nextAmpersand = ampersandIndex;
        }

        int end = (nextAmpersand != -1) ? nextAmpersand : query.length();

        int separator = query.indexOf('=', start);
        if (separator == -1 || separator > end) {
            separator = end;
        }

        // Check if substring from start to separator equals encodedKey
        boolean queryEquals = false;
        if (separator - start == encodedKey.length()) {
            queryEquals = query.regionMatches(start, encodedKey, 0, encodedKey.length());
        }

        if (separator - start == encodedKey.length() && queryEquals) {
            if (separator == end) {
                return "";
            } else {
                String encodedValue = query.substring(separator + 1, end);
                return decode(encodedValue, true, false);
            }
        }

        if (nextAmpersand != -1) {
            start = nextAmpersand + 1;
        } else {
            break;
        }
    }
    return "";
}

