     * @param less 比较函数，less(a, b) 返回 true 表示 a < b
     */
    public HeapKMergeIterator(Iterator<Iterator<T>> xss, java.util.function.BiPredicate<T, T> less) {
        this.sources = new ArrayList<>();
        this.positions = new ArrayList<>();
        this.done = false;

        // Use a custom comparator for PriorityQueue that captures `less`
        this.heap = new PriorityQueue<>((a, b) -> {
            if (less.test(a.value, b.value)) return -1;
            if (less.test(b.value, a.value)) return 1;
            return 0;
        });

        int idx = 0;
        while (xss.hasNext()) {
            Iterator<T> iter = xss.next();
            List<T> arr = toArrayList(iter);
            this.sources.add(arr);
            this.positions.add(0);

            // 如果源序列非空，将第一个元素加入堆
            if (!arr.isEmpty()) {
                this.heap.offer(new Element<>(arr.get(0), idx));
                this.positions.set(idx, 1); // 标记已读取第一个元素
            }
            idx++;
        }
    }

    // Helper to convert Iterator<T> to ArrayList<T>
    private static <T> List<T> toArrayList(Iterator<T> iter) {
        List<T> list = new ArrayList<>();
        iter.forEachRemaining(list::add);
        return list;
    }

    @Override
    public boolean hasNext() {
        return !this.done && !this.heap.isEmpty();
    }

    @Override
    public T next() {
        if (this.done || this.heap.isEmpty()) {
            this.done = true;
            throw new NoSuchElementException();
        }

        Element<T> elem = this.heap.poll();
        if (elem == null) {
            this.done = true;
            throw new NoSuchElementException();
        }

        T value = elem.value;
        int srcIdx = elem.srcIdx;
        List<T> src = this.sources.get(srcIdx);
        int pos = this.positions.get(srcIdx);

        if (pos < src.size()) {
            this.heap.offer(new Element<>(src.get(pos), srcIdx));
            this.positions.set(srcIdx, pos + 1);
        }

        return value;
    }
