public class DgeevTest {
    private static final double DEFAULT_TOL = 1e-13;

    public static void testDgeev(LFloat64 lFloat64, String tc, DgeevTestStruct test,
                                 LeftEVJob jobvl, RightEVJob jobvr, long extra, Worklen wl) {
        double valTol = (test.valTol == 0.0) ? DEFAULT_TOL : test.valTol;
        double vecTol = (test.vecTol == 0.0) ? DEFAULT_TOL : test.vecTol;

        General64 a = cloneGeneral(test.a);
        long n = a.rows();

        General64 vl;
        if (jobvl == LeftEVJob.LeftEVCompute) {
            vl = nanGeneral(n, n, n);
        } else {
            vl = new General64(0, 0, 1, new double[0]);
            // vl.stride = 1.0
        }

        General64 vr;
        if (jobvr == RightEVJob.RightEVCompute) {
            vr = nanGeneral(n, n, n);
        } else {
            vr = new General64(0, 0, 1, new double[0]);
            // vr.stride = 1.0
        }

        double[] wr = new double[(int) n];
        double[] wi = new double[(int) n];

        long lwork = 0;
        if (wl == Worklen.minimumWork) {
            if (jobvl == LeftEVJob.LeftEVCompute || jobvr == RightEVJob.RightEVCompute) {
                lwork = Math.max(1, 4 * n);
            } else {
                lwork = Math.max(1, 3 * n);
            }
        } else if (wl == Worklen.mediumWork) {
            double[] work = new double[1];
            lFloat64.dgeev(jobvl, jobvr, n, a.data(), a.stride(), wr, wi,
                    vl.data(), vl.stride(), vr.data(), vr.stride(), work, -1);
            if (jobvl == LeftEVJob.LeftEVCompute || jobvr == RightEVJob.RightEVCompute) {
                lwork = (Math.round(work[0]) + 4 * n) / 2;
            } else {
                lwork = (Math.round(work[0]) + 3 * n) / 2;
            }
            lwork = Math.max(1, lwork);
        } else if (wl == Worklen.optimumWork) {
            double[] work = new double[1];
            lFloat64.dgeev(jobvl, jobvr, n, a.data(), a.stride(), wr, wi,
                    vl.data(), vl.stride(), vr.data(), vr.stride(), work, -1);
            lwork = Math.round(work[0]);
        }

        double[] work = new double[(int) lwork];

        int first = lFloat64.dgeev(jobvl, jobvr, n, a.data(), a.stride(), wr, wi,
                vl.data(), vl.stride(), vr.data(), vr.stride(), work, work.length);

        String prefix = String.format("Case #%s: n=%d, jobvl=%s, jobvr=%s, extra=%d, work=%s",
                tc, n, jobvl, jobvr, extra, wl);

        if (!generalOutsideAllNaN(vl)) {
            throw new RuntimeException(prefix + ": out-of-range write to VL");
        }
        if (!generalOutsideAllNaN(vr)) {
            throw new RuntimeException(prefix + ": out-of-range write to VR");
        }

        if (first > 0) {
            // handled below
        }

        long i = first;
        while (i < n) {
            if (wi[(int) i] == 0.0) {
                i++;
                continue;
            }
            if (wr[(int) i] != wr[(int) i + 1]) {
                throw new RuntimeException(prefix + ": real parts of " + i + "th conjugate pair not equal");
            }
            if ((wi[(int) i] < 0.0) || (wi[(int) i + 1] >= 0.0)) {
                throw new RuntimeException(prefix + ": unexpected ordering of " + i + "th conjugate pair");
            }
            i += 2;
        }

        if (!test.evWant().isEmpty()) {
            boolean[] used = new boolean[test.evWant().size()];
            for (long idx = first; idx < n; idx++) {
                Complex128 evGot = new Complex128(wr[(int) idx], wi[(int) idx]);
                int foundIdx = -1;
                for (int k = 0; k < test.evWant().size(); k++) {
                    Complex128 evWant = test.evWant().get(k);
                    if (!used[k] && c128Abs(evWant.subtract(evGot)) < valTol) {
                        foundIdx = k;
                        used[k] = true;
                        break;
                    }
                }
                if (foundIdx == -1) {
                    throw new RuntimeException(prefix + ": unexpected eigenvalue " + evGot);
                }
            }
        }

        if (first > 0 || (jobvl == LeftEVJob.LeftEVNone && jobvr == RightEVJob.RightEVNone)) {
            return;
        }

        NFloat64 nFloat64 = nFloat64Implementation();

        if (jobvr == RightEVJob.RightEVCompute) {
            double resid = residualRightEV(test.a(), vr, wr, wi);
            if (resid > vecTol) {
                throw new RuntimeException(prefix + ": unexpected right eigenvectors; residual=" + resid + ", want<=" + vecTol);
            }

            for (long j = 0; j < n; j++) {
                double nrm = 1.0;
                if (wi[(int) j] == 0.0) {
                    nrm = nFloat64.dnrm2(n, getSubarray(vr.data(), (int) j), vr.stride());
                } else if (wi[(int) j] > 0.0) {
                    double[] dataJ = getSubarray(vr.data(), (int) j);
                    double[] dataJ1 = getSubarray(vr.data(), (int) j + 1);
                    nrm = hypot(nFloat64.dnrm2(n, dataJ, vr.stride()),
                                nFloat64.dnrm2(n, dataJ1, vr.stride()));
                }
                double diff = Math.abs(nrm - 1.0);
                if (diff > DEFAULT_TOL) {
                    throw new RuntimeException(prefix + ": unexpected Euclidean norm of right eigenvector; |VR[" + j + "]-1|=" + diff + ", want<=" + DEFAULT_TOL);
                }

                if (wi[(int) j] > 0.0) {
                    double vmax = 0.0;
                    double vrmax = 0.0;
                    for (long iInner = 0; iInner < n; iInner++) {
                        int idxJ = (int) (iInner * vr.stride() + j);
                        int idxJ1 = (int) (iInner * vr.stride() + j + 1);
                        double vtest = hypot(vr.data()[idxJ], vr.data()[idxJ1]);
                        vmax = Math.max(vmax, vtest);
                        if (vr.data()[idxJ1] == 0.0) {
                            vrmax = Math.max(vrmax, Math.abs(vr.data()[idxJ]));
                        }
                    }
                    if (vrmax / vmax < 1.0 - DEFAULT_TOL) {
                        throw new RuntimeException(prefix + ": largest component of " + j + "th right eigenvector is not real");
                    }
                }
            }
        }

        if (jobvl == LeftEVJob.LeftEVCompute) {
            double resid = residualLeftEV(test.a(), vl, wr, wi);
            if (resid > vecTol) {
                throw new RuntimeException(prefix + ": unexpected left eigenvectors; residual=" + resid + ", want<=" + vecTol);
            }

            for (long j = 0; j < n; j++) {
                double nrm = 1.0;
                if (wi[(int) j] == 0.0) {
                    nrm = nFloat64.dnrm2(n, getSubarray(vl.data(), (int) j), vl.stride());
                } else if (wi[(int) j] > 0.0) {
                    double[] dataJ = getSubarray(vl.data(), (int) j);
                    double[] dataJ1 = getSubarray(vl.data(), (int) j + 1);
                    nrm = hypot(nFloat64.dnrm2(n, dataJ, vl.stride()),
                                nFloat64.dnrm2(n, dataJ1, vl.stride()));
                }
                double diff = Math.abs(nrm - 1.0);
                if (diff > DEFAULT_TOL) {
                    throw new RuntimeException(prefix + ": unexpected Euclidean norm of left eigenvector; |VL[" + j + "]-1|=" + diff + ", want<=" + DEFAULT_TOL);
                }

                if (wi[(int) j] > 0.0) {
                    double vmax = 0.0;
                    double vrmax = 0.0;
                    for (long iInner = 0; iInner < n; iInner++) {
                        int idxJ = (int) (iInner * vl.stride() + j);
                        int idxJ1 = (int) (iInner * vl.stride() + j + 1);
                        double vtest = hypot(vl.data()[idxJ], vl.data()[idxJ1]);
                        vmax = Math.max(vmax, vtest);
                        if (vl.data()[idxJ1] == 0.0) {
                            vrmax = Math.max(vrmax, Math.abs(vl.data()[idxJ]));
                        }
                    }
                    if (vrmax / vmax < 1.0 - DEFAULT_TOL) {
                        throw new RuntimeException(prefix + ": largest component of " + j + "th left eigenvector is not real");
                    }
                }
            }
        }
    }

    // Helper method to extract subarray starting at index
    private static double[] getSubarray(double[] arr, int start) {
        if (start >= arr.length) {
