        let used = Array<Bool>(n, repeat: false)
        for (i in first..n) {
            let evGot = Complex128(wr[i], wi[i])
            var idx = -1
            for (k in 0..test.evWant.size) {
                let evWant = test.evWant[k]
                if ((!used[k]) && (c128Abs(evWant - evGot) < valTol)) {
                    idx = k
                    used[k] = true
                    break
                }
            }
            if (idx == -1) {
                throw Exception("${prefix}: unexpected eigenvalue ${evGot}")
            }
        }
    }

    if ((first > 0) || ((jobvl == LeftEVNone) && (jobvr == RightEVNone))) {
        return
    }

    let nFloat64 = nFloat64Implementation()

    if (jobvr == RightEVCompute) {
        let resid = residualRightEV(test.a, vr, wr, wi)
        if (resid > vecTol) {
            throw Exception("${prefix}: unexpected right eigenvectors; residual=${resid}, want<=${vecTol}")
        }

        for (j in 0..n) {
            var nrm = 1.0
            if (wi[j] == 0.0) {
                nrm = nFloat64.dnrm2(n, vr.data[j..], vr.stride)
            } else if (wi[j] > 0.0) {
                nrm = hypot(nFloat64.dnrm2(n, vr.data[j..], vr.stride), nFloat64.dnrm2(n, vr.data[j + 1..], vr.stride))
            }
            let diff = abs(nrm - 1.0)
            if (diff > defaultTol) {
                throw Exception(
                    "${prefix}: unexpected Euclidean norm of right eigenvector; |VR[${j}]-1|=${diff}, want<=${defaultTol}")
            }

            if (wi[j] > 0.0) {
                var vmax: Float64 = 0.0
                var vrmax: Float64 = 0.0
                for (i in 0..n) {
                    let vtest = hypot(vr.data[i * vr.stride + j], vr.data[i * vr.stride + j + 1])
                    vmax = max(vmax, vtest)
                    if (vr.data[i * vr.stride + j + 1] == 0.0) {
                        vrmax = max(vrmax, abs(vr.data[i * vr.stride + j]))
                    }
                }
                if (vrmax / vmax < 1.0 - defaultTol) {
                    throw Exception("${prefix}: largest component of ${j}th right eigenvector is not real")
                }
            }
        }
    }

    if (jobvl == LeftEVCompute) {
        let resid = residualLeftEV(test.a, vl, wr, wi)
        if (resid > vecTol) {
            throw Exception("${prefix}: unexpected left eigenvectors; residual=${resid}, want<=${vecTol}")
        }

        for (j in 0..n) {
            var nrm = 1.0
            if (wi[j] == 0.0) {
                nrm = nFloat64.dnrm2(n, vl.data[j..], vl.stride)
            } else if (wi[j] > 0.0) {
                nrm = hypot(nFloat64.dnrm2(n, vl.data[j..], vl.stride), nFloat64.dnrm2(n, vl.data[j + 1..], vl.stride))
            }
            let diff = abs(nrm - 1.0)
            if (diff > defaultTol) {
                throw Exception(
                    "${prefix}: unexpected Euclidean norm of left eigenvector; |VL[${j}]-1|=${diff}, want<=${defaultTol}")
            }

            if (wi[j] > 0.0) {
                var vmax: Float64 = 0.0
                var vrmax: Float64 = 0.0
                for (i in 0..n) {
                    let vtest = hypot(vl.data[i * vl.stride + j], vl.data[i * vl.stride + j + 1])
                    vmax = max(vmax, vtest)
                    if (vl.data[i * vl.stride + j + 1] == 0.0) {
                        vrmax = max(vrmax, abs(vl.data[i * vl.stride + j]))
                    }
                }
                if (vrmax / vmax < 1.0 - defaultTol) {
                    throw Exception("${prefix}: largest component of ${j}th left eigenvector is not real")
                }
            }
        }
    }
}

