private Result<DatabaseResult, DatabaseError> executeUpdateInternal(
        String statement,
        String[] parameters,
        QueryOptions options) {
    long startTime = System.nanoTime();

    Result<?, ?> connectionResult = connection != null ? connection.execute(statement, parameters) : null;

    if (connectionResult == null || connectionResult.isErr()) {
        return Result.err(new DatabaseError(
                "UPDATE_FAILED",
                "Update statement execution failed"
        ));
    }

    long duration = System.nanoTime() - startTime;

    // Get affected rows and last insert ID
    int affectedRows = getAffectedRows(connection != null ? connection : new Connection());
    long lastInsertId = getLastInsertId(connection != null ? connection : new Connection());

    return Result.ok(new DatabaseResult(
            affectedRows,
            lastInsertId,
            duration
    ));
}

