private func executeUpdateInternal(
        statement: String,
        parameters: Array<String>,
        options: QueryOptions
    ) -> Result<DatabaseResult, DatabaseError> {
        let startTime = Time.current()

        let connectionResult = connection?.execute(statement, parameters)

        if (connectionResult is Err) {
            return Err<DatabaseResult, DatabaseError>(DatabaseError(
                code: "UPDATE_FAILED",
                message: "Update statement execution failed"
            ))
        }

        let duration = Time.current().difference(startTime)

        // Get affected rows and last insert ID
        let affectedRows = getAffectedRows(connection ?? Connection())
        let lastInsertId = getLastInsertId(connection ?? Connection())

        return Ok<DatabaseResult, DatabaseError>(DatabaseResult(
            affectedRows: affectedRows,
            lastInsertId: lastInsertId,
            executionTime: duration
        ))
    }

