private boolean isNumericToAlphaNumericLatch(long pos) {
    // Next is alphanumeric if there are 4 positions and they are all zeros, or if
    // there is a subset of this just before the end of the symbol
    if (pos + 1 > this.information.getSize()) {
        return false;
    }

    int i = 0;
    while (i < 4 && i + pos < this.information.getSize()) {
        if (this.information.get(pos + i)) {
            return false;
        }
        i++;
    }
    return true;
}

