public class NillableDoubleResponseBuilder implements ResponseBuilder<Double> {
    @Override
    public Double build(RedisMessage message) throws RedisException {
        if (message instanceof NullRedisMessage) {
            return null;
        }

        if (message instanceof DoubleRedisMessage) {
            return ((DoubleRedisMessage) message).getValue();
        } else if (message instanceof BulkStringRedisMessage) {
            BulkStringRedisMessage bulkMsg = (BulkStringRedisMessage) message;
            String value = bulkMsg.getStringValue();
            if (value != null) {
                try {
                    return Double.parseDouble(value);
                } catch (NumberFormatException e) {
                    return null;
                }
            } else {
                return null;
            }
        } else if (message instanceof ErrorRedisMessage) {
            throw new RedisException(((ErrorRedisMessage) message).getValue());
        }

        throw new RedisException("Unsupported message type: " + message.getType());
    }
}

