public class NillableDoubleResponseBuilder <: ResponseBuilder<?Float64> {
    public func build(message: RedisMessage): ?Float64 {
        if (let Some(message) <- (message as NullRedisMessage)) {
            return None
        }

        if (let Some(message) <- (message as DoubleRedisMessage)) {
            return message.getValue()
        } else if (let Some(message) <- (message as BulkStringRedisMessage)) {
            if (let Some(value) <- message.getStringValue()) {
                return Float64.parse(value)
            } else {
                return None
            }
        } else if (let Some(message) <- (message as ErrorRedisMessage)) {
            throw RedisException(message.getValue())
        }

        throw RedisException("Unsupported message type: ${message.getType()}")
    }
}

