/**
 * Slices the byte buffer from start to end (inclusive).
 * If range is not closed, end is adjusted to be exclusive.
 */
public ByteBuffer slice(Range<Long> range) {
    long start = 0;
    if (range.hasStart()) {
        start = range.getStart();
    }

    long end = limitVal;
    if (range.hasEnd()) {
        end = range.getEnd();
    }

    if (!range.isClosed()) {
        end = end - 1;
    }

    long length = (end - start) + 1;
    return slice(start, length);
}

