public static Vector<Double> paramsUpdateFn(Vector<Double> params, Matrix<Double> data,
                                            Double stepSize, Matrix<Double> preMatrix,
                                            McmcModule module) {
    int n = params.size();

    Vector<Double> gradOut = new Vector<>(n); // Assuming Vector<Double> has a constructor taking size

    if (params.size() == 1) {
        Double productGrad = grad(postDensGrad1, params.get(0), data, module);
        gradOut.set(0, productGrad);
    }

    if (params.size() == 2) {
        Vector<Double> productGrad = grad(postDensGrad2, params.get(0), params.get(1), data, module);
        gradOut.set(0, productGrad.get(0));
        gradOut.set(1, productGrad.get(1));
    }

    if (params.size() == 3) {
        Vector<Double> productGrad = grad(postDensGrad3, params.get(0), params.get(1), params.get(2), data, module);
        gradOut.set(0, productGrad.get(0));
        gradOut.set(1, productGrad.get(1));
        gradOut.set(2, productGrad.get(2));
    }

    // Compute: params + (step_size * step_size / 2.0) * (pre_matrix * grad_out)
    Double scale = stepSize * stepSize / 2.0;
    Vector<Double> scaledGrad = preMatrix.multiply(gradOut).scale(scale);
    return params.add(scaledGrad);
}

