public class EvaluatorIsOnlyChild extends Evaluator {
    @Override
    public boolean matches(Element element) {
        // Get parent, or null if none
        Element p = element.parent();
        // Check if parent exists and is not a Document
        if (p != null && !(p instanceof Document)) {
            // Check if element has no siblings
            if (element.siblingElements().elementArr.isEmpty()) {
                return true;
            }
        }
        return false;
    }

    @Override
    public String toString() {
        return ":only-child";
    }
}

