        if (i > 0) {
            tokens += `comma`
        }
        let decl = vars[i]
        let varName = decl.identifier
        let dts = quote($(decl.declType))
        let meta = mapperMetaFn(varName.value)
        tokens += generateMappers(name, varName, dts, meta)
    }
    tokens
}

