private TlsServerConfig loadTlsConfig(JoyServerTlsProperties tlsCfg) {
    JoyLog.info("server.tls.certFile=" + tlsCfg.getCertFile());
    String certText = readPermFile(tlsCfg.getCertFile());

    JoyLog.info("server.tls.keyFile=" + tlsCfg.getKeyFile());
    String keyText = readPermFile(tlsCfg.getKeyFile());

    String password = tlsCfg.getKeyPassword() != null && !tlsCfg.getKeyPassword().isEmpty()
        ? tlsCfg.getKeyPassword()
        : null;

    X509Certificate certificate = X509Certificate.decodeFromPem(certText);
    PrivateKey privateKey = PrivateKey.decodeFromPem(keyText, password);

    TlsServerConfig tlsServerCfg = new TlsServerConfig(certificate, privateKey);

    JoyLog.info("server.tls.trustAll=" + tlsCfg.isTrustAll());
    if (tlsCfg.isTrustAll()) {
        JoyLog.warn("tls trust all is not security");
        tlsServerCfg.setVerifyMode(CertificateVerifyMode.TrustAll);
    }

    JoyLog.info("server.tls.clientAuth=" + tlsCfg.isClientAuth());
    if (tlsCfg.isClientAuth()) {
        tlsServerCfg.setClientIdentityRequired(TlsClientIdentificationMode.Required);
    }

    JoyLog.info("server.tls.ciphers=" + tlsCfg.getCiphers());
    String[] ciphers = tlsCfg.getCiphers().split(",");

    JoyLog.info("server.tls.version=" + tlsCfg.getVersion());
    switch (tlsCfg.getVersion()) {
        case "1.2":
            tlsServerCfg.setMinVersion(TlsVersion.V1_2);
            if (ciphers.length > 0) {
                tlsServerCfg.setCipherSuitesV1_2(Arrays.asList(ciphers));
            }
            break;
        case "1.3":
            tlsServerCfg.setMinVersion(TlsVersion.V1_3);
            if (ciphers.length > 0) {
                tlsServerCfg.setCipherSuitesV1_3(Arrays.asList(ciphers));
            }
            break;
        default:
            // no-op
            break;
    }

    return tlsServerCfg;
}

