import java.util.HashSet;
import java.util.concurrent.locks.ReentrantLock;

public class ShardActor extends Actor {
    private final ShardId shardId;
    private final HashSet<String> entities;
    private final ReentrantLock mutex;

    public ShardActor(ShardId shardId) {
        this.shardId = shardId;
        this.entities = new HashSet<>();
        this.mutex = new ReentrantLock();
    }

    public String getName() {
        return "ShardActor-" + shardId.getId();
    }

    public String getDescription() {
        return "分片Actor: " + shardId.toString();
    }

    public MessageResult receive(Message message, ActorContext context) {
        if (message instanceof StringMessage stringMsg) {
            String content = stringMsg.getContent();
            if (content.startsWith("ADD_ENTITY:")) {
                String entityIdStr = content.replace("ADD_ENTITY:", "");
                addEntity(entityIdStr);
            } else if (content.startsWith("REMOVE_ENTITY:")) {
                String entityIdStr = content.replace("REMOVE_ENTITY:", "");
                removeEntity(entityIdStr);
            } else if ("GET_ENTITY_COUNT".equals(content)) {
                reportEntityCount(context);
            }
            return MessageResult.Handled;
        } else {
            return MessageResult.Unhandled;
        }
    }

    private void addEntity(String entityId) {
        mutex.lock();
        try {
            entities.add(entityId);
        } finally {
            mutex.unlock();
        }
        System.out.println("分片 " + shardId.toString() + " 添加实体: " + entityId);
    }

    private void removeEntity(String entityId) {
        mutex.lock();
        try {
            entities.remove(entityId);
        } finally {
            mutex.unlock();
        }
        System.out.println("分片 " + shardId.toString() + " 移除实体: " + entityId);
    }

    private void reportEntityCount(ActorContext context) {
        mutex.lock();
        try {
            int count = entities.size();
            System.out.println("分片 " + shardId.toString() + " 实体数量: " + count);

            if (context.sender().isPresent()) {
                System.out.println("向发送者报告实体数量");
            }
        } finally {
            mutex.unlock();
        }
    }
}

