    long min_block = Math.min(pending_buf_size - 5, w_size);
    long len = 0;
    long left = 0;
    long have = 0;
    long last = 0;
    long used = avail_in;

    do {
        len = MAX_STORED;
        have = (bits_valid + 42) >> 3;
        if (avail_out < have) {
            break;
        }
        have = avail_out - have;
        left = strstart - block_start;
        if (len > left + avail_in) {
            len = left + avail_in;
        }
        if (len > have) {
            len = have;
        }
        if (len < min_block && ((len == 0 && flush != Z_FINISH) || flush == Z_NO_FLUSH || len != left + avail_in)) {
            break;
        }
        if (flush == Z_FINISH && len == left + avail_in) {
            last = 1;
        } else {
            last = 0;
        }
        storedBlock(0, 0, last == 1);
        putLenNumToPendingBuf((int) len);
        flushPending();
        if (left != 0 && left > len) {
            left = len;
        }
        if (left != 0) {
            putWindowToOutBuf(left);
            len -= left;
        }
        if (len != 0) {
            putReadBufNum(len);
        }
    } while (last == 0);

    used -= avail_in;
    handleUsedNumInDeflateStored((int) used);

    if (last != 0) {
        return FINISH_DONE;
    }
    if (flush != Z_NO_FLUSH && flush != Z_FINISH && avail_in == 0 && strstart == block_start) {
        return BLOCK_DONE;
    }

    have = window_size - strstart - 1;
    if (avail_in > have && block_start >= w_size) {
        putWindowInDeflateStored(w_size);
        have += w_size;
    }
    if (have > avail_in) {
        have = avail_in;
    }
    if (have != 0) {
        handleHaveNumInDeflateStored((int) have);
    }

    have = (bits_valid + 42) >> 3;
    have = Math.min(pending_buf_size - have, MAX_STORED);
    min_block = Math.min(have, w_size);
    left = strstart - block_start;

    if (left >= min_block || ((left != 0 || flush == Z_FINISH) && flush != Z_NO_FLUSH && avail_in == 0 && left <= have)) {
        len = Math.min(left, have);
