import java.util.*;
import java.util.stream.Collectors;

public class PinyinHelper {

    private static final String PINYIN_SEPARATOR = " ";

    // Assuming these static fields are defined elsewhere in the仓颉 codebase.
    // We declare them here as placeholders with reasonable Java types.
    private static final Map<String, String> PINYIN_TABLE = new HashMap<>();
    private static final Map<String, String> MUTIL_PINYIN_TABLE = new HashMap<>();
    private static final Map<String, String> TONGYONG_PINYIN_TABLE = new HashMap<>();

    // Vowel arrays — must be initialized per仓颉 logic; using char[] for runes (UTF-16 surrogate-safe assumed)
    private static final char[] ALL_MARKED_VOWEL_ARRAY = {
        'ā', 'á', 'ǎ', 'à',
        'ē', 'é', 'ě', 'è',
        'ī', 'í', 'ǐ', 'ì',
        'ō', 'ó', 'ǒ', 'ò',
        'ū', 'ú', 'ǔ', 'ù',
        'ǖ', 'ǘ', 'ǚ', 'ǜ'
    };

    private static final char[] ALL_UNMARKED_VOWEL_ARRAY = {'a', 'e', 'i', 'o', 'u', 'v'};

    private static final char CHINESE_LING = '〇';

    /*
     * Convert pinyin with tone format to pinyin with numbers representing tone format
     *
     * @param str - pinyin with tone format
     * @return Array<String> - pinyin with numbers representing tone format
     */
    public static List<String> convertWithToneNumber(String str) {
        List<String> pinyinArray = Arrays.asList(str.split(PINYIN_SEPARATOR));

        List<String> result = new ArrayList<>();
        for (String pinyin : pinyinArray) {
            boolean hasMarkedChar = false;
            String originalPinyin = pinyin.replace("ü", "v");
            char[] originalCharArray = originalPinyin.toCharArray();

            for (int j = 0; j < originalCharArray.length; j++) {
                char originalChar = originalCharArray[j];
                if (originalChar < 'a' || originalChar > 'z') {
                    long indexInAllMarked = findArrayKeyByValue(originalChar);
                    if (indexInAllMarked != -1) {
                        int toneNumber = (int) (indexInAllMarked % 4 + 1);
                        char replaceChar = ALL_UNMARKED_VOWEL_ARRAY[(int) ((indexInAllMarked - indexInAllMarked % 4) / 4)];
                        originalCharArray[j] = replaceChar;
                        String base = new String(originalCharArray);
                        result.add(base + toneNumber);
                        hasMarkedChar = true;
                        break;
                    }
                }
            }
            if (!hasMarkedChar) {
                // Light tone → 5
                result.add(originalPinyin + "5");
            }
        }
        return result;
    }

    /*
     * Convert Pinyin with tone format to Pinyin without tone format
     *
     * @param str - Pinyin with tone format
     * @return Array<String> - Pinyin without tone format
     */
    public static List<String> convertWithoutTone(String str) {
        String s = str;
        for (int i = 0; i < ALL_MARKED_VOWEL_ARRAY.length; i++) {
            char originalChar = ALL_MARKED_VOWEL_ARRAY[i];
            char replaceChar = ALL_UNMARKED_VOWEL_ARRAY[(i - i % 4) / 4];
            s = s.replace(String.valueOf(originalChar), String.valueOf(replaceChar));
        }
        s = s.replace("ü", "v");
        return Arrays.asList(s.split(PINYIN_SEPARATOR));
    }

    /*
     * Formatting Pinyin with Tones into Corresponding Formatted Pinyin
     *
     * @param str - Pinyin with tone format
     * @param format - format
     * @return Array<String>
     */
    public static List<String> formatPinyin(String str, PinyinFormat format) {
        if ("WITH_TONE_MARK".equals(format.getName())) {
            return Arrays.asList(str.split(PINYIN_SEPARATOR));
        } else if ("WITH_TONE_NUMBER".equals(format.getName())) {
            return convertWithToneNumber(str);
        } else if ("WITHOUT_TONE".equals(format.getName()) || "FIRST_LETTER".equals(format.getName())) {
            return convertWithoutTone(str);
        } else {
            return new ArrayList<>();
        }
    }

    /*
     * Convert individual Chinese characters into corresponding pinyin formats
     *
     * @param c - Chinese character
     * @param format - format
     * @return Array<String>
     */
    public static List<String> convertToPinyinArray(char c, PinyinFormat format) {
        List<String> pinyinArray = new ArrayList<>();
        String key = String.valueOf(c);
        String v = PINYIN_TABLE.get(key);
        if (v != null) {
            pinyinArray = formatPinyin(v, format);
            if ("FIRST_LETTER".equals(format.getName())) {
                pinyinArray = pinyinArray.stream()
                        .map(p -> String.valueOf(p.charAt(0)))
                        .collect(Collectors.toList());
            }
        }
        return pinyinArray;
    }

    public static List<String> convertToPinyinArrays(char c, PinyinFormat format) {
        List<String> pinyinArray = new ArrayList<>();
        String key = String.valueOf(c);
        String v = PINYIN_TABLE.get(key);
        if (v != null) {
            pinyinArray = formatPinyin(v, format);
        }
        return pinyinArray;
    }

    /*
     * Gets whether the given string finds the pinyin correspondence of the phrase in the dictionary
     *
     * @param charArray - array of runes (chars)
     * @return Array<String>
     */
    public static List<String> getWords(char[] charArray) {
        int len = Math.min(charArray.length + 1, 6);
        for (int i = 1; i < len; i++) {
            String str = new String(charArray, 0, i);
            if (MUTIL_PINYIN_TABLE.containsKey(str)) {
                return Collections.singletonList(str);
            }
        }
        return Collections.emptyList();
    }

    /*
     * Convert strings into corresponding pinyin formats
     *
     * @param str - Chinese characters
     * @param separator - Separator
     * @param format - PinyinFormat
     * @return String
     */
    public static String convertToPinyinString(String str, String separator, PinyinFormat format) {
        if (str == null || str.isEmpty()) {
            throw new Pinyin4cjException("Please enter a word or sentence");
        }
        char[] charArray = str.toCharArray();
        StringBuilder resultPinyinStrBuf = new StringBuilder();
        int i = 0;
        int strLen = charArray.length;

        while (i < strLen) {
            char[] slice = Arrays.copyOfRange(charArray, i, strLen);
            List<String> commonPrefixList = getWords(slice);

            if (commonPrefixList.isEmpty()) {
                char c = charArray[i];
                if (ChineseHelper.isChinese(c) || c == CHINESE_LING) {
                    List<String> pinyinArray = convertToPinyinArrays(c, format);
                    if (!pinyinArray.isEmpty()) {
                        String pinyin = pinyinArray.get(0);
                        if ("FIRST_LETTER".equals(format.getName())) {
                            resultPinyinStrBuf.append(pinyin.charAt(0)).append(separator);
                        } else {
                            resultPinyinStrBuf.append(pinyin).append(separator);
                        }
                    } else {
                        resultPinyinStrBuf.append(c);
                    }
                } else {
                    if (i + 1 < strLen && ChineseHelper.isChinese(charArray[i + 1])) {
                        resultPinyinStrBuf.append(c).append(separator);
                    } else {
                        resultPinyinStrBuf.append(c);
                    }
                }
                i++;
            } else {
                String words = commonPrefixList.get(commonPrefixList.size() - 1);
                List<String> pinyinArray = formatPinyin(MUTIL_PINYIN_TABLE.get(words), format);
                for (String pinyin : pinyinArray) {
                    if ("FIRST_LETTER".equals(format.getName())) {
                        resultPinyinStrBuf.append(pinyin.charAt(0)).append(separator);
                    } else {
                        resultPinyinStrBuf.append(pinyin).append(separator);
                    }
                }
                i += words.length();
            }
        }

        return convertToPinyinStringResult(resultPinyinStrBuf, separator);
    }

    public static String convertToPinyinStringTraditional(String str, String separator, PinyinFormat format) {
        String simplified = ChineseHelper.convertToSimplifiedChinese(str);
        return convertToPinyinString(simplified, separator, format);
    }

    public static String convertToPinyinStringResult(StringBuilder buf, String separator) {
