    private static long findArrayKeyByValue(char ch) {
        for (int i = 0; i < ALL_MARKED_VOWEL_ARRAY.length; i++) {
            if (ALL_MARKED_VOWEL_ARRAY[i] == ch) {
                return i;
            }
        }
        return -1L;
    }

    /**
     * Character to Universal Pinyin
     *
     * @param c - Simplified or Traditional Characters
     * @return Array<String>
     */
    public static List<String> toTongyongPinyinStringArray(char c) {
        List<String> pinyinArray = convertToPinyinArray(c, PinyinFormat.WITH_TONE_NUMBER);
        List<String> res = new ArrayList<>();
        for (String pinyin : pinyinArray) {
            String word;
            int lastIdx = pinyin.length() - 1;
            if (lastIdx >= 0 && Character.isDigit(pinyin.charAt(lastIdx))) {
                String num = String.valueOf(pinyin.charAt(lastIdx));
                String base = pinyin.substring(0, lastIdx);
                String t = TONGYONG_PINYIN_TABLE.get(base);
                word = (t != null) ? t + num : pinyin;
            } else {
                word = pinyin;
            }
            res.add(word);
        }
        return res;
    }
