private void ackLater(MessageDispatch md, byte ackType) {
    if (session.getTransacted()) {
        registerSync();
    }

    deliveredCounter++;

    synchronized (deliveredMessagesMutex) {
        MessageAck oldPendingAck = pendingAck;

        MessageAck newPendingAck = new MessageAck(md, ackType, deliveredCounter);
        if (session.getTransactionContext() != null) {
            newPendingAck.setTransactionId(session.getTransactionContext().getTransactionId());
        }
        pendingAck = newPendingAck;

        if (oldPendingAck != null) {
            if (newPendingAck.getAckType() == oldPendingAck.getAckType()) {
                newPendingAck.setFirstMessageId(oldPendingAck.getFirstMessageId());
            } else {
                if (!oldPendingAck.isDeliveredAck()) {
                    logger.debug("Sending old pending ack {}, new pending: {}", oldPendingAck, newPendingAck);
                    session.sendAck(oldPendingAck);
                } else {
                    logger.debug("dropping old pending ack {}, new pending: {}", oldPendingAck, pendingAck);
                }
            }
        } else {
            newPendingAck.setFirstMessageId(newPendingAck.getLastMessageId());
        }

        double prefetchThreshold = 0.5 * info.getPrefetchSize();
        double currentCount = deliveredCounter + ackCounter - additionalWindowSize;
        if (prefetchThreshold <= currentCount) {
            logger.debug("ackLater: sending: {}", pendingAck);
            session.sendAck(newPendingAck);
            pendingAck = null;
            deliveredCounter = 0;
            additionalWindowSize = 0;
        }
    }
}

