public class QueryMappersGenerator {
    // Helper method to simulate CaseFormat conversion (assumes Guava or similar)
    // In real code, this would use com.google.common.base.CaseFormat
    private static String convertCase(String input, CaseFormat from, CaseFormat to) {
        // This is a simplified placeholder; actual implementation depends on library
        if (from == CaseFormat.PASCAL && to == CaseFormat.LOWER_UNDERSCORE) {
            return pascalToSnake(input, false);
        } else if (from == CaseFormat.PASCAL && to == CaseFormat.UPPER_UNDERSCORE) {
            return pascalToSnake(input, true);
        } else if (from == CaseFormat.PASCAL && to == CaseFormat.PASCAL) {
            return input;
        }
        return input;
    }

    private static String pascalToSnake(String input, boolean upper) {
        if (input == null || input.isEmpty()) return input;
        StringBuilder result = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (Character.isUpperCase(c) && i > 0) {
                result.append('_');
            }
            result.append(upper ? Character.toUpperCase(c) : Character.toLowerCase(c));
        }
        return result.toString();
    }

    private static String removePrefix(String str, String prefix) {
        if (str != null && prefix != null && str.startsWith(prefix)) {
            return str.substring(prefix.length());
        }
        return str;
    }

    private static String removeSuffix(String str, String suffix) {
        if (str != null && suffix != null && str.endsWith(suffix)) {
            return str.substring(0, str.length() - suffix.length());
        }
        return str;
    }

    public static String transformTableName(List<Token> attrs, Decl decl) {
        String className = decl.getIdentifier().getValue();

        if (attrs.size() == 0 ||
            (attrs.size() == 1 &&
             attrs.get(0).getKind() == TokenKind.IDENTIFIER &&
             "dirty".equals(attrs.get(0).getValue().toLowerCase()))) {
            return convertCase(className, CaseFormat.PASCAL, CaseFormat.LOWER_UNDERSCORE);
        }

        Token tableToken = new Token(TokenKind.STRING_LITERAL, "");
        String classPrefix = "";
        String classSuffix = "";
        String tablePrefix = "";
        String tableSuffix = "";

        if (attrs.size() == 1) {
            tableToken = attrs.get(0);
        } else {
            int i = 0;
            while (i < attrs.size()) {
                Token attr = attrs.get(i);
                TokenKind kind = attr.getKind();
                String value = attr.getValue();

                if (kind == TokenKind.IDENTIFIER && "table".equals(value)) {
                    if (i + 2 < attrs.size()) {
                        tableToken = attrs.get(i + 2);
                    }
                    i += 2;
                } else if ("classPrefix".equals(value)) {
                    if (i + 2 < attrs.size()) {
                        classPrefix = attrs.get(i + 2).getValue();
                    }
                    i += 2;
                } else if ("classSuffix".equals(value)) {
                    if (i + 2 < attrs.size()) {
                        classSuffix = attrs.get(i + 2).getValue();
                    }
                    i += 2;
                } else if ("tablePrefix".equals(value)) {
                    if (i + 2 < attrs.size()) {
                        tablePrefix = attrs.get(i + 2).getValue();
                    }
                    i += 2;
                } else if ("tableSuffix".equals(value)) {
                    if (i + 2 < attrs.size()) {
                        tableSuffix = attrs.get(i + 2).getValue();
                    }
                    i += 2;
                } else if (kind == TokenKind.COMMA ||
                           kind == TokenKind.SEMI ||
                           (kind == TokenKind.IDENTIFIER && "dirty".equals(value))) {
                    // skip
                } else {
                    // diagReport(WARNING, attrs, value + " is illegal attr for @QueryMappersGenerator, which is modifying " + decl.getIdentifier().getValue(), "");
                    // Warning reporting omitted per Java translation scope; no equivalent runtime diag in plain Java
                }
                i++;
            }
        }

        className = removePrefix(className, classPrefix);
        className = removeSuffix(className, classSuffix);

        String tableName;
        TokenKind tableTokenKind = tableToken.getKind();
        String tableTokenValue = tableToken.getValue();

        if (tableTokenKind == TokenKind.STRING_LITERAL ||
            tableTokenKind == TokenKind.SINGLE_QUOTED_STRING_LITERAL) {
            tableName = tableTokenValue;
        } else if (tableTokenKind == TokenKind.IDENTIFIER) {
            switch (tableTokenValue) {
                case "LowerUnderScore":
                    tableName = convertCase(className, CaseFormat.PASCAL, CaseFormat.LOWER_UNDERSCORE);
                    break;
                case "UpperUnderScore":
                    tableName = convertCase(className, CaseFormat.PASCAL, CaseFormat.UPPER_UNDERSCORE);
                    break;
                case "Pascal":
                    tableName = className;
                    break;
                default:
                    tableName = tableTokenValue;
                    break;
            }
        } else {
            tableName = tableTokenValue;
        }

        return tablePrefix + tableName + tableSuffix;
    }

    // Supporting enums and classes (minimal required for compilation)
    enum TokenKind {
        IDENTIFIER, STRING_LITERAL, SINGLE_QUOTED_STRING_LITERAL, COMMA, SEMI
    }

    static class Token {
        private final TokenKind kind;
        private final String value;

        Token(TokenKind kind, String value) {
            this.kind = kind;
            this.value = value;
        }

        TokenKind getKind() { return kind; }
        String getValue() { return value; }
    }

    static class Decl {
        private final Identifier identifier;

        Decl(Identifier identifier) {
            this.identifier = identifier;
        }

        Identifier getIdentifier() { return identifier; }
    }

    static class Identifier {
        private final String value;

        Identifier(String value) {
            this.value = value;
        }

        String getValue() { return value; }
    }

    enum CaseFormat {
        PASCAL, LOWER_UNDERSCORE, UPPER_UNDERSCORE
    }
}

