private void unsubscribeByEventType(Object subscriber, TypeInfo eventType) {
    Optional<List<Subscription>> subscriptionsOpt = subscriptionsByEventType.get(eventType);
    if (subscriptionsOpt.isPresent()) {
        List<Subscription> subscriptions = subscriptionsOpt.get();
        int size = subscriptions.size();
        for (int i = 0; i < size; i++) {
            Subscription subscription = subscriptions.get(i);
            if (subscription != null &&
                subscriber != null &&
                subscription.subscriber == subscriber) {
                subscription.active = false;
                subscriptions.remove(i);
                i--;
                size--;
            }
        }
    }
