                                    if (md.getMessage() != null) {
                                        this.session.connection.rollbackDuplicate(this, md.getMessage());
                                    }
                                }
                            }
                        }
                        logger.debug(
                            "{} clearing delivered list ({}) on transport interrupt",
                            consumerId, deliveredMessages.size()
                        );
                        deliveredMessages.clear();
                        pendingAck = null;
                    }
                }
            }
            clearDeliveredListVal = false;
        }
    }
