public static void buildFlatView(Node node, java.util.function.Consumer<Node> nodeVisitor, boolean needProps) {
    NodeView start;
    NodeView end;

    Node parent = node.getParent();
    NodeView parentView = null;
    if (parent != null && parent.getCustom() instanceof NodeView) {
        parentView = (NodeView) parent.getCustom();
    }

    if (parentView != null) {
        if (parentView.getNode() instanceof Document) {
            NodeView list = new NodeView(node, parentView);
            list.setDepth(-1);
            list.setBulletListDepth(-1);
            list.setBlockQuoteDepth(-1);
            if (list.getCollector() != null && list.getCollector().getChildren() != null) {
                list.getCollector().getChildren().add(list);
            }
            list.setCollector(list);
            start = new NodeView(node, list);
            end = new NodeView(node, list);
        } else {
            start = new NodeView(node, parentView);
            end = new NodeView(node, parentView);
        }
    } else {
        start = new NodeView(node);
        end = new NodeView(node);
    }

    start.setStartend(0);

    if (needProps && (start.getProps() == null || start.getProps().isEmpty())) {
        start.setProps(new java.util.HashMap<String, Object>());
    }

    node.setCustom(start);

    if (start.getCollector() != null && start.getCollector().getChildren() != null) {
        start.getCollector().getChildren().add(start);
    }

    nodeVisitor.accept(node);

    end.setStartend(1);
    if (start.getCollector() != null && start.getCollector().getChildren() != null) {
        start.getCollector().getChildren().add(end);
    }
}

