class CommentEndDashState extends TokeniserState {
    @Override
    protected void read(Tokeniser tker, CharacterReader r) {
        char c = r.consume();
        switch (c) {
            case '-':
                tker.transition(CommentEnd.class);
                break;
            case '\0': // nullChar
                tker.error(this);
                tker.commentPending.append('-').append('\uFFFD'); // replacementChar (Unicode Replacement Character)
                tker.transition(CommentState.class);
                break;
            case CharacterReader.EOF:
                tker.eofError(this);
                tker.emitCommentPending();
                tker.transition(Data.class);
                break;
            default:
                tker.commentPending.append('-').append(c);
                tker.transition(CommentState.class);
                break;
        }
    }
}

