        // 'a'-'z': 97-122
        for (int i = 'a'; i <= 'z'; i++) {
            bs.set(i);
        }
        // 'A'-'Z': 65-90
        for (int i = 'A'; i <= 'Z'; i++) {
            bs.set(i);
        }
        // '0'-'9': 48-57
        for (int i = '0'; i <= '9'; i++) {
            bs.set(i);
        }
        // encoding spaces as '+' is done in the encode() method. '+' = 43
        bs.set(' '); // ' ' : 32
        bs.set('-'); // '-' : 45
        bs.set('_'); // '_' : 95
        bs.set('.'); // '.' : 46
        bs.set('*'); // '*' : 42
        return bs;
    }

