        boolean needToChange = false;
        StringBuilder out = new StringBuilder();
        CharArrayStream cas = new CharArrayStream(512);

        char[] charBuf = s.toCharArray();
        int len = charBuf.length;
        int i = 0;
        while (i < len) {
