        StringBuilder sb = new StringBuilder();
        int i = 0;

        char c;
        byte[] bytes = null;

        char[] charBuf = s.toCharArray();
        while (i < numChars) {
            c = charBuf[i];
            switch (c) {
                case '+':
                    sb.append(' ');
                    i++;
                    needToChange = true;
                    break;
                case '%':
                    try {
                        // (numChars-i)/3 is the upper limit of the remaining bytes.
                        if (bytes == null) {
                            bytes = new byte[(numChars - i) / 3];
                        }
                        i = handlePercentageSign(s, i, numChars, c, bytes, charBuf, sb);
                    } catch (IllegalArgumentException e) {
                        throw e;
                    } catch (Exception e) {
                        String err = "Illegal hex characters in escape (%) pattern - " + e.getMessage();
                        throw new IllegalArgumentException(err);
                    }
                    needToChange = true;
                    break;
                default:
                    sb.append(c);
                    i++;
            }
        }
        return needToChange ? sb.toString() : s;
    }

    private static int handlePercentageSign(String s, int index, int numChars, char charAt,
                                            byte[] bytes, char[] charBuf, StringBuilder sb) {
        int pos = 0;
        int i = index;
        char c = charAt;
        while ((i + 2) < numChars && c == '%') {
            String strNum = "0X" + s.substring(i + 1, i + 3);
            int v;
