                        i = handlePercentageSign(s, i, numChars, c, bytes, charBuf, sb)
                    } catch (e: IllegalArgumentException) {
                        throw e
                    } catch (e: Exception) {
                        let err: String = "Illegal hex characters in escape (%) pattern - " + e.message
                        throw IllegalArgumentException(err)
                    }
                    needToChange = true
                case _ =>
                    sb.append(c)
                    i++
            }
        }
        if (needToChange) {
            return sb.toString()
        }
        return s
    }

    private static func handlePercentageSign(s: String, index: Int64, numChars: Int64, char: Rune,
                                            bytes: Array<UInt8>, charBuf: Array<Rune>, sb: StringBuilder): Int64 {
        var pos: Int64 = 0
        var i: Int64 = index
        var c: Rune = char
        while ( ((i + 2) < numChars) && (c == r'%')) {
            let strNum: String = "0X" + s[(i+1)..(i+3)]
            let v: Int64 = Int64.parse(strNum)

            if (v < 0) {
                let err: String = "Illegal hex characters in escape " + "(%) pattern - negative value."
                throw IllegalArgumentException(err)
            }
            bytes[pos] = UInt8(v)
            pos++
            i += 3
            if (i < numChars) {
                c = charBuf[i]
            }
        }

        // Trailing, incomplete byte encoding (such as "%x") will cause an exception to be thrown.
        if (i < numChars && c == r'%') {
            throw IllegalArgumentException("Incomplete trailing escape (%) pattern.")
        }

        sb.append(String.fromUtf8(bytes[0..pos]))
        return i
    }
}

