    @Override
    public Pair<String, ArrayList<Pair<String, String>>> build(RedisMessage message) {
        if (message instanceof ArraysRedisMessage arraysMessage) {
            ArrayList<RedisMessage> children = arraysMessage.getValue();
            if (children != null) {
                if (children.size() != 2) {
                    throw new RedisException(
                        "Incompatible type, wrong size of ArraysRedisMessage, expect 2 but " + children.size()
                    );
                }

                String key = "";
                RedisMessage bulkStringMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(0),
                    RedisMessageType.BULK_STRINGS
                );
                if (bulkStringMessage instanceof BulkStringRedisMessage bulkStringMsg) {
                    String content = bulkStringMsg.getStringValue();
                    if (content != null) {
                        key = content;
                    } else {
                        throw new RedisException("Incompatible type, key is nil");
                    }
                } else {
                    throw new RedisException(
                        "Incompatible type, expected first message's type: " + RedisMessageType.BULK_STRINGS
                        + ", but " + bulkStringMessage.getType()
                    );
                }

                RedisMessage arrayMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(1),
                    RedisMessageType.ARRAYS
                );
                if (arrayMessage instanceof ArraysRedisMessage arrayMsg) {
                    ArrayList<Pair<String, String>> results = ResponseBuilderFactory.listOfStringTupleBuilder.build(arrayMsg);
                    return new Pair<>(key, results);
                } else if (message instanceof ErrorRedisMessage errorMsg) {
                    throw new RedisException(errorMsg.getValue());
                } else {
                    throw new RedisException(
                        "Incompatible type, expected second message's type: " + RedisMessageType.ARRAYS
                        + ", but " + bulkStringMessage.getType()
                    );
                }
            }
            throw new RedisException("Incompatible type, null arrays is not the expected type");
        } else if (message instanceof ErrorRedisMessage errorMsg) {
            throw new RedisException(errorMsg.getValue());
        }

        throw new RedisException("Incompatible type, " + message.getType() + " is not the expected type");
    }
}

