protected MqttWireMessage waitForResponse(Duration timeout) {
    String methodName = "waitForResponse";
    synchronized (responseLock) {
        // @TRACE 400=>key={0} timeout={1} sent={2} completed={3} hasException={4} response={5} token={6}
        Object[] params = {getKey(), timeout, sent, completed, exception != null, response, this};
        if (exception != null) {
            log.trace(CLASS_NAME, methodName, "400", params, exception);
        } else {
            log.trace(CLASS_NAME, methodName, "400", params);
        }

        while (!this.completed) {
            if (this.exception == null) {
                try {
                    // @TRACE 408=key={0} wait max={1}
                    log.trace(CLASS_NAME, methodName, "408", new Object[]{getKey(), timeout});

                    if (timeout == null) {
                        responseLockCondition.await();
                    } else {
                        responseLockCondition.await(timeout.toMillis(), TimeUnit.MILLISECONDS);
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    exception = new MqttException(e);
                } catch (Exception e) {
                    exception = new MqttException(e);
                }
            }
            if (!this.completed) {
                if (this.exception != null) {
                    // @TRACE 401=failed with exception
                    log.trace(CLASS_NAME, methodName, "401", null, exception);
                    throw exception;
                }

                if (timeout != null) {
                    // time up and still not completed
                    break;
                }
            }
        }
    }
    // @TRACE 402=key={0} response={1}
    log.trace(CLASS_NAME, methodName, "402", new Object[]{getKey(), this.response});
    return this.response;
}

