public class BACnetEncoding {
    public static byte[] encodingToApplicationDataTagHead(int arg_tagNum, long arg_tagLength, int arg_tagClass_mask) {
        // arg_tagClass_mask is already a UInt8 equivalent (0-255)
        ArrayList<Byte> _array_buf = new ArrayList<>();
        byte _SDContextTag = 0x00;

        _SDContextTag = (byte) (_SDContextTag | (arg_tagClass_mask & 0xFF));

        _array_buf.add(_SDContextTag);

        if (arg_tagNum < 15) {
            // tagnum < 15: tag number encoded in high 4 bits of first byte
            int _tagNum = arg_tagNum << 4;
            _SDContextTag = (byte) (_SDContextTag | (_tagNum & 0xFF));
            _array_buf.set(0, _SDContextTag);
        } else {
            // tagNum >= 15 and <= 255 (per BACnet spec; U8 range)
            // Set high nibble to 0b1111, then append full tagNum byte
            _SDContextTag = (byte) (_SDContextTag | 0xF0);
            _array_buf.set(0, _SDContextTag);
            _array_buf.add((byte) arg_tagNum);
        }

        if (arg_tagLength < 5) {
            // Length encoded directly in low 3 bits
            _SDContextTag = (byte) (_SDContextTag | (arg_tagLength & 0x07));
            _array_buf.set(0, _SDContextTag);
        } else if (arg_tagLength >= 5 && arg_tagLength <= 253) {
            // One-byte extended length: set low 3 bits to 0b101, then append length byte
            _SDContextTag = (byte) (_SDContextTag | 0x05);
            _array_buf.set(0, _SDContextTag);
            _array_buf.add((byte) arg_tagLength);
        } else if (arg_tagLength >= 254 && arg_tagLength <= 65535) {
            // Two-byte extended length: marker 0xFE, then 2-byte big-endian length
            _SDContextTag = (byte) (_SDContextTag | 0x05);
            _array_buf.set(0, _SDContextTag);
            _array_buf.add((byte) 0xFE);

            ByteBuffer bb = ByteBuffer.allocate(2).order(ByteOrder.BIG_ENDIAN);
            bb.putShort((short) arg_tagLength);
            _array_buf.add(bb.array()[0]);
            _array_buf.add(bb.array()[1]);
        } else if (arg_tagLength >= 65536 && arg_tagLength <= 4294967295L) {
            // Four-byte extended length: marker 0xFF, then 4-byte big-endian length
            _SDContextTag = (byte) (_SDContextTag | 0x05);
            _array_buf.set(0, _SDContextTag);
            _array_buf.add((byte) 0xFF);

            ByteBuffer bb = ByteBuffer.allocate(4).order(ByteOrder.BIG_ENDIAN);
            bb.putInt((int) arg_tagLength); // Note: arg_tagLength is guaranteed <= 2^32-1, fits in int
            _array_buf.add(bb.array()[0]);
            _array_buf.add(bb.array()[1]);
            _array_buf.add(bb.array()[2]);
            _array_buf.add(bb.array()[3]);
        }

        // Convert ArrayList<Byte> to byte[]
        byte[] result = new byte[_array_buf.size()];
        for (int i = 0; i < _array_buf.size(); i++) {
            result[i] = _array_buf.get(i);
        }
        return result;
    }

    // Example main for testing (not part of original, but added per requirement for top-level entry)
    public static void main(String[] args) {
        // Example usage (uncomment and adjust as needed):
        // byte[] tag = encodingToApplicationDataTagHead(10, 3, 0); // context-specific, class 0
    }
}

