    let n = Float64(x.getRows())
    var res: Float64 = 0.0

    //compute prior
    let pre: Array<McmcDist> = module.pre
    // let num = pre.size()
    // if(Float64(num) != 1.0) {
    //     throw IllegalArgumentException("prior_dens: pre_dist size incompatible with param1 size")
    // }

    res = res + pre[Int64(0.0)].logDensity(param1)

    //compute likelihood
    var i = 0.0
    while(stopGradient<Float64>(i) < n) {
        //暂时似然函数都设置为静态函数
        var temp = ExponentialMcmcDist.staticLogDensity(x[Int64(i)][0],
            param1)
        res = res + temp
        i = i + 1.0
    }

    return res
}

