/**
 * Checks if there are n consecutive characters starting at the given index,
 * where none of them are ECI (Extended Character Interpretation) characters.
 *
 * @param index The starting index (0-based) in the byte array.
 * @param n The number of consecutive characters to check.
 * @return true if n consecutive non-ECI characters exist starting at index; false otherwise.
 */
public static boolean haveNCharacters(long index, long n) {
    if (index + n - 1 >= bytes.size()) {
        return false;
    }

    for (long i = 0; i < n; i++) {
        if (isECI(index + i)) {
            return false;
        }
    }
    return true;
}

