    short[] count = new short[MAXBITS + 1]; // initialized to 0
    for (long i = lstart; i < lstart + symnums; i++) {
        count[lens[(int)i]]++;
    }
    /* The maximum code length whose frequency is greater than 0 is found. */
    max = MAXBITS;
    while (max > 0) {
        if (count[max] != 0) { break; }
