        codetable[0] = here;
        if (tabletype == TYPE_DISTS) {
            distbits = 1;
        } else {
            lenbits = 1;
        }
        return false;
    }
    root = midcodelen;
    if (root > max) {
        root = max;
    }
    /* Find the minimum code length whose frequency is greater than 0. */
    min = 1;
    while (min < max) {
        if (count[min] != 0) { break; }
        min++;
    }
    if (root < min) {
        root = min;
    }
    /* Check the validity of the code length sequence. */
    left = 1;
    for (int i = 1; i <= MAXBITS; i++) {
