                if (left <= 0) { break; }
                curr++;
                left <<= 1;
            }
            /* Check the size of the code table. */
            used += 1 << curr;
            if ((tabletype == TYPE_LENS && used > ENOUGH_LENS) ||
                (tabletype == TYPE_DISTS && used > ENOUGH_DISTS)) {
