        here.option = 64;
        here.bits = (byte)((len - drop) & 0xFF);
        here.value = 0;
        codetable[huff] = here;
    }
    if (tabletype == TYPE_DISTS) {
        distbits = root;
    } else {
        lenbits = root;
    }
    return false;
}

