public void appendStreamData(DataFrame data) {
    if (this.isEndStream) {
        this.unknownFrames.add(data);
        return;
    }

    if (!this.isGzip) {
        for (ByteBuffer d : data.getData()) {
            byte[] bytes = ByteBufferToArray(d);
            this.streamQueue.put(java.util.Optional.of(bytes));
            this.body.write(bytes);
        }
    } else {
        ByteBuffer gzipInput = ByteBuffer.allocate(8192); // reasonable initial capacity
        for (ByteBuffer d : data.getData()) {
            byte[] bytes = ByteBufferToArray(d);
            gzipInput.put(bytes);
            this.streamQueue.put(java.util.Optional.of(bytes));
        }

        gzipInput.flip(); // prepare for reading

        try (InputStream decompressInputStream = new java.util.zip.GZIPInputStream(
                new java.io.ByteArrayInputStream(gzipInput.array(), gzipInput.arrayOffset(), gzipInput.remaining()),
                10000)) {

            int readNum;
            while ((readNum = decompressInputStream.read(this.tempBuf)) > 0) {
                byte[] utf8data = java.util.Arrays.copyOfRange(this.tempBuf, 0, readNum);
                this.body.write(utf8data);
            }
        } catch (java.io.IOException e) {
            throw new RuntimeException("Failed to decompress stream data", e);
        }
    }

    if (data.getFlag(0x1)) {
        this.isEndStream = true;
        this.streamQueue.put(java.util.Optional.empty());
    }
}

