public class DhseqrTest {
    public static boolean testDhseqr(LFloat64 lFloat64, long i, DhseqrTestStruct test, SchurJob job, boolean wantz, long extra,
                                    boolean optwork) {
        final double tol = 1e-14;
        double evTol = test.tol;
        if (evTol == 0.0) {
            evTol = tol;
        }

        int n = test.n;
        int ihi = test.ihi;
        int ilo = test.ilo;

        // h = zeros(n, n, n + extra)
        double[][] h = new double[n][n];
        // Initialize with zeros
        for (int r = 0; r < n; r++) {
            java.util.Arrays.fill(h[r], 0.0);
        }
        // copyGeneral(h, General64(rows: n, cols: n, stride: max(1, n), data: test.h))
        int strideH = Math.max(1, n);
        for (int r = 0; r < n; r++) {
            for (int c = 0; c < n; c++) {
                h[r][c] = test.h[r * strideH + c];
            }
        }

        // hCopy = cloneGeneral(h)
        double[][] hCopy = new double[n][n];
        for (int r = 0; r < n; r++) {
            System.arraycopy(h[r], 0, hCopy[r], 0, n);
        }

        SchurComp compz = SchurComp.SCHUR_NONE;
        double[][] z = null;
        if (wantz) {
            compz = SchurComp.SCHUR_HESS;
            // z = nanGeneral(n, n, n + extra)
            z = new double[n][n];
            for (int r = 0; r < n; r++) {
                java.util.Arrays.fill(z[r], Double.NaN);
            }
        }

        double[] wr = new double[n];
        double[] wi = new double[n];
        // Initialize with NaN
        java.util.Arrays.fill(wr, Double.NaN);
        java.util.Arrays.fill(wi, Double.NaN);

        double[] work = new double[Math.max(1, n)];
        // Initialize with NaN
        java.util.Arrays.fill(work, Double.NaN);

        if (optwork) {
            // First call with lwork = -1 to query optimal size
            lFloat64.dhseqr(job, SchurComp.SCHUR_HESS, n, ilo, ihi,
                    flatten2D(h), strideH, wr, wi,
                    z != null ? flatten2D(z) : null, z != null ? strideH : 0,
                    work, -1);
            // work[0] contains optimal size
            long optimalSize = (long) Math.ceil(work[0]);
            work = new double[(int) optimalSize];
            java.util.Arrays.fill(work, Double.NaN);
        }

        int unconverged = lFloat64.dhseqr(job, compz, n, ilo, ihi,
                flatten2D(h), strideH, wr, wi,
                z != null ? flatten2D(z) : null, z != null ? strideH : 0,
                work, work.length);

        String prefix = String.format("Case %d: job=%s, compz=%s, n=%d, ilo=%d, ihi=%d, extra=%d, optwk=%s",
                i, job, compz, n, ilo, ihi, extra, optwork);

        if (unconverged > 0) {
            System.out.println(prefix + ": Dhseqr did not compute all eigenvalues. unconverged=" + unconverged);
            if (unconverged <= ilo) {
                throw new RuntimeException(prefix + ": 0 < unconverged <= ilo");
            }
        }

        if (hasNaN(wr)) {
            throw new RuntimeException(prefix + ": wr has NaN elements");
        }
        if (hasNaN(wi)) {
            throw new RuntimeException(prefix + ": wi has NaN elements");
        }

        int i_ev = 0;
        while (i_ev < n) {
            if (unconverged > 0 && i_ev == ilo) {
                i_ev = unconverged;
                continue;
            }
            if (wi[i_ev] == 0.0) {
                i_ev++;
                continue;
            }
            if (wr[i_ev] != wr[i_ev + 1]) {
                throw new RuntimeException(String.format("%s: wr[%d] and wr[%d] are not equal", prefix, i_ev, i_ev + 1));
            }
            if (wi[i_ev] < 0.0) {
                throw new RuntimeException(String.format("%s: wi[%d] > 0 but it is the last element", prefix, i_ev));
            }
            if (wi[i_ev + 1] != -wi[i_ev]) {
                throw new RuntimeException(String.format("%s: wi[%d] and wi[%d] are not complex conjugates", prefix, i_ev, i_ev + 1));
            }
            i_ev += 2;
        }

        if (job == SchurJob.EIGENVALUES_AND_SCHUR) {
            int idx = 0;
            while (idx < n) {
                if (unconverged > 0 && idx == ilo) {
                    idx = unconverged;
                    continue;
                }
                if (wi[idx] == 0.0) {
                    double diagVal = h[idx][idx];
                    if (Math.abs(wr[idx] - diagVal) > tol) {
                        throw new RuntimeException(String.format("%s: T not in Schur form (real eigenvalue not on diagonal)", prefix));
                    }
                    idx++;
                    continue;
                }
                // im = sqrt(|h[i+1,i]|) * sqrt(|h[i,i+1]|)
                double h_im1_i = h[idx + 1][idx];
                double h_i_ip1 = h[idx][idx + 1];
                double im = Math.sqrt(Math.abs(h_im1_i)) * Math.sqrt(Math.abs(h_i_ip1));
                double diag1 = h[idx][idx];
                double diag2 = h[idx + 1][idx + 1];
                if (Math.abs(wr[idx] - diag1) > tol || Math.abs(wr[idx] - diag2) > tol || Math.abs(wi[idx] - im) > tol) {
                    throw new RuntimeException(String.format("%s: conjugate pair and 2 x 2 diagonal block don't correspond", prefix));
                }
                idx += 2;
            }
        }

        boolean[] foundEV = new boolean[test.evWant.size()];
        java.util.Arrays.fill(foundEV, false);

        int ii = 0;
        while (ii < n) {
            if (unconverged > 0 && ii == ilo) {
                ii = unconverged;
                continue;
            }
            Complex128 ev = new Complex128(wr[ii], wi[ii]);
            ComplexMatchResult match = containsComplex(test.evWant, ev, evTol);
            if (!match.found) {
                throw new RuntimeException(String.format("%s: unexpected eigenvalue %s", prefix, ev));
            } else {
                foundEV[match.index] = true;
            }
            ii++;
        }

        if (unconverged == 0) {
            for (int j = 0; j < foundEV.length; j++) {
                if (!foundEV[j]) {
                    throw new RuntimeException(String.format("%s: %d th eigenvalue not found", prefix, j));
                }
            }
        }

        if (!wantz) {
            return true;
        }

        double resid = residualOrthogonal(z, false);
        if (resid > tol * n) {
            throw new RuntimeException(String.format("Case %s: Z is not orthogonal; resid=%f, want<=%f", prefix, resid, tol * n));
        }

        if (job == SchurJob.EIGENVALUES_AND_SCHUR) {
            // tz = zeros(n, n)
            double[][] tz = new double[n][n];
            for (int r = 0; r < n; r++) {
                java.util.Arrays.fill(tz[r], 0.0);
            }
            // gemm(NoTrans, Trans, 1.0, h, z, 0.0, tz)
            gemm(false, true, 1.0, h, z, 0.0, tz);

            // ztz = zeros(n, n)
            double[][] ztz = new double[n][n];
            for (int r = 0; r < n; r++) {
                java.util.Arrays.fill(ztz[r], 0.0);
            }
            // gemm(NoTrans, NoTrans, 1.0, z, tz, 0.0, ztz)
            gemm(false, false, 1.0, z, tz, 0.0, ztz);

            if (!equalApproxGeneral(ztz, hCopy, evTol)) {
                throw new RuntimeException(prefix + ": H != Z T Zᵀ");
            }
        }

        // restore h from hCopy
        for (int r = 0; r < n; r++) {
            System.arraycopy(hCopy[r], 0, h[r], 0, n);
        }

        // q = eye(n, n + extra)
        double[][] q = new double[n][n];
        for (int r = 0; r < n; r++) {
            java.util.Arrays.fill(q[r], 0.0);
            q[r][r] = 1.0;
        }

        lFloat64.dhseqr(job, SchurComp.SCHUR_ORIG, n, ilo, ihi,
                flatten2D(h), strideH, wr, wi,
                flatten2D(q), strideH, work, work.length);

        if (!equalApproxGeneral(z, q, 0.0)) {
            throw new RuntimeException(prefix + ": Z and Q are not equal");
        }

        return true;
    }

    // Helper method to flatten 2D array to 1D column-major (as expected by BLAS-like APIs)
    private static double[] flatten2D(double[][] mat) {
        if (mat == null) return null;
        int rows = mat.length;
        int cols = mat[0].length;
        double[] flat = new double[rows * cols];
        for (int c = 0; c < cols; c++) {
            for (int r = 0; r < rows; r++) {
                flat[r + c * rows] = mat[r][c];
            }
        }
        return flat;
    }

    private static boolean hasNaN(double[] arr) {
        for (double v : arr) {
            if (Double.isNaN(v)) return true;
        }
        return false;
    }

    // Placeholder for complex containment logic — must be implemented per domain
    private static class ComplexMatchResult {
        boolean found;
        int index;
        ComplexMatchResult(boolean found, int index) {
            this.found = found;
            this.index = index;
        }
    }

    private static ComplexMatchResult containsComplex(java.util.List<Complex128> list, Complex128 target, double tol) {
        for (int i = 0; i < list.size(); i++) {
            Complex128 c = list.get(i);
            if (Math.abs(c.real - target.real) <= tol && Math.abs(c.imag - target.imag) <= tol) {
                return new ComplexMatchResult(true, i);
            }
        }
        return new ComplexMatchResult(false, -1);
    }

    // Placeholder stub — real impl depends on linear algebra library
    private static double residualOrthogonal(double[][] z, boolean transpose) {
        // Compute Z^T Z or Z Z^T and measure deviation from identity
        int n = z.length;
        double[][] zz = new double[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                double sum = 0.0;
                for (int k = 0; k < n; k++) {
                    sum += transpose ? z[k][i] * z[k][j] : z[i][k] * z[j][k];
                }
                zz[i][j] = sum;
            }
        }
        double maxOffDiag = 0.0;
        double maxDiagErr = 0.0;
        for (int i = 0; i < n; i++) {
            maxDiagErr = Math.max(maxDiagErr, Math.abs(zz[i][i] - 1.0));
            for (int j = 0; j < n; j++) {
                if (i != j) {
                    maxOffDiag = Math.max(maxOffDiag, Math.abs(zz[i][j]));
                }
            }
        }
        return Math.max(maxOffDiag, maxDiagErr);
    }

    // Stub for gemm: C = alpha * op(A) * op(B) + beta * C
    private static void gemm(boolean transA, boolean transB, double alpha, double[][] A, double[][] B,
                            double beta, double[][] C) {
        int m = transA ? A[0].length : A.length;
        int n = transB ? B.length : B[0].length;
        int k = transA ? A.length : A[0].length;

        // Initialize C with beta*C if beta != 0
        if (beta != 0.0) {
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    C[i][j] *= beta;
                }
            }
        } else {
            for (int i = 0; i < m; i++) {
                java.util.Arrays.fill(C[i], 0.0);
            }
        }

        // Compute alpha * op(A) * op(B)
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                double sum = 0.0;
                for (int p = 0; p < k; p++) {
                    double aVal = transA ? A[p][i] : A[i][p];
                    double bVal = transB ? B[j][p] : B[p][j];
                    sum += aVal * bVal;
                }
                C[i][j] += alpha * sum;
            }
        }
    }

    // Stub for matrix equality with tolerance
    private static boolean equalApproxGeneral(double[][] A, double[][] B, double tol) {
        if (A.length != B.length) return false;
        for (int i = 0; i < A.length; i++) {
            if (A[i].length != B[i].length) return false;
            for (int j = 0; j < A[i].length; j++) {
                if (Math.abs(A[i][j] - B[i][j]) > tol) {
                    return false;
                }
            }
        }
        return true;
    }

    // Minimal supporting types (to make code self-contained & compilable)
    public enum SchurJob {
        EIGENVALUES_ONLY,
