func testDhseqr(lFloat64: LFloat64, i: Int64, test: dhseqrTestStruct, job: SchurJob, wantz: Bool, extra: Int64,
    optwork: Bool): Bool {
    const tol = 1e-14
    var evTol = test.tol
    if (evTol == 0.0) {
        evTol = tol
    }

    let n = test.n
    let ihi = test.ihi
    let ilo = test.ilo
    let h = zeros(n, n, n + extra)
    copyGeneral(h, General64(rows: n, cols: n, stride: max(1, n), data: test.h))
    let hCopy = cloneGeneral(h)

    var compz = SchurNone
    var z = General64(stride: max(1, n), rows: 0, cols: 0, data: [])
    if (wantz) {
        compz = SchurHess
        z = nanGeneral(n, n, n + extra)
    }

    let wr = nanSlice(n)
    let wi = nanSlice(n)

    var work = nanSlice(max(1, n))
    if (optwork) {
        lFloat64.dhseqr(job, SchurHess, n, ilo, ihi, h.data, h.stride, wr, wi, z.data, z.stride, work, -1)
        work = nanSlice(Int64(work[0]))
    }

    var unconverged = lFloat64.dhseqr(job, compz, n, ilo, ihi, h.data, h.stride, wr, wi, z.data, z.stride, work,
        work.size)
    let prefix = "Case ${i}: job=${job}, compz=${compz}, n=${n}, ilo=${ilo}, ihi=${ihi}, extra=${extra}, optwk=${optwork}"

    if (unconverged > 0) {
        println("${prefix}: Dhseqr did not compute all eigenvalues. unconverged=${unconverged}")
        if (unconverged <= ilo) {
            throw Exception("${prefix}: 0 < unconverged <= ilo")
        }
    }

    if (fHasNaN(wr)) {
        throw Exception("${prefix}: wr has NaN elements")
    }
    if (fHasNaN(wi)) {
        throw Exception("${prefix}: wi has NaN elements")
    }

    var i_ev = 0
    while (i_ev < n) {
        if (unconverged > 0 && i_ev == ilo) {
            i_ev = unconverged
            continue
        }
        if (wi[i_ev] == 0.0) {
            i_ev++
            continue
        }
        if (wr[i_ev] != wr[i_ev + 1]) {
            throw Exception("${prefix}: wr[${i_ev}] and wr[${i_ev + 1}] are not equal")
        }
        if (wi[i_ev] < 0.0) {
            throw Exception("${prefix}: wi[${i_ev}] > 0 but it is the last element")
        }
        if (wi[i_ev + 1] != -wi[i_ev]) {
            throw Exception("${prefix}: wi[${i_ev}] and wi[${i_ev + 1}] are not complex conjugates")
        }
        i_ev += 2
    }

    if (job == EigenvaluesAndSchur) {
        var i = 0
        while (i < n) {
            if (unconverged > 0 && i == ilo) {
                i = unconverged
                continue
            }
            if (wi[i] == 0.0) {
                if (wr[i] != h.data[i * h.stride + i]) {
                    throw Exception("${prefix}: T not in Schur form (real eigenvalue not on diagonal)")
                }
                i++
                continue
            }
            let im = sqrt(abs(h.data[(i + 1) * h.stride + i])) * sqrt(abs(h.data[i * h.stride + i + 1]))
            if (wr[i] != h.data[i * h.stride + i] || wr[i] != h.data[(i + 1) * h.stride + i + 1] || abs(wi[i] - im) > tol) {
                throw Exception("${prefix}: conjugate pair and 2 x 2 diagonal block don't correspond")
            }
            i += 2
        }
    }

    let foundEV = Array<Bool>(test.evWant.size, repeat: false)
    var ii = 0
    while (ii < n) {
        if (unconverged > 0 && ii == ilo) {
            ii = unconverged
            continue
        }
        let ev = Complex128(wr[ii], wi[ii])
        let (found, index) = containsComplex(test.evWant, ev, evTol)
        if (!found) {
            throw Exception("${prefix}: unexpected eigenvalue ${ev}")
        } else {
            foundEV[index] = true
        }
        ii++
    }
    if (unconverged == 0) {
        for (i in 0..foundEV.size) {
            if (!foundEV[i]) {
                throw Exception("${prefix}: ${i} th eigenvalue not found")
            }
        }
    }

    if (!wantz) {
        return true
    }

    let resid = residualOrthogonal(z, false)
    if (resid > tol * Float64(n)) {
        throw Exception("Case ${prefix}: Z is not orthogonal; resid=${resid}, want<=${tol * Float64(n)}")
    }

    if (job == EigenvaluesAndSchur) {
        let tz = zeros(n, n, n)
        gemm(NoTrans, Trans, 1.0, h, z, 0.0, tz)
        let ztz = zeros(n, n, n)
        gemm(NoTrans, NoTrans, 1.0, z, tz, 0.0, ztz)
        if (!equalApproxGeneral(ztz, hCopy, evTol)) {
            throw Exception("${prefix}: H != Z T Zᵀ")
        }
    }

    copyGeneral(h, hCopy)
    let q = eye(n, n + extra)
    lFloat64.dhseqr(job, SchurOrig, n, ilo, ihi, h.data, h.stride, wr, wi, q.data, q.stride, work, work.size)
    if (!equalApproxGeneral(z, q, 0.0)) {
        throw Exception("${prefix}: Z and Q are not equal")
    }

    return true
}

