import java.util.*;
import java.util.function.Consumer;
import java.util.stream.Collectors;
import java.util.stream.IntStream;

// Note: This Java translation assumes a custom UI framework abstraction.
// Since仓颉 (Cangjie) is a declarative UI language (similar to SwiftUI/ArkTS),
// and Java has no built-in declarative UI DSL, we map to a conceptual, compile-time-usable Java structure
// that preserves logic, state flow, and lifecycle — using idiomatic Java patterns (e.g., lambdas, builders, callbacks).
// Real Android usage would require binding to View/RecyclerView + custom Scroller logic; this is a *semantic* translation.

public class WheelMonthPicker {
    private WheelMonthPickerModel model = new WheelMonthPickerModel();
    private double scrollerDirection = 0.0;

    // Builder-style helper: occupyText → returns List of empty Text-like objects
    public List<Text> occupyText() {
        return IntStream.range(0, model.mHalfItemCount)
                .mapToObj(i -> new Text("")
                        .fontSize(model.mItemTextSize)
                        .height(model.mItemHeight)
                        .padding(model.mSpace))
                .collect(Collectors.toList());
    }

    // Builder-style helper: scrollIndex → returns Column containing Text items
    public Column scrollIndex(Color textColor) {
        Column column = new Column();
        if (!model.isCyslic) {
            for (long item : model.mData) {
                column.addChild(new Text(String.valueOf(item))
                        .fontSize(model.mItemTextSize)
                        .height(model.mItemHeight)
                        .fontColor(textColor)
                        .fontFamily(model.mFontFamily)
                        .padding(model.mSpace));
            }
        } else if (model.mVisibleItem < model.mData.size()) {
            // Repeat 3 times
            for (int i = 0; i < 3; i++) {
                for (long item : model.mData) {
                    column.addChild(new Text(String.valueOf(item))
                            .fontSize(model.mItemTextSize)
                            .height(model.mItemHeight)
                            .fontColor(textColor)
                            .fontFamily(model.mFontFamily)
                            .padding(model.mSpace));
                }
            }
        } else {
            int repeatCount = (int) Math.ceil((double) model.mVisibleItem / model.mData.size()) * 3;
            for (int i = 0; i < repeatCount; i++) {
                for (long item : model.mData) {
                    column.addChild(new Text(String.valueOf(item))
                            .fontSize(model.mItemTextSize)
                            .height(model.mItemHeight)
                            .fontColor(textColor)
                            .fontFamily(model.mFontFamily)
                            .padding(model.mSpace));
                }
            }
        }
        return column.widthPercent(30).alignItems(model.mAlign);
    }

    // Lifecycle: aboutToAppear
    public void aboutToAppear() {
        model.updateVisibleItemCount();

        // Simulate Timer.once(300μs)
        Timer.schedule(() -> {
            model.scrollInit(model.scroller1);
            double mOffset = model.scroller.currentOffset().yOffset;
            if (model.isCyslic) {
                model.scroller1.scrollTo(
                        0.0,
                        mOffset + (double) model.mHalfItemCount * model.mItemHeight
                );
                model.scroller.scrollTo(0.0, 1.0);
            } else {
                model.scroller1.scrollTo(0.0, mOffset);
            }
        }, 300, TimeUnit.MICROSECONDS);
    }

    // Main build logic — returns root Row
    public Row build() {
        Row row = new Row();
        Stack stack = new Stack();

        // Main scrollable wheel
        Scroll scroll = new Scroll(model.scroller)
                .height(model.mWheelHeight)
                .backgroundColor(model.scrollBgColor)
                .scrollBar(BarState.OFF)
                .onScroll(offset -> {
                    double mOffset = model.scroller.currentOffset().yOffset;
                    if (model.isCyslic) {
                        model.scroller1.scrollTo(
                                0.0,
                                mOffset + (double) model.mHalfItemCount * model.mItemHeight
                        );
                    } else {
                        model.scroller1.scrollTo(0.0, mOffset);
                    }
                })
                .onScrollEnd(() -> {
                    double scrollOffset = model.scroller.currentOffset().yOffset % model.mItemHeight;
                    double itemHeight = model.mItemHeight;

                    if (scrollOffset > itemHeight / 2.0) {
                        if (scrollerDirection <= 0.0) {
                            double targetY = model.scroller.currentOffset().yOffset - scrollOffset + itemHeight;
                            model.scroller.scrollTo(0.0, targetY, model.mDuration, Curve.EASE);

                            long size = model.mData.size();
                            double basePos = (model.scroller.currentOffset().yOffset - scrollOffset) / itemHeight + 1.0;
                            model.mSelectedItemPosition = (long) ((basePos % size + size) % size);

                            if (model.isCyslic) {
                                model.mSelectedItemPosition = (model.mSelectedItemPosition + model.mHalfItemCount) % size;
                                model.mSelectedData = String.valueOf(model.mData.get((int) model.mSelectedItemPosition));
                            } else {
                                int idx = (int) (model.mSelectedItemPosition % size);
                                model.mSelectedData = String.valueOf(model.mData.get(idx));
                            }
                        }
                    } else if (scrollOffset > 0.0 && scrollOffset < itemHeight / 2.0) {
                        if (scrollerDirection <= 0.0) {
                            double targetY = model.scroller.currentOffset().yOffset - scrollOffset;
                            model.scroller.scrollTo(0.0, targetY, model.mDuration, Curve.EASE);

                            long size = model.mData.size();
                            double basePos = (model.scroller.currentOffset().yOffset - scrollOffset) / itemHeight;
                            model.mSelectedItemPosition = (long) ((basePos % size + size) % size);

                            if (model.isCyslic) {
                                model.mSelectedItemPosition = (model.mSelectedItemPosition + model.mHalfItemCount) % size;
                                model.mSelectedData = String.valueOf(model.mData.get((int) model.mSelectedItemPosition));
                            } else {
                                int idx = (int) (model.mSelectedItemPosition % size);
                                model.mSelectedData = String.valueOf(model.mData.get(idx));
                            }
                        }
                    }

                    // Notify listener
                    if (model.mOnItemSelectedListener != null) {
                        int pos = (int) model.mSelectedItemPosition;
                        long data = model.mData.get(pos);
                        model.mOnItemSelectedListener.onItemSelected(pos, data);
                    }
                    model.setOnItemSelectedListener(model.mOnItemSelectedListener); // placeholder side-effect
                })
                .onScrollEdge(edge -> {
                    if (model.isCyslic) {
                        long size = model.mData.size();
                        double repeatFactor = Math.ceil((double) model.mVisibleItem / size) * 3.0;
                        double scollerBack = Math.ceil(repeatFactor / 2.0 + 1.0) * size * itemHeight;

                        switch (edge) {
                            case TOP:
                                model.scroller.scrollTo(0.0, scollerBack, 0.0, Curve.EASE);
                                break;
                            case BOTTOM:
                                double offset = (2 * model.mHalfItemCount + 1) * itemHeight;
                                model.scroller.scrollTo(0.0, scollerBack - offset, 0.0, Curve.EASE);
                                break;
                        }
                    }
                });

        Column scrollContent = new Column();
        if (!model.isCyslic) {
            occupyText().forEach(scrollContent::addChild);
        }
        scrollContent.addChild(scrollIndex(model.mItemTextColor));
        if (!model.isCyslic) {
            occupyText().forEach(scrollContent::addChild);
        }
        scroll.setChild(scrollContent);

        stack.addChild(scroll);

        // Indicator dividers
        if (model.hasIndicator) {
            Divider topDivider = new Divider()
                    .offset(0.0, -model.mItemHeight / 2.0)
                    .color(model.mIndicatorColor)
                    .widthPercent(30)
                    .strokeWidth(model.mIndicatorSize)
                    .zIndex(2);
            Divider bottomDivider = new Divider()
                    .offset(0.0, model.mItemHeight / 2.0)
                    .color(model.mIndicatorColor)
                    .widthPercent(30)
                    .strokeWidth(model.mIndicatorSize)
                    .zIndex(2);
            stack.addChild(topDivider);
            stack.addChild(bottomDivider);
        }

        // Selected item curtain (non-scrollable overlay)
        Scroll curtainScroll = new Scroll(model.scroller1)
                .height(model.mItemHeight)
                .enabled(false)
                .backgroundColor(model.mCurtainColor)
                .scrollBar(BarState.OFF);
        curtainScroll.setChild(scrollIndex(model.mSelectedItemTextColor));
        stack.addChild(curtainScroll);

        // Atmospheric effect (gradient flex)
        if (model.hasAtmospheric) {
            Flex flex = new Flex(new FlexParams())
                    .widthPercent(30)
                    .height(model.mWheelHeight)
                    .linearGradient(0.0, GradientDirection.TOP, model.atmosphericColor);
            stack.addChild(flex);
        }

        row.addChild(stack);
        return row;
    }

    // --- Supporting stub classes (minimal required for compilation & clarity) ---
    public static class Text {
        private String content;
        private double fontSize;
        private double height;
        private double padding;
        private Color fontColor;
        private String fontFamily;

        public Text(String content) { this.content = content; }

        public Text fontSize(double size) { this.fontSize = size; return this; }
        public Text height(double h) { this.height = h; return this; }
        public Text padding(double p) { this.padding = p; return this; }
        public Text fontColor(Color c) { this.fontColor = c; return this; }
        public Text fontFamily(String f) { this.fontFamily = f; return this; }
        public String getContent() { return content; }
    }

    public static class Column {
        private final List<Object> children = new ArrayList<>();
        private double widthPercent;
        private String alignItems;

        public Column addChild(Object child) { children.add(child); return this; }
        public Column widthPercent(double p) { this.widthPercent = p; return this; }
        public Column alignItems(String align) { this.alignItems = align; return this; }
        public List<Object> getChildren() { return Collections.unmodifiableList(children); }
    }

    public static class Row {
        private final List<Object> children = new ArrayList<>();

        public Row addChild(Object child) { children.add(child); return this; }
        public List<Object> getChildren() { return Collections.unmodifiableList(children); }
    }

    public static class Stack {
        private final List<Object> children = new ArrayList<>();

        public Stack addChild(Object child) { children.add(child); return this; }
        public List<Object> getChildren() { return Collections.unmodifiableList(children); }
    }

    public static class Scroll {
        private final Scroller scroller;
        private Object child;
        private double height;
        private Color backgroundColor;
        private BarState scrollBarState;
        private Consumer<Double> onScrollHandler = d -> {};
        private Runnable onScrollEndHandler = () -> {};
        private Consumer<Edge> onScrollEdgeHandler = e -> {};

        public Scroll(Scroller scroller) { this.scroller = scroller; }

        public Scroll height(double h) { this.height = h; return this; }
        public Scroll backgroundColor(Color c) { this.backgroundColor = c; return this; }
        public Scroll scrollBar(BarState s) { this.scrollBarState = s; return this; }
        public Scroll onScroll(Consumer<Double> h) { this.onScrollHandler = h; return this; }
        public Scroll onScrollEnd(Runnable r) { this.onScrollEndHandler = r; return this; }
        public Scroll onScrollEdge(Consumer<Edge> h) { this.onScrollEdgeHandler = h; return this; }
        public Scroll setChild(Object c) { this.child = c; return this; }
    }

    public static class Divider {
        private double offsetX, offsetY;
        private Color color;
        private double widthPercent;
        private double strokeWidth;
        private int zIndex;

        public Divider offset(double x, double y) { this.offsetX = x; this.offsetY = y; return this; }
        public Divider color(Color c) { this.color = c; return this; }
        public Divider widthPercent(double p) { this.widthPercent = p; return this; }
        public Divider strokeWidth(double w) { this.strokeWidth = w; return this; }
        public Divider zIndex(int z) { this.zIndex = z; return this; }
    }

    public static class Flex {
        private FlexParams params;
        private double widthPercent, height;
        private double angle;
        private GradientDirection direction;
        private List<Color> colors;

        public Flex(FlexParams params) { this.params = params; }

        public Flex widthPercent(double p) { this.widthPercent = p; return this; }
        public Flex height(double h) { this.height = h; return this; }
        public Flex linearGradient(double angle, GradientDirection dir, List<Color> colors) {
            this.angle = angle; this.direction = dir; this.colors = colors; return this;
        }
    }

    public static class FlexParams {}
    public static class Color {}
    public static class Scroller {
        public Offset currentOffset() { return new Offset(); }
        public void scrollTo(double x, double y) {}
        public void scrollTo(double x, double y, double duration, Curve curve) {}
    }
    public static class Offset { public double yOffset = 0.0; }
    public enum BarState { OFF }
    public enum Curve { EASE }
    public enum Edge { TOP, BOTTOM }
    public enum GradientDirection { TOP }

    public static class Timer {
        public static void schedule(Runnable task, long delay, TimeUnit unit) {
            // Stub — real impl would use ScheduledExecutorService
        }
    }

    public static class TimeUnit {
        public static final TimeUnit MICROSECONDS = null;
    }

    // Callback interface
    public interface OnItemSelectedListener {
        void onItemSelected(int position, long data);
    }
}

