public class GammaMcmcDist extends McmcDist {

    protected java.util.Vector<Double> params;

    public GammaMcmcDist() {
        this.params = new java.util.Vector<>();
        this.params.add(1.0);
    }

    public GammaMcmcDist(java.util.Vector<Double> params) {
        this.params = params;
    }

    @Override
    public double density(double x) {
        return gammaPDF(x, this.params.get(0));
    }

    @Override
    public double density(double x, java.util.Vector<Double> params) {
        return gammaPDF(x, params.get(0));
    }

    @Override
    public double logDensity(double x) {
        double alpha = this.params.get(0);
        return -gammaLog(alpha) + (alpha - 1.0) * mylog(x) - x;
    }

    public static double staticLogDensity(double x, double alpha) {
