/**
 * @brief RGF绘制库封装的窗口类注册方法
 * @param className        窗口类名
 * @param style            窗口风格
 * @param hbrBackground    窗口背景画刷(默认 NULL_BRUSH)
 * @note 非本类注册的窗口类需要手动注入窗口过程函数，否则RGF窗口类无法捕获系统事件
 */
public class RgfWindowUtils {
    // Native foreign function declaration (to be implemented via JNI)
    private static native long rApiRegisterWinClass(long className, long hInstance, int hbrBackground, int style);

    // Assuming these types map as follows:
    // LPCTSTR -> long (pointer to wide string)
    // HINSTANCE -> long (handle)
    // UINT -> int
    // RgfCtxt -> long (opaque context handle)

    public static boolean rwRegister(WinContext ctxt, String className, int style, int hbrBackground) {
        if (ctxt == null || className == null) {
            return false;
        }
        // Convert Java String to Windows wide string (UTF-16 LE bytes, null-terminated)
        // This simulates ruStrToWStr: allocates native memory, copies UTF-16, returns pointer
        long strPtr = ruStrToWStr(className);
        if (strPtr == 0) {
            return false;
        }

        if (ctxt.getContext().isPresent()) {
            Context ctx = ctxt.getContext().get();
            long winClassCTxtPtr = rApiRegisterWinClass(strPtr, ctx.hInst, hbrBackground, style);
            ctxt.setWinClassCTxtPtr(winClassCTxtPtr);
            // Free the allocated wide string memory
            ruFree(strPtr);
            // Record window class name
            ctxt.setClassName(className);
            // Add to static map (assumed thread-safe map implementation)
            staticWinClassMap.put(className, ctxt);
            return true;
        } else {
            ruFree(strPtr);
            return false;
        }
    }

    // Overloaded version with default hbrBackground = 5 (NULL_BRUSH)
    public static boolean rwRegister(WinContext ctxt, String className, int style) {
        return rwRegister(ctxt, className, style, 5);
    }

    // Placeholder native helper stubs — must be implemented in JNI layer
    private static native long ruStrToWStr(String s);
    private static native void ruFree(long ptr);

    // Static map to hold registered window classes (e.g., ConcurrentHashMap<String, WinContext>)
    private static final java.util.Map<String, WinContext> staticWinClassMap =
            new java.util.HashMap<>();

    // Example WinContext class (minimal skeleton for compilation)
    public static class WinContext {
        private long winClassCTxtPtr;
        private String _className;
        private java.util.Optional<Context> context = java.util.Optional.empty();

        public void setWinClassCTxtPtr(long ptr) { this.winClassCTxtPtr = ptr; }
        public void setClassName(String name) { this._className = name; }
        public java.util.Optional<Context> getContext() { return context; }
        // For demo: setter to inject context (real impl may differ)
        public void setContext(java.util.Optional<Context> ctx) { this.context = ctx; }
    }

    // Example Context class (minimal)
    public static class Context {
        public long hInst;
    }
}

