*/
public func rwRegister (ctxt:WinContext,className:String/*, hInstance:Context*/, style:UInt32, hbrBackground!:Int32 = 5/*NULL_BRUSH*/):Bool{
    let str:LPWSTR = unsafe{ ruStrToWStr(className) }
    if(context.isSome()){
        ctxt.winClassCTxtPtr = unsafe{ rApiRegisterWinClass(str,context.getOrThrow().hInst,hbrBackground,style) }
        unsafe{
            ruFree(CPointer<Unit>(str))
        }
        // 记录窗口类
        ctxt._className = className
        staticWinClassMap.add(className,ctxt)
        return true
    }else{
        return false
    }
}

