protected void tightMarshalThrowable(Throwable throwable, ByteBuffer dataOut, BoolStream bs) {
    if (throwable != null) {
        bs.writeBool(true);
        tightMarshalString(throwable.getClass().getName(), dataOut, bs);
        tightMarshalString(throwable.getMessage(), dataOut, bs);
        if (isStackTraceEnabled()) {
            StackTraceElement[] stackTrace = throwable.getStackTrace();
            if (stackTrace != null) {
                dataOut.putShort((short) stackTrace.length);
                for (StackTraceElement element : stackTrace) {
                    tightMarshalString(element.getClassName(), dataOut, bs);
                    tightMarshalString(element.getMethodName(), dataOut, bs);
                    tightMarshalString(element.getFileName(), dataOut, bs);
                    dataOut.putInt(element.getLineNumber());
                }
            } else {
                dataOut.putShort((short) 0);
            }
            tightMarshalThrowable(throwable.getCause(), dataOut, bs);
        }
    } else {
        bs.writeBool(false);
    }
}

