public class Luffa384 extends LuffaBase {
    public Luffa384() {
        super(HashSize384);
        resultBlocks = 4;
        ivLength = 32;

        initialize();
    }

    @Override
    protected void transformBlock(byte[] inputData, int index) {
        int chainv0 = 0;
        int chainv1 = 0;
        int chainv2 = 0;
        int chainv3 = 0;
        int chainv4 = 0;
        int chainv5 = 0;
        int chainv6 = 0;
        int chainv7 = 0;

        int tmp = 0;
        int[] data = convertBytesToUInt32sSwapOrder(inputData, index, blockSize);
        int[] t = new int[32];

        // First t initialization: t[i] = state[i] ^ state[i+8] ^ state[i+16] ^ state[i+24]
        for (int i = 0; i < 8; i++) {
            t[i] = state[i] ^ state[i + 8] ^ state[i + 16] ^ state[i + 24];
        }

        // Rotate t[0..7] right by 1 (t[7] becomes new t[0], others shift down)
        tmp = t[7];
        t[7] = t[6];
        t[6] = t[5];
        t[5] = t[4];
        t[4] = t[3] ^ tmp;
        t[3] = t[2] ^ tmp;
        t[2] = t[1];
        t[1] = t[0] ^ tmp;
        t[0] = tmp;

        // Mix t back into state columns
        for (int j = 0; j < 4; j++) {
            for (int i = 0; i < 8; i++) {
                state[i + 8 * j] ^= t[i];
            }
        }

        // Copy current state to t (full 32-word copy)
        for (int j = 0; j < 4; j++) {
            for (int i = 0; i < 8; i++) {
                t[i + 8 * j] = state[i + 8 * j];
            }
        }

        // Rotate each column of state (8 words per column) right by 1
        for (int j = 0; j < 4; j++) {
            tmp = state[7 + (8 * j)];
            state[7 + (8 * j)] = state[6 + (8 * j)];
            state[6 + (8 * j)] = state[5 + (8 * j)];
            state[5 + (8 * j)] = state[4 + (8 * j)];
            state[4 + (8 * j)] = state[3 + (8 * j)] ^ tmp;
            state[3 + (8 * j)] = state[2 + (8 * j)] ^ tmp;
            state[2 + (8 * j)] = state[1 + (8 * j)];
            state[1 + (8 * j)] = state[0 + (8 * j)] ^ tmp;
            state[8 * j] = tmp;
        }

        // XOR state with t shifted cyclically: t[(j+3)%4 * 8 + i]
        for (int j = 0; j < 4; j++) {
            for (int i = 0; i < 8; i++) {
                state[8 * j + i] ^= t[8 * ((j + 3) % 4) + i];
            }
        }

        // XOR each column with data and rotate data column
        for (int j = 0; j < 4; j++) {
            for (int i = 0; i < 8; i++) {
                state[i + 8 * j] ^= data[i];
            }

            // Rotate data[0..7] right by 1
            tmp = data[7];
            data[7] = data[6];
            data[6] = data[5];
            data[5] = data[4];
            data[4] = data[3] ^ tmp;
            data[3] = data[2] ^ tmp;
            data[2] = data[1];
            data[1] = data[0] ^ tmp;
            data[0] = tmp;
        }

        // Load initial chain values from first column
        chainv0 = state[0];
        chainv1 = state[1];
        chainv2 = state[2];
        chainv3 = state[3];
        chainv4 = state[4];
        chainv5 = state[5];
        chainv6 = state[6];
        chainv7 = state[7];

        // First round of 8 iterations (i = 0..7)
        for (int i = 0; i < 8; i++) {
            // First 8-word round function (chainv0..chainv3)
            tmp = chainv0;
            chainv0 |= chainv1;
            chainv2 ^= chainv3;
            chainv1 = ~chainv1;
            chainv0 ^= chainv3;
            chainv3 &= tmp;
            chainv1 ^= chainv3;
            chainv3 ^= chainv2;
            chainv2 &= chainv0;
            chainv0 = ~chainv0;
            chainv2 ^= chainv1;
            chainv1 |= chainv3;
            tmp ^= chainv1;
            chainv3 ^= chainv2;
            chainv2 &= chainv1;
            chainv1 ^= chainv0;
            chainv0 = tmp;

            // Second 8-word round function (chainv4..chainv7)
            tmp = chainv5;
            chainv5 |= chainv6;
            chainv7 ^= chainv4;
            chainv6 = ~chainv6;
            chainv5 ^= chainv4;
            chainv4 &= tmp;
            chainv6 ^= chainv4;
            chainv4 ^= chainv7;
            chainv7 &= chainv5;
            chainv5 = ~chainv5;
            chainv7 ^= chainv6;
            chainv6 |= chainv4;
            tmp ^= chainv6;
            chainv4 ^= chainv7;
            chainv7 &= chainv6;
            chainv6 ^= chainv5;
            chainv5 = tmp;

            // Cross-mix
            chainv4 ^= chainv0;

            // Rotations and XORs for chainv0/chainv4 pair
            chainv0 = Integer.rotateLeft(chainv0, 2);
            chainv0 ^= chainv4;
            chainv4 = Integer.rotateLeft(chainv4, 14);
            chainv4 ^= chainv0;
            chainv0 = Integer.rotateLeft(chainv0, 10);
            chainv0 ^= chainv4;
            chainv4 = Integer.rotateLeft(chainv4, 1);

            // Rotations and XORs for chainv1/chainv5 pair
            chainv5 ^= chainv1;
            chainv1 = Integer.rotateLeft(chainv1, 2);
            chainv1 ^= chainv5;
            chainv5 = Integer.rotateLeft(chainv5, 14);
            chainv5 ^= chainv1;
            chainv1 = Integer.rotateLeft(chainv1, 10);
            chainv1 ^= chainv5;
            chainv5 = Integer.rotateLeft(chainv5, 1);

            // Rotations and XORs for chainv2/chainv6 pair
            chainv6 ^= chainv2;
            chainv2 = Integer.rotateLeft(chainv2, 2);
            chainv2 ^= chainv6;
            chainv6 = Integer.rotateLeft(chainv6, 14);
            chainv6 ^= chainv2;
            chainv2 = Integer.rotateLeft(chainv2, 10);
            chainv2 ^= chainv6;
            chainv6 = Integer.rotateLeft(chainv6, 1);

            // Rotations and XORs for chainv3/chainv7 pair
            chainv7 ^= chainv3;
            chainv3 = Integer.rotateLeft(chainv3, 2);
            chainv3 ^= chainv7;
            chainv7 = Integer.rotateLeft(chainv7, 14);
            chainv7 ^= chainv3;
            chainv3 = Integer.rotateLeft(chainv3, 10);
            chainv3 ^= chainv7;
            chainv7 = Integer.rotateLeft(chainv7, 1);

            // Constant addition
            chainv0 ^= CNS[2 * i];
            chainv4 ^= CNS[2 * i + 1];
        }

        // Store first column result and load second column
        state[0] = chainv0;
        chainv0 = state[0 + 8];
        state[1] = chainv1;
        chainv1 = state[1 + 8];
        state[2] = chainv2;
        chainv2 = state[2 + 8];
        state[3] = chainv3;
        chainv3 = state[3 + 8];
        state[4] = chainv4;
        chainv4 = state[4 + 8];
        state[5] = chainv5;
        chainv5 = state[5 + 8];
        state[6] = chainv6;
        chainv6 = state[6 + 8];
        state[7] = chainv7;
        chainv7 = state[7 + 8];

        // Apply final rotation to chainv4..chainv7 before next round
        chainv4 = Integer.rotateLeft(chainv4, 1);
        chainv5 = Integer.rotateLeft(chainv5, 1);
        chainv6 = Integer.rotateLeft(chainv6, 1);
        chainv7 = Integer.rotateLeft(chainv7, 1);

        // Second round (i = 0..7)
        for (int i = 0; i < 8; i++) {
            tmp = chainv0;
            chainv0 |= chainv1;
            chainv2 ^= chainv3;
            chainv1 = ~chainv1;
            chainv0 ^= chainv3;
            chainv3 &= tmp;
            chainv1 ^= chainv3;
            chainv3 ^= chainv2;
            chainv2 &= chainv0;
            chainv0 = ~chainv0;
            chainv2 ^= chainv1;
            chainv1 |= chainv3;
            tmp ^= chainv1;
            chainv3 ^= chainv2;
            chainv2 &= chainv1;
            chainv1 ^= chainv0;
            chainv0 = tmp;

            tmp = chainv5;
            chainv5 |= chainv6;
            chainv7 ^= chainv4;
            chainv6 = ~chainv6;
            chainv5 ^= chainv4;
            chainv4 &= tmp;
            chainv6 ^= chainv4;
            chainv4 ^= chainv7;
            chainv7 &= chainv5;
            chainv5 = ~chainv5;
            chainv7 ^= chainv6;
            chainv6 |= chainv4;
            tmp ^= chainv6;
            chainv4 ^= chainv7;
            chainv7 &= chainv6;
            chainv6 ^= chainv5;
            chainv5 = tmp;

            chainv4 ^= chainv0;

            chainv0 = Integer.rotateLeft(chainv0, 2);
            chainv0 ^= chainv4;
            chainv4 = Integer.rotateLeft(chainv4, 14);
            chainv4 ^= chainv0;
            chainv0 = Integer.rotateLeft(chainv0, 10);
            chainv0 ^= chainv4;
            chainv4 = Integer.rotateLeft(chainv4, 1);

            chainv5 ^= chainv1;
            chainv1 = Integer.rotateLeft(chainv1, 2);
            chainv1 ^= chainv5;
            chainv5 = Integer.rotateLeft(chainv5, 14);
            chainv5 ^= chainv1;
            chainv1 = Integer.rotateLeft(chainv1, 10);
            chainv1 ^= chainv5;
            chainv5 = Integer.rotateLeft(chainv5, 1);

            chainv6 ^= chainv2;
            chainv2 = Integer.rotateLeft(chainv2, 2);
            chainv2 ^= chainv6;
            chainv6 = Integer.rotateLeft(chainv6, 14);
            chainv6 ^= chainv2;
            chainv2 = Integer.rotateLeft(chainv2, 10);
            chainv2 ^= chainv6;
            chainv6 = Integer.rotateLeft(chainv6, 1);

