            chainv3 = Integer.rotateLeft(chainv3, 2);
            chainv3 ^= chainv7;
            chainv7 = Integer.rotateLeft(chainv7, 14);
            chainv7 ^= chainv3;
            chainv3 = Integer.rotateLeft(chainv3, 10);
            chainv3 ^= chainv7;
            chainv7 = Integer.rotateLeft(chainv7, 1);

            chainv0 ^= CNS[2 * i + 16];
            chainv4 ^= CNS[2 * i + 17];
