public func hilbert<T>(N: Int64): Matrix<T> where T <: Float<T> {
    let res = empty<T>(N, N)
    for (i in 0..N) {
        for (j in 0..N) {
            res[i,j] = T.fromInt(1) / T.fromInt(i + j + 1)
        }
    }
    return res
}

