import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.net.URI;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.Map;
import java.util.HashMap;
import java.util.stream.Collectors;

public class DaprClient {
    private final String host;
    private final int port;
    private final HttpClient httpClient;

    public DaprClient(String host, int port, HttpClient httpClient) {
        this.host = host;
        this.port = port;
        this.httpClient = httpClient;
    }

    public void publishEvent(
            String pubsubName,
            String topic,
            byte[] data,
            String dataContentType,
            Map<String, String> meta) throws Exception {
        if (pubsubName == null || pubsubName.trim().isEmpty()) {
            throw new IllegalArgumentException("empty pubsubName");
        }
        if (topic == null || topic.trim().isEmpty()) {
            throw new IllegalArgumentException("empty topic");
        }

        String url = "http://" + host + ":" + port + "/v1.0/publish/" + pubsubName + "/" + topic;

        // Build query string from metadata
        if (meta != null && !meta.isEmpty()) {
            String queryString = meta.entrySet().stream()
                    .map(entry -> "metadata." + encode(entry.getKey()) + "=" + encode(entry.getValue()))
                    .collect(Collectors.joining("&"));
            url += "?" + queryString;
        }

        // Create HTTP request with POST body
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(url))
                .header("Content-Type", dataContentType)
                .POST(HttpRequest.BodyPublishers.ofByteArray(data))
                .build();

        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

        int statusCode = response.statusCode();
        if (statusCode == 204) {
            return;
        } else {
            throw new DaprException(response.body(), statusCode);
        }
    }

    private String encode(String s) {
        return URLEncoder.encode(s, StandardCharsets.UTF_8);
    }
}

// Minimal placeholder for DaprException — adjust based on actual exception structure
class DaprException extends Exception {
    private final int statusCode;

    public DaprException(String message, int statusCode) {
        super(message);
        this.statusCode = statusCode;
    }

    public int getStatusCode() {
        return statusCode;
    }
}

