        pubsubName: String,
        topic: String,
        data: Array<UInt8>,
        dataContentType: String,
        meta: Map<String, String>
    ): Unit {
        if (pubsubName == "") {
            throw IllegalArgumentException("empty pubsubName")
        }
        if (topic == "") {
            throw IllegalArgumentException("empty topic")
        }

        var url = "http://${host}:${port}/v1.0/publish/${pubsubName}/${topic}"
        let query = Form()
        for ((k, v) in meta) {
            query.add("metadata.${k}", v)
        }

        if (!meta.isEmpty()) {
            url += "?${query.toEncodeString()}"
        }

        let res = httpClient.newCall(
            Request.builder().url(url).post(RealRequestBody.create(
                MediaType.parse(dataContentType),
                data
            )).build()
        ).execute()

        match (res.getCode()) {
            case 204 => return
            case _ => throw res.getAs<DaprException>()
        }
    }

