import org.junit.jupiter.api.*;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.List;

public class MultiPartParserTestCaseSuit {

    private static JoyMultiPart checkPart(String name, String value, JoyMultiPartParser parser, JoyMemoryMultiPartHandler handler) {
        JoyMultiPart part = parser.getPart(name).orElseThrow(() -> new RuntimeException("Part not found: " + name));
        byte[] content = handler.getContent(name).orElseThrow(() -> new RuntimeException("Content not found: " + name));
        String rc = new String(content, StandardCharsets.UTF_8);
        if (!rc.equals(value)) {
            Assertions.fail("the part content is not match, expect=" + value + ", real=" + rc);
        }
        return part;
    }

    private static void checkPartProp(JoyMultiPart part, String filename, String contType) {
        if (!part.getFileName().equals(filename)) {
            Assertions.fail("the file name is not match, expect=" + filename + ", real=" + part.getFileName());
        }
        if (!part.getContentType().equals(contType)) {
            Assertions.fail("the content type is not match, expect=" + contType + ", real=" + part.getContentType());
        }
    }

    /**
     * 测试小数据块解析 - 验证解析包含文本字段和文件的小型 multipart 数据
     */
    @Test
    public void testSmallParts() {
        String str = "--WebKitFormBoundaryrGKCBY7qhFd3TrwA\r\n" +
                "Content-Disposition: form-data; name=\"text\"\r\n" +
                "\r\n" +
                "title\r\n" +
                "--WebKitFormBoundaryrGKCBY7qhFd3TrwA\r\n" +
                "Content-Disposition: form-data; name=\"file\"; filename=\"abc.png\"\r\n" +
                "Content-Type: image/png\r\n" +
                "\r\n" +
                "PNG ... content of abc.png\r\n" +
                "--WebKitFormBoundaryrGKCBY7qhFd3TrwA--";

        JoyMultiPartConfig config = new JoyMultiPartConfig();
        JoyMemoryMultiPartHandler handler = new JoyMemoryMultiPartHandler(config);
        ByteBuffer byteBuffer = new ByteBuffer();
        byteBuffer.write(str.getBytes(StandardCharsets.UTF_8));
        JoyMultiPartParser parser = new JoyMultiPartParser(config, handler, byteBuffer, "WebKitFormBoundaryrGKCBY7qhFd3TrwA");
        parser.parseParts();
        checkPart("text", "title", parser, handler);
        JoyMultiPart part = checkPart("file", "PNG ... content of abc.png", parser, handler);
        checkPartProp(part, "abc.png", "image/png");
    }

    /**
     * 测试大数据块解析 - 验证解析包含多个大文件（每个约 4KB）的 multipart 数据
     */
    @Test
    public void testBigParts() {
        String str = "--WebKitFormBoundaryrGKCBY7qhFd3TrwA\r\n" +
                "Content-Disposition: form-data; name=\"file1\"; filename=\"random.png\"\r\n" +
                "Content-Type: image/png\r\n" +
                "\r\n" +
                "test_file\r\n" +
                "--WebKitFormBoundaryrGKCBY7qhFd3TrwA\r\n" +
                "Content-Disposition: form-data; name=\"file2\"; filename=\"random.png\"\r\n" +
                "Content-Type: image/png\r\n" +
                "\r\n" +
                "test_file\r\n" +
                "--WebKitFormBoundaryrGKCBY7qhFd3TrwA\r\n" +
                "Content-Disposition: form-data; name=\"file3\"; filename=\"random.png\"\r\n" +
                "Content-Type: image/png\r\n" +
                "\r\n" +
                "test_file\r\n" +
                "--WebKitFormBoundaryrGKCBY7qhFd3TrwA--";

        JoyMultiPartConfig config = new JoyMultiPartConfig();
        JoyMemoryMultiPartHandler handler = new JoyMemoryMultiPartHandler(config);
        ByteBuffer byteBuffer = new ByteBuffer();
        String testFile = "abcd".repeat(1024);
        String filledStr = str.replace("test_file", testFile).replace("\n", "\r\n");
        byteBuffer.write(filledStr.getBytes(StandardCharsets.UTF_8));
        JoyMultiPartParser parser = new JoyMultiPartParser(config, handler, byteBuffer, "WebKitFormBoundaryrGKCBY7qhFd3TrwA");
        parser.parseParts();
        checkPart("file1", testFile, parser, handler);
        checkPart("file2", testFile, parser, handler);
        checkPart("file3", testFile, parser, handler);
    }

    /**
     * 测试最大分块数量限制 - 验证当分块数量超过配置的最大限制时抛出 MultiPartLimitReachedException 异常
     */
    @Test
    public void testMaxPartsLimit() {
        String boundary = "WebKitFormBoundaryrGKCBY7qhFd3TrwA";
        StringBuilder str = new StringBuilder();
        for (int i = 0; i < 3; i++) { // 3 parts (0, 1, 2)
            str.append("--WebKitFormBoundaryrGKCBY7qhFd3TrwA\r\n")
               .append("Content-Disposition: form-data; name=\"field").append(i).append("\"\r\n")
               .append("\r\n")
               .append("value").append(i).append("\r\n");
        }
        str.append("--WebKitFormBoundaryrGKCBY7qhFd3TrwA--");

        JoyMultiPartConfig config = new JoyMultiPartConfig();
        config.setMaxParts(2);
        JoyMemoryMultiPartHandler handler = new JoyMemoryMultiPartHandler(config);
        ByteBuffer byteBuffer = new ByteBuffer();
        byteBuffer.write(str.toString().getBytes(StandardCharsets.UTF_8));

        JoyMultiPartParser parser = new JoyMultiPartParser(config, handler, byteBuffer, boundary);
        Assertions.assertThrows(MultiPartLimitReachedException.class, () -> {
            parser.parseParts();
        }, "should throw MultiPartLimitReachedException when parts exceed max limit");
    }

    /**
     * 测试最大头部数量限制 - 验证当单个分块的头部数量超过配置的最大限制时抛出 MultiPartLimitReachedException 异常
     */
    @Test
    public void testMaxHeadersLimit() {
        String str = "--WebKitFormBoundaryrGKCBY7qhFd3TrwA\r\n" +
                "Content-Disposition: form-data; name=\"test\"\r\n" +
                "Header1: value1\r\n" +
                "Header2: value2\r\n" +
                "Header3: value3\r\n" +
                "Header4: value4\r\n" +
                "Header5: value5\r\n" +
                "Header6: value6\r\n" +
                "\r\n" +
                "content\r\n" +
                "--WebKitFormBoundaryrGKCBY7qhFd3TrwA--";

        JoyMultiPartConfig config = new JoyMultiPartConfig();
        config.setMaxHeaders(5);
        JoyMemoryMultiPartHandler handler = new JoyMemoryMultiPartHandler(config);
        ByteBuffer byteBuffer = new ByteBuffer();
        byteBuffer.write(str.getBytes(StandardCharsets.UTF_8));

        JoyMultiPartParser parser = new JoyMultiPartParser(config, handler, byteBuffer, "WebKitFormBoundaryrGKCBY7qhFd3TrwA");
        Assertions.assertThrows(MultiPartLimitReachedException.class, () -> {
            parser.parseParts();
        }, "should throw MultiPartLimitReachedException when headers exceed max limit");
    }

    /**
     * 测试无效边界字符串 - 验证当边界字符串不匹配时抛出 MultiPartParseException 异常
     */
    @Test
    @Disabled("Skipped per original annotation")
    public void testInvalidBoundary() {
        String str = "--InvalidBoundary\r\n" +
                "Content-Disposition: form-data; name=\"test\"\r\n" +
                "\r\n" +
