import java.util.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicLong;
import java.time.Instant;

public class OptimizedWorkerThread {
    private final int workerId;
    private final SchedulerConfig config;
    private final LockFreeRingBufferMailbox localQueue;
    private final LockFreeRingBufferMailbox globalQueue;
    private final LoadBalancer loadBalancer;
    private final List<OptimizedWorkerThread> otherWorkers;
    private final AtomicBoolean isRunning;
    private final AtomicLong tasksProcessed;
    private final AtomicLong stealAttempts;
    private final AtomicLong successfulSteals;
    private final AtomicLong lastStatsUpdate;
    private final AtomicLong adaptiveThrottleCounter;

    public OptimizedWorkerThread(int workerId, SchedulerConfig config,
                                 LockFreeRingBufferMailbox globalQueue, LoadBalancer loadBalancer) {
        this.workerId = workerId;
        this.config = config;
        this.localQueue = new LockFreeRingBufferMailbox(config.getMaxLocalQueueSize());
        this.globalQueue = globalQueue;
        this.loadBalancer = loadBalancer;
        this.otherWorkers = new ArrayList<>();
        this.isRunning = new AtomicBoolean(false);
        this.tasksProcessed = new AtomicLong(0);
        this.stealAttempts = new AtomicLong(0);
        this.successfulSteals = new AtomicLong(0);
        this.lastStatsUpdate = new AtomicLong(0);
        this.adaptiveThrottleCounter = new AtomicLong(0);
    }

    public void setOtherWorkers(List<OptimizedWorkerThread> workers) {
        // 简化实现：存储其他工作线程的引用
        for (OptimizedWorkerThread worker : workers) {
            if (worker.workerId != this.workerId) {
                this.otherWorkers.add(worker);
            }
        }
    }

    public void start() {
        if (isRunning.compareAndSet(false, true)) {
            new Thread(this::optimizedWorkerLoop).start();
        }
    }

    public void stop() {
        isRunning.set(false);
    }

    public boolean submitTask(Envelope envelope) {
        return localQueue.enqueue(envelope);
    }

    private void optimizedWorkerLoop() {
        while (isRunning.get()) {
            Optional<Envelope> task = findTaskOptimized();
            if (task.isPresent()) {
                executeTask(task.get());
                tasksProcessed.incrementAndGet();
                updateStatsIfNeeded();
            } else {
                // 高性能优化：极短休眠或自旋等待
                long sleepTime = calculateAdaptiveSleepTime();
                if (sleepTime <= 1) {
                    // 自旋等待，不休眠
                    Thread.onSpinWait();
                } else {
                    try {
                        Thread.sleep(0, (int) Math.min(sleepTime * 100, Integer.MAX_VALUE)); // nanosecond-scale sleep via ns in sleep(ns)
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                        break;
                    }
                }
            }
        }
    }

    private Optional<Envelope> findTaskOptimized() {
        // 1. 优先从本地队列获取任务
        Optional<Envelope> envelope = localQueue.dequeue();
        if (envelope.isPresent()) {
            return envelope;
        }
        // 2. 尝试从全局队列获取任务
        envelope = globalQueue.dequeue();
        if (envelope.isPresent()) {
            return envelope;
        }
        // 3. 使用优化的窃取策略
        return stealTasksOptimized();
    }

    private Optional<Envelope> stealTasksOptimized() {
        switch (config.getStealingStrategy()) {
            case RANDOM_STEALING:
                return stealRandomly();
            case BATCH_STEALING:
                return stealInBatch();
            case ADAPTIVE_STEALING:
                return stealAdaptively();
            default:
                return Optional.empty();
        }
    }

    private Optional<Envelope> stealRandomly() {
        stealAttempts.incrementAndGet();

        if (otherWorkers.isEmpty()) {
            return Optional.empty();
        }

        // 高效窃取：尝试多个工作线程
        int maxAttempts = Math.min(otherWorkers.size(), 4); // 最多尝试4个线程
        int startIndex = workerId % otherWorkers.size();

        for (int i = 0; i < maxAttempts; i++) {
            int targetIndex = (startIndex + i) % otherWorkers.size();
            OptimizedWorkerThread targetWorker = otherWorkers.get(targetIndex);

            Optional<Envelope> envelope = targetWorker.localQueue.dequeue();
            if (envelope.isPresent()) {
                successfulSteals.incrementAndGet();
                return envelope;
            }
        }

        return Optional.empty();
    }

    private Optional<Envelope> stealInBatch() {
        stealAttempts.incrementAndGet();

        // 高效批量窃取：优先从负载高的线程窃取
        int stolenTasks = 0;
        Optional<Envelope> firstTask = Optional.empty();
        int maxBatchSize = Math.min(config.getStealBatchSize(), 8); // 限制批量大小

        // 找到负载最高的工作线程
        int bestTargetIndex = 0;
        long maxQueueSize = 0;

        for (int i = 0; i < otherWorkers.size(); i++) {
            OptimizedWorkerThread worker = otherWorkers.get(i);
            long queueSize = worker.localQueue.size();
            if (queueSize > maxQueueSize) {
                maxQueueSize = queueSize;
                bestTargetIndex = i;
            }
        }

        // 从负载最高的线程批量窃取
        if (maxQueueSize > 0) {
            OptimizedWorkerThread targetWorker = otherWorkers.get(bestTargetIndex);

            for (int i = 0; i < maxBatchSize; i++) {
                Optional<Envelope> envelope = targetWorker.localQueue.dequeue();
                if (envelope.isPresent()) {
                    if (stolenTasks == 0) {
                        firstTask = envelope;
                    } else {
                        // 将额外的任务放入本地队列
                        localQueue.enqueue(envelope.get());
                    }
                    stolenTasks++;
                } else {
                    break; // 队列空了，停止窃取
                }
            }
        }

        if (stolenTasks > 0) {
            successfulSteals.addAndGet((long) stolenTasks);
        }

        return firstTask;
    }

    private Optional<Envelope> stealAdaptively() {
        // 自适应窃取：根据历史成功率调整策略
        double successRate = getStealSuccessRate();

        if (successRate > 0.5) {
            // 成功率高，使用批量窃取
            return stealInBatch();
        } else {
            // 成功率低，使用随机窃取
            return stealRandomly();
        }
    }

    private void executeTask(Envelope envelope) {
        try {
            // 高性能任务执行：移除打印开销
            Message message = envelope.getMessage();
            // 实际的消息处理逻辑应该在这里
            // 移除println以提升性能
        } catch (Exception e) {
            // 只在调试模式下打印错误
            // System.out.println("Worker " + workerId + " 执行任务失败: " + e);
        }
    }

    private long calculateAdaptiveSleepTime() {
        if (!config.isEnableAdaptiveThrottling()) {
            return 1; // 默认1纳秒单位
        }

        adaptiveThrottleCounter.incrementAndGet();
        long localQueueSize = localQueue.size();

        if (localQueueSize > config.getMaxLocalQueueSize() / 2) {
            return 0; // 高负载，自旋不休眠
        } else if (localQueueSize == 0) {
            return 10; // 无负载，短休眠(1μs)
        } else {
            return 1; // 中等负载，极短休眠(100ns)
        }
    }

    private void updateStatsIfNeeded() {
        long currentTime = Instant.now().toNanos();
        long lastUpdate = lastStatsUpdate.get();

        // 每1秒更新一次统计信息，减少更新频率
        if (currentTime - lastUpdate > 1_000_000_000L) { // 1s in nanoseconds
            if (lastStatsUpdate.compareAndSet(lastUpdate, currentTime)) {
                WorkerLoadStats stats = new WorkerLoadStats(
                    workerId,
                    localQueue.size(),
                    tasksProcessed.get(),
                    stealAttempts.get(),
                    successfulSteals.get(),
                    calculateCpuUsage()
                );
                loadBalancer.updateWorkerStats(workerId, stats);
            }
        }
    }

    private double calculateCpuUsage() {
        // 简化的CPU使用率计算
        long processed = tasksProcessed.get();
        return (processed % 100) / 100.0;
    }

    private double getStealSuccessRate() {
        long attempts = stealAttempts.get();
        if (attempts == 0) {
            return 0.0;
        }
