        queries.add("SET NAMES '" + config.charset + "'");
    }

    if (config.timezone != null) {
        queries.add("SET time_zone = '" + config.timezone + "'");
    }

    if (config.applicationName != null) {
        queries.add("SET session sql_mode = 'STRICT_TRANS_TABLES,NO_ZERO_DATE,NO_ZERO_IN_DATE,ERROR_FOR_DIVISION_BY_ZERO'");
    }

    for (String query : queries) {
        Result<?, ?> result = connection.execute(query, new ArrayList<>());
        if (result.isErr()) {
            return Result.err(new DatabaseError(
                "INITIALIZATION_FAILED",
                "Failed to initialize connection"
            ));
        }
    }

    return Result.ok(true);
}

