    /**
     * 合并多个流 - 将多个StreamSource合并为一个
     */
    public static <T> StreamSource<T> merge(StreamSource<T>[] sources) {
        List<T> allElements = new ArrayList<>();
        for (StreamSource<T> source : sources) {
            List<T> elements = source.getElements();
            allElements.addAll(elements);
        }
        return new StreamSource<>(allElements.toArray(), "merged-source");
    }

    /**
     * 连接多个流 - 按顺序连接多个StreamSource
     */
    public static <T> StreamSource<T> concat(StreamSource<T>[] sources) {
        List<T> allElements = new ArrayList<>();
        for (StreamSource<T> source : sources) {
            List<T> elements = source.getElements();
            allElements.addAll(elements);
        }
        return new StreamSource<>(allElements.toArray(), "concatenated-source");
    }

    /**
     * 压缩两个流 - 将两个流的元素配对
     */
    public static <T, U> StreamSource<Tuple2<T, U>> zip(StreamSource<T> source1, StreamSource<U> source2) {
        List<T> elements1 = source1.getElements();
        List<U> elements2 = source2.getElements();
        int minSize = Math.min(elements1.size(), elements2.size());

        Tuple2<T, U>[] zippedElements = new Tuple2[minSize];
        for (int i = 0; i < minSize; i++) {
            zippedElements[i] = new Tuple2<>(elements1.get(i), elements2.get(i));
        }
        return new StreamSource<>(zippedElements, "zipped-source");
    }

    /**
     * 交错合并 - 交替取两个流的元素
     */
    public static <T> StreamSource<T> interleave(StreamSource<T> source1, StreamSource<T> source2) {
        List<T> elements1 = source1.getElements();
        List<T> elements2 = source2.getElements();
        List<T> result = new ArrayList<>();

        int maxSize = Math.max(elements1.size(), elements2.size());
        for (int i = 0; i < maxSize; i++) {
            if (i < elements1.size()) {
                result.add(elements1.get(i));
            }
            if (i < elements2.size()) {
                result.add(elements2.get(i));
            }
        }

