     * 分区 - 根据谓词将流分为两部分
     */
    public static <T> Tuple2<StreamSource<T>, StreamSource<T>> partition(StreamSource<T> source, Predicate<T> predicate) {
        List<T> elements = source.getElements();
        List<T> trueElements = new ArrayList<>();
        List<T> falseElements = new ArrayList<>();

        for (T element : elements) {
            if (predicate.test(element)) {
                trueElements.add(element);
            } else {
                falseElements.add(element);
            }
        }

        @SuppressWarnings("unchecked")
        T[] trueArray = (T[]) trueElements.toArray();
        @SuppressWarnings("unchecked")
        T[] falseArray = (T[]) falseElements.toArray();

        StreamSource<T> trueSource = new StreamSource<>(trueArray, "partition-true");
        StreamSource<T> falseSource = new StreamSource<>(falseArray, "partition-false");
        return new Tuple2<>(trueSource, falseSource);
    }

    /**
     * 分组批次 - 按条件分组元素
     */
    public static <T> StreamSource<T[]> groupedWithin(StreamSource<T> source, int maxElements, Predicate<T> predicate) {
        List<T> elements = source.getElements();
        List<T[]> groups = new ArrayList<>();
        List<T> currentGroup = new ArrayList<>();

        for (T element : elements) {
            currentGroup.add(element);

            if (currentGroup.size() >= maxElements || predicate.test(element)) {
                @SuppressWarnings("unchecked")
                T[] groupArray = (T[]) currentGroup.toArray();
                groups.add(groupArray);
                currentGroup.clear();
            }
        }

        // 添加剩余元素
        if (!currentGroup.isEmpty()) {
            @SuppressWarnings("unchecked")
            T[] remainingArray = (T[]) currentGroup.toArray();
            groups.add(remainingArray);
        }

        @SuppressWarnings("unchecked")
        T[][] groupsArray = (T[][]) groups.toArray();
        return new StreamSource<>(groupsArray, "groupedWithin-source");
    }

    /**
     * 缓冲区 - 创建固定大小的缓冲区
     */
    public static <T> StreamSource<T[]> buffer(StreamSource<T> source, int size, String overflowStrategy) {
        List<T> elements = source.getElements();
        List<T[]> buffers = new ArrayList<>();

        int start = 0;
        while (start < elements.size()) {
            int end = Math.min(start + size, elements.size());
            int bufferSize = end - start;
            T[] buffer = (T[]) new Object[bufferSize];
            for (int i = 0; i < bufferSize; i++) {
                buffer[i] = elements.get(start + i);
            }
            buffers.add(buffer);
            start = end;
        }

