    public static <T> StreamSource<T> throttle(StreamSource<T> source, long elementsPerSecond) {
        // 简化实现：直接返回原始流（实际应用中会有真正的限流）
        return new StreamSource<>(source.getElements().toArray(), source.getSourceId() + ".throttle(" + elementsPerSecond + "/s)");
