    public void refreshToken() {
        AuthState currentState = getCurrentState();
        TokenRequest request = currentState.createTokenRefreshRequest();
        ClientAuthentication clientAuthentication = currentState.getClientAuthentication();

        TokenResponse.Callback callback = (tokenResponse, ex) -> {
            if (ex == null && tokenResponse != null) {
                currentState.update(tokenResponse, ex);
                replace(currentState);
                HiLog.error(TAG, "------------> 令牌刷新成功");
