            } else {
                String msg = (ex != null) ? ex.getMessage() : "Unknown error";
                HiLog.error(TAG, "------------> 令牌刷新失败：" + msg);
                return false;
            }
        };
        service.performTokenRequest(request, clientAuthentication, callback);
    }

    // ----------------- 本地持久化的一些方法
    private AuthState readState() {
        mPrefsLock.lock();
        try {
            String currentState = "";
            Object value = preferences.get(KEY_STATE);
            if (value instanceof String) {
                currentState = (String) value;
            } else {
                HiLog.error(TAG, "------------> 获取到的值不是String类型");
            }
            if (currentState.isEmpty()) {
                return new AuthState();
            } else {
                return AuthState.jsonDeserialize(currentState);
            }
        } catch (Exception e) {
            HiLog.error(TAG, "------------> JSON deserialize failed: " + e.getMessage());
            return new AuthState();
        } finally {
            mPrefsLock.unlock();
        }
    }

    private void writeState(AuthState state) {
        mPrefsLock.lock();
        try {
            preferences.remove(KEY_STATE);
            preferences.put(KEY_STATE, state.jsonSerializeString());
            preferences.flush();
        } finally {
            mPrefsLock.unlock();
        }
    }

    private AuthState replace(AuthState state) {
        writeState(state);
        this.authState = state;
        return state;
    }

    private AuthState getCurrentState() {
        if (authState != null) {
            return authState;
        }
        authState = readState();
        return authState;
    }
}

