public class JWTVerifier {
    private final byte[] headerBytes;
    private final byte[] payloadBytes;
    private final byte[] signBytes;
    private final String data;
    private final JWT jwt;

    public JWTVerifier(String data, JWT jwt) {
        this.data = data;
        this.jwt = jwt;

        int firstDot = data.indexOf('.');
        int lastDot = (firstDot >= 0) ? data.indexOf('.', firstDot + 1) : -1;

        if (firstDot == -1 || lastDot == -1) {
            throw new IllegalArgumentException("Invalid JWT format: missing dots");
        }

        String headerB64 = data.substring(0, firstDot);
        String payloadB64 = data.substring(firstDot + 1, lastDot);
        String signB64 = data.substring(lastDot + 1);

        this.headerBytes = Base64.getDecoder().decode(headerB64);
        this.payloadBytes = Base64.getDecoder().decode(payloadB64);
        this.signBytes = Base64.getDecoder().decode(signB64);

        String headerJsonStr = new String(headerBytes, java.nio.charset.StandardCharsets.UTF_8);
        String payloadJsonStr = new String(payloadBytes, java.nio.charset.StandardCharsets.UTF_8);

        JsonValue headerJson = JsonValue.fromStr(headerJsonStr);
        JsonValue payloadJson = JsonValue.fromStr(payloadJsonStr);

        populate(headerJson, jwt.headers);
        populate(payloadJson, jwt.payload);
    }

    private static <T> void populate(JsonValue json, Map<String, T> map) {
        if (json instanceof JsonObject jsonObject) {
            for (Map.Entry<String, JsonValue> entry : jsonObject.getFields().entrySet()) {
                String key = entry.getKey();
                JsonValue value = entry.getValue();
                @SuppressWarnings("unchecked")
                T typedValue = (T) getJsonValue(value);
                map.put(key, typedValue);
            }
        }
    }

    @SuppressWarnings("unchecked")
    private static <T> T getJsonValue(JsonValue v) {
        Object r;
        if (v instanceof JsonBool bool) {
            r = bool.getValue();
        } else if (v instanceof JsonInt integer) {
            r = integer.getValue();
        } else if (v instanceof JsonString string) {
            r = string.getValue();
        } else if (v instanceof JsonFloat flt) {
            r = flt.getValue();
        } else if (v instanceof JsonArray array) {
            List<Object> list = new ArrayList<>();
            for (int i = 0; i < array.size(); i++) {
                Optional<JsonValue> elemOpt = array.get(i);
                if (elemOpt.isPresent()) {
                    list.add(getJsonValue(elemOpt.get()));
                } else {
                    list.add(null);
                }
            }
            r = list;
        } else if (v instanceof JsonObject obj) {
            Map<String, Object> vm = new HashMap<>();
            populate(obj, vm);
            r = vm;
        } else {
            r = null;
        }
        return (T) r;
    }

    public Optional<Object> getPayload(String name) {
        return Optional.ofNullable(jwt.payload.get(name));
    }

    public Optional<String> getHeader(String name) {
        return Optional.ofNullable(jwt.headers.get(name));
    }

    public Optional<DateTime> getExpireAt() {
        Optional<Duration> dur = getExpireAtDuration();
        return dur.map(d -> DateTime.now().plus(d));
    }

    public Optional<Duration> getExpireAtDuration() {
        Optional<Long> millis = getExpireAtMillis();
        return millis.map(m -> new Duration(m));
    }

    public Optional<Long> getExpireAtMillis() {
        return getPayloadValue("exp", Long.class);
    }

    public <T> Optional<T> getPayloadValue(String name, Class<T> clazz) {
        Optional<Object> raw = getPayload(name);
        if (!raw.isPresent()) return Optional.empty();

        Object x = raw.get();
        if (clazz.isInstance(x)) {
            return Optional.of(clazz.cast(x));
        } else if (x instanceof String str) {
            return tryParse(str, clazz);
        } else if (x instanceof Object toStringObj && toStringObj.toString() != null) {
            return tryParse(toStringObj.toString(), clazz);
        }
        return Optional.empty();
    }

    public <T> Optional<T> getHeaderValue(String name, Class<T> clazz) {
        Optional<String> strOpt = getHeader(name);
        return strOpt.flatMap(s -> tryParse(s, clazz));
    }

    private <T> Optional<T> tryParse(String value, Class<T> clazz) {
        if (value == null) return Optional.empty();
        if (clazz == Long.class || clazz == long.class) {
            try {
                return Optional.of(clazz.cast(Long.parseLong(value)));
            } catch (NumberFormatException e) {
                return Optional.empty();
            }
        } else if (clazz == Integer.class || clazz == int.class) {
            try {
                return Optional.of(clazz.cast(Integer.parseInt(value)));
            } catch (NumberFormatException e) {
                return Optional.empty();
            }
        } else if (clazz == Boolean.class || clazz == boolean.class) {
            if ("true".equalsIgnoreCase(value) || "false".equalsIgnoreCase(value)) {
                return Optional.of(clazz.cast(Boolean.parseBoolean(value)));
            }
            return Optional.empty();
        } else if (clazz == String.class) {
            return Optional.of(clazz.cast(value));
        } else if (Parsable.class.isAssignableFrom(clazz)) {
            try {
                // Assuming static tryParse(String) method exists on T
                java.lang.reflect.Method tryParseMethod = clazz.getDeclaredMethod("tryParse", String.class);
                @SuppressWarnings("unchecked")
                Optional<T> result = (Optional<T>) tryParseMethod.invoke(null, value);
                return result;
            } catch (Exception e) {
                return Optional.empty();
            }
        }
        return Optional.empty();
    }

    public boolean verify() {
        byte[] dataToSign = bytesToSign(headerBytes, payloadBytes);
        return jwt.signAlgo.verify(dataToSign, signBytes);
    }

    private byte[] bytesToSign(byte[] header, byte[] payload) {
        // Standard JWT signing input: base64UrlEncode(header) + '.' + base64UrlEncode(payload)
        String headerB64 = Base64.getUrlEncoder().withoutPadding().encodeToString(header);
        String payloadB64 = Base64.getUrlEncoder().withoutPadding().encodeToString(payload);
        return (headerB64 + "." + payloadB64).getBytes(java.nio.charset.StandardCharsets.UTF_8);
    }
}

