            case Aliased -> (byte) 1;
            case GdiClassic -> (byte) 2;
            case GdiNatural -> (byte) 3;
            case Natural -> (byte) 4;
            case NaturalSymmetric -> (byte) 5;
            case Outline -> (byte) 6;
        };
