import java.util.ArrayList;
import java.util.concurrent.locks.ReentrantLock;

public class DoubleExplicitBucketHistogramHandler extends AggregatorHandle<HistogramPointData> {
    private final double[] boundaries;
    private final ArrayList<Double> boundaryList;
    private double sum;
    private double minValue;
    private double maxValue;
    private long count;
    private final long[] counts;
    private final ReentrantLock mtx = new ReentrantLock();

    public DoubleExplicitBucketHistogramHandler(double[] boundaries, ArrayList<Double> boundaryList) {
        this.boundaries = boundaries;
        this.boundaryList = boundaryList;
        this.sum = 0.0;
        this.minValue = Double.MAX_VALUE;
        this.maxValue = -1.0;
        this.count = 0;
        this.counts = new long[boundaries.length + 1];
        // counts is already zero-initialized by JVM
    }

    @Override
    protected HistogramPointData doAggregateThenMaybeReset(
            long startEpochNanos,
            long epochNanos,
            Attributes attributes,
            boolean reset) {
        mtx.lock();
        try {
            HistogramPointData point = new HistogramPointData(
                    startEpochNanos,
                    epochNanos,
                    attributes,
                    sum,
                    minValue,
                    maxValue,
                    count,
                    boundaryList,
                    counts.clone() // copy new object
            );
            if (reset) {
                this.sum = 0.0;
                this.minValue = Double.MAX_VALUE;
                this.maxValue = -1.0;
                this.count = 0;
                for (int i = 0; i < counts.length; i++) {
                    counts[i] = 0;
                }
            }
            return point;
        } finally {
            mtx.unlock();
        }
    }

    @Override
    protected void doRecordDouble(double value) {
        int bucketIndex = AdderUtil.findBucketIndex(boundaries, value);
        mtx.lock();
        try {
            this.sum += value;
            this.maxValue = Math.max(this.maxValue, value);
            this.minValue = Math.min(this.minValue, value);
            this.count++;
            counts[bucketIndex]++;
        } finally {
            mtx.unlock();
        }
    }

    @Override
    protected void doRecordLong(long value) {
        doRecordDouble((double) value);
    }
}

