private func createNTFTPEntryParser(config2: ?FTPClientConfig): FTPFileEntryParser {
        if (config2.isSome() && FTPClientConfig.SYST_NT == config2.getOrThrow().getServerSystemKey()) {
            return NTFTPEntryParser(config2)
        }
        // clone the config2 as it may be changed by the parsers (NET-602)
        let config2 = if (config2.isSome()) {
            FTPClientConfig(config2.getOrThrow())
        } else {
            clone<FTPClientConfig>
        }

        return CompositeFileEntryParser(
            NTFTPEntryParser(config2),
            UnixFTPEntryParser(
                config2,
                config2.isSome() && FTPClientConfig.SYST_UNIX_TRIM_LEADING == config2.getOrThrow().getServerSystemKey()
            )
        )
    }

