public class BigMoney {
    public final long amount;
    public final String currency;

    public BigMoney(long amount, String currency) {
        this.amount = amount;
        this.currency = currency;
    }
}

public class MoneyUtils {
    public static BigMoney allocate(BigMoney m, long r, long s) {
        if (s <= 0) {
            throw new IllegalArgumentException("划分比例s不能小于等于零");
        }
        // Use BigInteger to avoid overflow during multiplication and division
        java.math.BigInteger amountBI = java.math.BigInteger.valueOf(m.amount);
        java.math.BigInteger rBI = java.math.BigInteger.valueOf(r);
        java.math.BigInteger sBI = java.math.BigInteger.valueOf(s);
        java.math.BigInteger resultAmount = amountBI.multiply(rBI).divide(sBI);
        return new BigMoney(resultAmount.longValue(), m.currency);
    }
}

