public func allocate(m: BigMoney, r: Int64, s: Int64): BigMoney {
    if (s <= 0) {
        throw IllegalArgumentException("划分比例s不能小于等于零")
    }
    return BigMoney(m.amount * BigInt(r) / BigInt(s), m.currency)
}

