public class MapOfNillableAnyResponseBuilder implements ResponseBuilder<HashMap<String, Object>> {
    @Override
    public HashMap<String, Object> build(RedisMessage message) {
        // Build list of key-value pairs from the Redis message
        List<KeyValue> keyValues = ResponseBuilderFactory.listOfKeyValueBuilder.build(message);
        HashMap<String, Object> results = new HashMap<>();

        for (KeyValue keyValue : keyValues) {
            // Extract and build the key as a String
            String key = ResponseBuilderFactory.stringBuilder.build(keyValue.getKey());
            // Build the value as a nillable (nullable) Object
            Object anyResult = ListOfNillableAnyResponseBuilder.buildToNillableAny(keyValue.getValue());
            results.put(key, anyResult);
        }

        return results;
    }
}

