public static BigMoney round(BigMoney m, long e) {
    if (e <= 0) {
        throw new IllegalArgumentException("精度 e 为正整数。");
    }

    BigInt absam;
    if (m.amount.compareTo(BigInt.ZERO) >= 0) {
        absam = m.amount;
    } else {
        absam = m.amount.negate();
    }

    // Compute 10^e as BigInt
    BigInt exp = BigInt.TEN.pow((int) e);
    BigInt dec = absam.remainder(exp);

    if (dec.compareTo(exp.divide(BigInt.TWO)) >= 0) {
        absam = absam.add(exp);
    }

    absam = absam.divide(exp).multiply(exp);

    if (m.amount.compareTo(BigInt.ZERO) < 0) {
        return new BigMoney(absam.negate(), m.currency);
    }

    return new BigMoney(absam, m.currency);
}

