private void afterNodeAccess(Entry<K, V> node) {
    Entry<K, V> last = tail;
    if (last != null) {
        if (last != node) {
            Entry<K, V> b = node.prev;
            Entry<K, V> a = node.next;

            node.next = null;

            if (b != null) {
                b.next = a;
            } else {
                head = a;
            }

            if (a != null) {
                a.prev = b;
            } else {
                tail = b;
            }
            node.prev = last;
            last.next = node;
            tail = node;
        }
    } else {
        head = node;
    }
}

