private Optional<ArrayList<String>> fuzzySearchMax(String src, int maxcost) {
    String closestMatch = "";
    ArrayList<String> closestCleanWords = new ArrayList<>();
    int minimumDistance = Integer.MAX_VALUE;
    List<String> keywords = getAllKeywords();
    for (String k : keywords) {
        int distance = levenshteinDistance(src, k);
        if (distance <= maxcost) {
            if (distance < minimumDistance) {
                minimumDistance = distance;
                closestMatch = k;
                closestCleanWords = getCleanwords(k);
            } else if (distance == minimumDistance && closestMatch.isEmpty()) {
                closestMatch = k;
                closestCleanWords = getCleanwords(k);
            }
        }
    }
    if (!closestMatch.isEmpty()) {
        return Optional.of(closestCleanWords);
    } else {
        return Optional.empty();
    }
}

