import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;

public class EngineTestCaseSuit {

    /**
     * 测试引擎创建 - 验证可以创建默认名称的引擎实例
     */
    @Test
    public void testEngineCreation() {
        JoyEngine engine = Joy.create();
        assertTrue("default".equals(engine.getName()));
    }

    /**
     * 测试自定义名称引擎创建 - 验证可以创建指定名称的引擎实例
     */
    @Test
    public void testEngineWithCustomName() {
        JoyEngine engine = Joy.create("testEngine");
        assertTrue("testEngine".equals(engine.getName()));
    }

    /**
     * 测试自定义配置引擎创建 - 验证可以使用自定义配置创建引擎实例
     */
    @Test
    public void testEngineWithCustomConfig() {
        JoyConfig config = new JoyConfig(
            new String[]{"X-Forwarded-For", "X-Real-IP"},
            true,
            true,
            64 * 1024 * 1024
        );
        JoyEngine engine = Joy.create(config, "customEngine");
        assertEquals(2, engine.getConfig().getRemoteIPHeaders().length);
        assertTrue(engine.getConfig().isCaseInsensitive());
        assertTrue(engine.getConfig().isEscapeAddedRoutes());
        assertEquals(64 * 1024 * 1024, engine.getConfig().getMaxRequestBodySize());
    }

