     * 测试引擎单例模式 - 验证相同名称的引擎实例是否为单例
     */
    @Test
    public void testEngineSingleton() {
        JoyEngine engine1 = Joy.create("testSingleton");
        assertTrue("testSingleton".equals(engine1.getName()));
        engine1.shutdown(); // 清理实例

        JoyEngine engine2 = Joy.create("testSingleton");
        assertTrue("testSingleton".equals(engine2.getName()));
        engine2.shutdown(); // 清理实例
