        String testService = "testServiceValue";
        engine.addService("testService", testService);

        Object retrievedService = engine.getService("testService");
        assertNotNull(retrievedService);
        assertEquals(testService, retrievedService);
    }

    /**
     * 测试获取不存在的服务 - 验证获取不存在的服务时返回 null
     */
    @Test
