     */
    @Test
    public void testConfigRemoteIPHeaders() {
        JoyConfig config = new JoyConfig(
            new String[]{"X-Forwarded-For", "X-Real-IP", "CF-Connecting-IP"},
            false, false, 0
        );

        assertEquals(3, config.getRemoteIPHeaders().length);
