public class Ite implements java.util.Iterator<Value> {
    private final java.util.List<Value> array;
    private int index;

    public Ite(java.util.List<Value> array) {
        this.array = array;
        this.index = 0;
    }

    @Override
    public boolean hasNext() {
        return index < array.size();
    }

    @Override
    public Value next() {
        if (!hasNext()) {
            throw new MessagePackException();
        }
        return array.get(index++);
    }
}

