private class Ite
        <: Iterator<Value>
{
    private let array: Array<Value>
    private var index: Int64

    public init(array: Array<Value>)
    {
        this.array = array
        this.index = 0
    }

    public override func next(): ?Value
    {
        var i = index
        if (i >= array.size) {
            throw MessagePackException()
        }
        index = i + 1
        return array[i]
    }
}

