import java.nio.charset.Charset;
import java.nio.charset.UnsupportedCharsetException;
import java.text.DecimalFormat;
import java.util.Arrays;

public class IccDescriptor extends TagDescriptor<IccDirectory> {
    public IccDescriptor(IccDirectory directory) {
        super(directory);
    }

    @Override
    public String getDescription(int tagType) {
        switch (tagType) {
            case 8:
                return getProfileVersionDescription();
            case 12:
                return getProfileClassDescription();
            case 40:
                return getPlatformDescription();
            case 64:
                return getRenderingIntentDescription();
            default:
                break;
        }
        if (tagType > 0x20202020 && tagType < 0x7a7a7a7a) {
            return getTagDataString(tagType);
        }
        return super.getDescription(tagType);
    }

    private static final int ICC_TAG_TYPE_TEXT = 0x74657874;
    private static final int ICC_TAG_TYPE_DESC = 0x64657363;
    private static final int ICC_TAG_TYPE_SIG = 0x73696720;
    private static final int ICC_TAG_TYPE_MEAS = 0x6D656173;
    private static final int ICC_TAG_TYPE_XYZ_ARRAY = 0x58595A20;
    private static final int ICC_TAG_TYPE_MLUC = 0x6d6c7563;
    private static final int ICC_TAG_TYPE_CURV = 0x63757276;

    private String getTagDataString(int tagType) {
        byte[] bytes = _directory.getByteArray(tagType);
        if (bytes == null || bytes.length == 0) {
            return _directory.getString(tagType);
        }
        ByteArrayReader reader = new ByteArrayReader(bytes);
        int iccTagType = reader.getInt32(0);
        switch (iccTagType) {
            case ICC_TAG_TYPE_TEXT:
                try {
                    // Skip first 8 bytes (header), then decode UTF-8 from index 8 to end-1
                    byte[] textBytes = Arrays.copyOfRange(bytes, 8, bytes.length - 1);
                    return OtherUtil.bytes2StringByCharset(textBytes, Charset.forName("UTF-8"));
                } catch (UnsupportedCharsetException ex) {
                    System.err.println("ASCII error " + ex.getMessage());
                    return new String(Arrays.copyOfRange(bytes, 8, bytes.length - 1), java.nio.charset.StandardCharsets.UTF_8);
                }
            case ICC_TAG_TYPE_DESC:
                int stringLength = reader.getInt32(8);
                int endIdx = Math.min(12 + stringLength, bytes.length);
                byte[] descBytes = Arrays.copyOfRange(bytes, 12, endIdx);
                return new String(descBytes, java.nio.charset.StandardCharsets.UTF_8);
            case ICC_TAG_TYPE_SIG:
                return IccReader.getStringFromInt32(reader.getInt32(8));
            case ICC_TAG_TYPE_MEAS:
                int observerType = reader.getInt32(8);
                float x = reader.getS15Fixed16(12);
                float y = reader.getS15Fixed16(16);
                float z = reader.getS15Fixed16(20);
                int geometryType = reader.getInt32(24);
                float flare = reader.getS15Fixed16(28);
                int illuminantType = reader.getInt32(32);

                String observerString;
                switch (observerType) {
                    case 0: observerString = "Unknown"; break;
                    case 1: observerString = "1931 2°"; break;
                    case 2: observerString = "1964 10°"; break;
                    default: observerString = "Unknown " + observerType; break;
                }

                String geometryString;
                switch (geometryType) {
                    case 0: geometryString = "Unknown"; break;
                    case 1: geometryString = "0/45 or 45/0"; break;
                    case 2: geometryString = "0/d or d/0"; break;
                    default: geometryString = "Unknown " + observerType; break;
                }

                String illuminantString;
                switch (illuminantType) {
                    case 0: illuminantString = "unknown"; break;
                    case 1: illuminantString = "D50"; break;
                    case 2: illuminantString = "D65"; break;
                    case 3: illuminantString = "D93"; break;
                    case 4: illuminantString = "F2"; break;
                    case 5: illuminantString = "D55"; break;
                    case 6: illuminantString = "A"; break;
                    case 7: illuminantString = "Equi-Power (E)"; break;
                    case 8: illuminantString = "F8"; break;
                    default: illuminantString = "Unknown " + illuminantType; break;
                }

                DecimalFormat format = new DecimalFormat("0.###");
                double flarePercent = Math.round(flare * 100.0);
                DecimalFormat flareFormat = new DecimalFormat("0.##");
                return String.format("%s Observer, Backing (%s, %s, %s), Geometry %s, Flare %s%%, Illuminant %s",
                        observerString,
                        format.format(x),
                        format.format(y),
                        format.format(z),
                        geometryString,
                        flareFormat.format(flarePercent),
                        illuminantString);
            case ICC_TAG_TYPE_XYZ_ARRAY:
                int count = (bytes.length - 8) / 12;
                StringBuilder xyzRes = new StringBuilder();
                DecimalFormat xyzFormat = new DecimalFormat("0.####");
                for (int i = 0; i < count; i++) {
                    int offset = 8 + i * 12;
                    float xVal = reader.getS15Fixed16(offset);
                    float yVal = reader.getS15Fixed16(offset + 4);
                    float zVal = reader.getS15Fixed16(offset + 8);
                    if (i > 0) {
                        xyzRes.append(", ");
                    }
                    xyzRes.append("(")
                            .append(xyzFormat.format(xVal))
                            .append(", ")
                            .append(xyzFormat.format(yVal))
                            .append(", ")
                            .append(xyzFormat.format(zVal))
                            .append(")");
                }
                return xyzRes.toString();
            case ICC_TAG_TYPE_MLUC:
                int int1 = reader.getInt32(8);
                StringBuilder mlucRes = new StringBuilder();
                mlucRes.append(int1);
                for (int i = 0; i < int1; i++) {
                    int baseOffset = 16 + i * 12;
                    int strCode = reader.getInt32(baseOffset);
                    int len = reader.getInt32(baseOffset + 4);
                    int ofs = reader.getInt32(baseOffset + 8);
                    String str = IccReader.getStringFromInt32(strCode);
                    String name = "";
                    try {
                        byte[] nameBytes = Arrays.copyOfRange(bytes, ofs, Math.min(ofs + len, bytes.length));
                        name = OtherUtil.bytes2StringByCharset(nameBytes, Charset.forName("UTF-16BE"));
                    } catch (UnsupportedCharsetException ex) {
                        try {
                            byte[] nameBytes = Arrays.copyOfRange(bytes, ofs, Math.min(ofs + len, bytes.length));
                            name = OtherUtil.bytes2StringByCharset(nameBytes, Charset.forName("UTF-8"));
                        } catch (UnsupportedCharsetException ex2) {
                            name = "";
                        }
                    }
                    mlucRes.append(" ").append(str).append("(").append(name).append(")");
                }
                return mlucRes.toString();
            case ICC_TAG_TYPE_CURV:
                int num = reader.getInt32(8);
                StringBuilder curvRes = new StringBuilder();
                for (int i = 0; i < num; i++) {
                    if (i != 0) {
                        curvRes.append(", ");
                    }
                    int value = reader.getUInt16(12 + i * 2);
                    double normalized = (double) value / 65535.0;
                    curvRes.append(formatDoubleAsString(normalized, 7, false));
                }
                return curvRes.toString();
            default:
                return IccReader.getStringFromInt32(iccTagType) + " (0x" + Integer.toHexString(iccTagType) + "): " + bytes.length + " bytes";
        }
    }

    public static String formatDoubleAsString(double value, long precision, boolean zeroes) {
        if (precision < 1) {
            return String.valueOf(Math.round(value));
        }
        long intPart = Math.abs((long) value);
        double fractional = Math.abs(value) - intPart;
        long rest = Math.round(fractional * Math.pow(10.0, precision));
        long restKept = rest;
        StringBuilder res = new StringBuilder();
        for (long i = precision; i >= 1; i--) {
            long digit = Math.abs(rest % 10);
            rest /= 10;
            if (res.length() > 0 || zeroes || digit != 0 || i == 1) {
                res.insert(0, digit);
            }
        }
        intPart += rest;
        boolean isNegative = (value < 0.0) && (intPart != 0 || restKept != 0);
        String str = isNegative ? "-" : "";
        return str + intPart + "." + res.toString();
    }

