            } catch (Exception e) {
                return str;
            }
        }
        return null;
    }

    private String getProfileVersionDescription() {
        Integer value = _directory.getInteger(IccDirectory.TAG_PROFILE_VERSION);
        if (value != null) {
            long v = value.longValue();
            int m = (int) ((v & 0xFF000000L) >> 24);
            int r = (int) ((v & 0x00F00000L) >> 20);
            int R = (int) ((v & 0x000F0000L) >> 16);
            return m + "." + r + "." + R;
        }
        return null;
    }

    private static long getInt32FromString(String string) {
