public class IccDescriptor <: TagDescriptor<IccDirectory> {
    public init(directory: IccDirectory) {
        super(directory)
    }

    public override func getDescription(tagType: Int32): ?String {
        match (tagType) {
            case 8 => return getProfileVersionDescription()
            case 12 => return getProfileClassDescription()
            case 40 => return getPlatformDescription()
            case 64 => return getRenderingIntentDescription()
            case _ => ()
        }
        if (tagType > 0x20202020 && tagType < 0x7a7a7a7a) {
            return getTagDataString(tagType)
        }
        return super.getDescription(tagType)
    }

    private static let ICC_TAG_TYPE_TEXT:Int32 = 0x74657874

    private static let ICC_TAG_TYPE_DESC:Int32 = 0x64657363

    private static let ICC_TAG_TYPE_SIG:Int32 = 0x73696720

    private static let ICC_TAG_TYPE_MEAS:Int32 = 0x6D656173

    private static let ICC_TAG_TYPE_XYZ_ARRAY:Int32 = 0x58595A20

    private static let ICC_TAG_TYPE_MLUC:Int32 = 0x6d6c7563

    private static let ICC_TAG_TYPE_CURV:Int32 = 0x63757276

    private func getTagDataString(tagType: Int32): ?String {
        if(let Some(bytes) <- _directory.getByteArray(tagType)) {
            if (bytes.isEmpty()) {
                return _directory.getString(tagType)
            }
            let reader = ByteArrayReader(bytes)
            let iccTagType = reader.getInt32(0)
            match (iccTagType) {
                case 0x74657874 =>
                    try {
                        return OtherUtil.bytes2StringByChartSet(bytes[8..(bytes.size-1)],Charsets.forName("UTF-8").getOrThrow())
                    } catch (ex: UnsupportedEncodingException) {
                        println("ASCII error " + ex.message)
                        return String.fromUtf8(bytes[8..(bytes.size-1)])
                    }
                case 0x64657363 =>
                    let stringLength = reader.getInt32(8)
                    return String.fromUtf8(bytes[12..Int64(stringLength+12 - 1)])
                case 0x73696720 =>
                    return IccReader.getStringFromInt32(reader.getInt32(8))
                case 0x6D656173 =>
                    let observerType = reader.getInt32(8)
                    let x = reader.getS15Fixed16(12)
                    let y = reader.getS15Fixed16(16)
                    let z = reader.getS15Fixed16(20)
                    let geometryType = reader.getInt32(24)
                    let flare = reader.getS15Fixed16(28)
                    let illuminantType = reader.getInt32(32)
                    let observerString: String
                    match (observerType) {
                        case 0 => observerString = "Unknown"
                        case 1 => observerString = "1931 2°"
                        case 2 => observerString = "1964 10°"
                        case _ => observerString = "Unknown ${observerType}"
                    }
                    let geometryString: String
                    match (geometryType) {
                        case 0 => geometryString = "Unknown"
                        case 1 => geometryString = "0/45 or 45/0"
                        case 2 => geometryString = "0/d or d/0"
                        case _ => geometryString = "Unknown ${observerType}"
                    }
                    let illuminantString: String
                    match (illuminantType) {
                        case 0 => illuminantString = "unknown"
                        case 1 => illuminantString = "D50"
                        case 2 => illuminantString = "D65"
                        case 3 => illuminantString = "D93"
                        case 4 => illuminantString = "F2"
                        case 5 => illuminantString = "D55"
                        case 6 => illuminantString = "A"
                        case 7 => illuminantString = "Equi-Power (E)"
                        case 8 => illuminantString = "F8"
                        case _ => illuminantString = "Unknown ${illuminantType}"
                    }
                    let format = "0.###"
                    return "${observerString} Observer, Backing (${OtherUtil.decimalFormat(Float64(x), format)}, ${OtherUtil.decimalFormat(Float64(y), format)}, ${OtherUtil.decimalFormat(Float64(z), format)}), Geometry ${geometryString}, Flare ${OtherUtil.decimalFormat(Float64(round(flare * 100.0)),"0.##")}%, Illuminant ${illuminantString}"
                case 0x58595A20 =>
                    let count = (bytes.size - 8) / 12
                    let res = StringBuilder()
                    let format = "0.####"
                    for (i in 0..count) {
                        let x = reader.getS15Fixed16(Int32(8 + i * 12))
                        let y = reader.getS15Fixed16(Int32(8 + i * 12 + 4))
                        let z = reader.getS15Fixed16(Int32(8 + i * 12 + 8))
                        if (i > 0) {
                            res.append(", ")
                        }
                        res.append("(")
                        res.append(OtherUtil.decimalFormat(Float64(x), format))
                        res.append(", ")
                        res.append(OtherUtil.decimalFormat(Float64(y), format))
                        res.append(", ")
                        res.append(OtherUtil.decimalFormat(Float64(z), format))
                        res.append(")")
                    }
                    return res.toString()
                case 0x6d6c7563 =>
                    let int1 = reader.getInt32(8)
                    let res = StringBuilder()
                    res.append(int1)
                    for (i in 0..int1) {
                        let str = IccReader.getStringFromInt32(reader.getInt32(Int32(16 + i * 12)))
                        let len = reader.getInt32(Int32(16 + i * 12 + 4))
                        let ofs = reader.getInt32(Int32(16 + i * 12 + 8))
                        var name: String = ""
                        try {
                            name = OtherUtil.bytes2StringByChartSet(bytes[Int64(ofs)..Int64(ofs+len)],Charsets.forName("UTF-16BE").getOrThrow())
                        } catch (ex: UnsupportedEncodingException) {
                            name = OtherUtil.bytes2StringByChartSet(bytes[Int64(ofs)..Int64(ofs+len)],Charsets.forName("UTF-8").getOrThrow())
                        }
                        res.append(" ")
                        res.append(str)
                        res.append("(")
                        res.append(name)
                        res.append(")")
                    }
                    return res.toString()
                case 0x63757276 =>
                    let num = reader.getInt32(8)
                    let res = StringBuilder()
                    for (i in 0..num) {
                        if (i != 0) {
                            res.append(", ")
                        }
                        res.append(formatDoubleAsString(Float64(Float32(reader.getUInt16(Int32(12 + i * 2)))) / 65535.0, 7, false))
                    }
                    return res.toString()
                case _ => return "${IccReader.getStringFromInt32(iccTagType)} (${iccTagType.format("#x")}): ${bytes.size} bytes"
            }
        }
        return None

    }

    public static func formatDoubleAsString(value: Float64, precision: Int64, zeroes: Bool): String {
        if (precision < 1) {
            return "" + round(value).toString()
        }
        var intPart = Int64(abs(value))
        var rest = Int64(round((abs(value) - Float64(intPart)) * Float64(pow(10.0, Float64(precision)))))
        var restKept = rest
        var res: String = ""
        var cour: UInt8 = 0
        for (i in precision..0:-1) {
            cour = UInt8(abs(rest % 10))
            rest /= 10
            if (Int64(res.size) > 0 || zeroes || Int64(cour) != 0 || i == 1) {
                res = cour.toString() + (res)
            }
        }
        intPart += rest
        let isNegative = ((value < 0.0) && (intPart != 0 || restKept != 0))
        var str = ""
        if (isNegative) {
            str = "-"
        }
        return "${str}${intPart.toString()}.${res}"
    }

    private func getRenderingIntentDescription(): ?String {
        return getIndexedDescription(IccDirectory.TAG_RENDERING_INTENT, ["Perceptual", "Media-Relative Colorimetric", "Saturation", "ICC-Absolute Colorimetric"])
    }

    private func getPlatformDescription(): ?String {
        if(let Some(str) <- _directory.getString(IccDirectory.TAG_PLATFORM)){
            let i: Int64
            try {
                i = getInt32FromString(str)
            } catch (e: Exception) {
                return str
            }
            match (i) {
                case 0x4150504C => return "Apple Computer, Inc."
                case 0x4D534654 => return "Microsoft Corporation"
                case 0x53474920 => return "Silicon Graphics, Inc."
                case 0x53554E57 => return "Sun Microsystems, Inc."
                case 0x54474E54 => return "Taligent, Inc."
                case _ => return "Unknown (${str})"
            }
        }
        return None
    }

    private func getProfileClassDescription(): ?String {
        if(let Some(str) <- _directory.getString(IccDirectory.TAG_PROFILE_CLASS)){
            let i: Int64
            try {
                i = getInt32FromString(str)
            } catch (e: Exception) {
                return str
            }
            match (i) {
                case 0x73636E72 => return "Input Device"
                case 0x6D6E7472 => return "Display Device"
                case 0x70727472 => return "Output Device"
                case 0x6C696E6B => return "DeviceLink"
                case 0x73706163 => return "ColorSpace Conversion"
                case 0x61627374 => return "Abstract"
                case 0x6E6D636C => return "Named Color"
                case _ => return "Unknown (${str})"
            }
        }
        return None
    }

    private func getProfileVersionDescription(): ?String {
        if(let Some(value) <- _directory.getInteger(IccDirectory.TAG_PROFILE_VERSION)){
            let m = (Int64(value) & 0xFF000000) >> 24
            let r = (Int64(value) & 0x00F00000) >> 20
            let R = (Int64(value) & 0x000F0000) >> 16
            return "${m}.${r}.${R}"
        }
        return None
    }

    private static func getInt32FromString(string: String): Int64 {
        let bytes = string.toArray()
        return Int64(ByteArrayReader(bytes).getInt32(0))
    }
}

