            double y = bounds.y + bounds.height / 2.0;
            painter.drawLine(
                new Position(bounds.x, y),
                new Position(bounds.x + bounds.width, y),
                theme.separatorColor(),
                1.0
            );
            break;
        case VERTICAL:
            double x = bounds.x + bounds.width / 2.0;
            painter.drawLine(
                new Position(x, bounds.y),
                new Position(x, bounds.y + bounds.height),
                theme.separatorColor(),
                1.0
            );
            break;
    }
}

