public Future<TransactionInfo, DatabaseError> beginTransaction(
        IsolationLevel isolationLevel,
        boolean readOnly) {
    return new Future<>(() -> {
        if (transactionManager.hasActiveTransaction()) {
            return Result.err(new DatabaseError(
                    "TRANSACTION_EXISTS",
                    "Transaction already active"
            ));
        }

        String transactionId = generateTransactionId();

        // Set isolation level
        String isolationStatement = getIsolationLevelStatement(isolationLevel);
        Result<DatabaseResult, DatabaseError> isolationResult =
                executeUpdateInternal(isolationStatement, new String[0], new QueryOptions());

        if (isolationResult.isErr()) {
            return Result.err(isolationResult.unwrapErr());
        }

        // Begin transaction
        String beginStatement = "BEGIN TRANSACTION";
        Result<DatabaseResult, DatabaseError> beginResult =
                executeUpdateInternal(beginStatement, new String[0], new QueryOptions());

        if (beginResult.isErr()) {
            return Result.err(beginResult.unwrapErr());
        }

        // Create transaction info
        TransactionInfo transactionInfo = new TransactionInfo(
                transactionId,
                isolationLevel,
                readOnly
        );

        transactionManager.beginTransaction(transactionInfo);

        return Result.ok(transactionInfo);
    });
}

