        isolationLevel: IsolationLevel = IsolationLevel.ReadCommitted,
        readOnly: Bool = false
    ) -> Future<TransactionInfo, DatabaseError> {
        return Future<TransactionInfo, DatabaseError> { () -> Result<TransactionInfo, DatabaseError> in
            if (transactionManager.hasActiveTransaction()) {
                return Err<TransactionInfo, DatabaseError>(DatabaseError(
                    code: "TRANSACTION_EXISTS",
                    message: "Transaction already active"
                ))
            }

            let transactionId = generateTransactionId()

            // Set isolation level
            let isolationStatement = getIsolationLevelStatement(isolationLevel)
            let isolationResult = executeUpdateInternal(isolationStatement, Array<String>(), QueryOptions())

            if (isolationResult is Err) {
                return Err<TransactionInfo, DatabaseError>((isolationResult as Err<DatabaseResult, DatabaseError>).value)
            }

            // Begin transaction
            let beginStatement = "BEGIN TRANSACTION"
            let beginResult = executeUpdateInternal(beginStatement, Array<String>(), QueryOptions())

            if (beginResult is Err) {
                return Err<TransactionInfo, DatabaseError>((beginResult as Err<DatabaseResult, DatabaseError>).value)
            }

            // Create transaction info
            let transactionInfo = TransactionInfo(
                transactionId: transactionId,
                isolationLevel: isolationLevel,
                readOnly: readOnly
            )

            transactionManager.beginTransaction(transactionInfo)

            return Ok<TransactionInfo, DatabaseError>(transactionInfo)
        }
