public class Deinterlace {
    public static byte[] deinterlace(byte[] pixels, int width) {
        // Calculate number of rows, rounding up to handle partial last row
        long rows = (long) pixels.length / width;
        long quyu = (long) pixels.length % width;
        if (quyu > 0) {
            rows++;
        }

        // Initialize new pixel array with same size as input
        byte[] newPixels = new byte[pixels.length];

        // Helper method to copy a row from pixels to newPixels
        // fromRow: source row index (0-based)
        // toRow: destination row index (0-based)
        // Each row has 'width' elements, but last row may be shorter
        java.util.function.BiConsumer<Long, Long> cpRow = (toRow, fromRow) -> {
            long fromStart = fromRow * width;
            long len = width; // nominal length
            if (fromStart + len > pixels.length) {
                len = pixels.length - fromStart;
            }
            if (len > 0) {
                int srcPos = (int) fromStart;
                int dstPos = (int) (toRow * width);
                int copyLen = (int) len;
                System.arraycopy(pixels, srcPos, newPixels, dstPos, copyLen);
            }
        };

        // Interlacing parameters: offsets and step sizes for 4 passes
        long[] offsets = {0, 4, 2, 1};
        long[] steps = {8, 8, 4, 2};

        long fromRow = 0;
        for (int pass = 0; pass < 4; pass++) {
            long toRow = offsets[pass];
            while (toRow < rows) {
                // Copy row 'fromRow' from input to row 'toRow' in output
                cpRow.accept(toRow, fromRow);
                fromRow++;
                toRow += steps[pass];
            }
        }

        return newPixels;
    }

    // Example main method for testing (if needed as standalone)
