import java.util.Objects;

public class VectorUtils {
    public static <T extends CNumber<T>> Vector<T> apply2(Vector<T> x, Vector<T> y,
            java.util.function.BinaryOperator<T> f) {
        if (x.size() != y.size()) {
            throw new IllegalArgumentException("apply2: dimension mismatch");
        }

        int size = x.size();
        Vector<T> res = new Vector<>(size);
        for (int i = 0; i < size; i++) {
            res.set(i, f.apply(x.get(i), y.get(i)));
        }
        return res;
    }
}

