public func apply2<T>(x: Vector<T>, y: Vector<T>, f: (T, T) -> T): Vector<T> where T <: CNumber<T> {
    if (x.size() != y.size()) {
        throw IllegalArgumentException("apply2: dimension mismatch")
    }

    let size = x.size()
    let res = Vector<T>(size)
    for (i in 0..size) {
        res[i] = f(x[i], y[i])
    }
    return res
}

