public static void genCodeMessageField(String typeName, ArrayList<FieldDescriptorProto> fields, GenCodeHelper helper) {
    StringBuilder outbuf = helper.outbuf;
    LineSepOut sepOut = new LineSepOut(outbuf);

    // class
    outbuf.append("\npublic class ").append(typeName).append(" extends MessageLite {\n");

    // accessors
    outbuf.append("    private static final HashMap<Integer, Accessor> m_accessors = new HashMap<>(Map.of(\n");
    for (FieldDescriptorProto f : fields) {
        sepOut.append("(" + f.getNumber() + ", " + getAccesor(f) + ".getInstance())");
    }
    outbuf.append("\n    ));\n    protected HashMap<Integer, Accessor> getAccessors() { return m_accessors; }\n");

    // names
    outbuf.append("\n    private static final HashMap<Integer, String> m_names = new HashMap<>(Map.of(\n");
    sepOut.reset();
    for (FieldDescriptorProto f : fields) {
        sepOut.append("(" + f.getNumber() + ", \"" + f.getName() + "\")");
    }
    outbuf.append("\n    ));\n    protected HashMap<Integer, String> getNames() { return m_names; }\n");

    // default value
    ArrayList<String> dvs = new ArrayList<>();
    for (FieldDescriptorProto f : fields) {
        try {
            String dvStr = f.getDefaultValue();
            String dv;
            switch (f.getType()) {
                case TYPE_STRING:
                    dv = "\"" + dvStr + "\"";
                    break;
                case TYPE_BOOL:
                case TYPE_INT64:
                case TYPE_DOUBLE:
                    dv = dvStr;
                    break;
                case TYPE_ENUM:
                    dv = getPropType(f) + "." + dvStr;
                    break;
                default:
                    dv = getPropType(f) + "(" + dvStr + ")";
                    break;
            }
            dvs.add("(" + f.getNumber() + ", " + dv + ")");
        } catch (Exception ignored) {
            continue;
        }
    }
    if (!dvs.isEmpty()) {
        outbuf.append("\n    private static final HashMap<Integer, Object> m_dv = new HashMap<>(Map.of(\n");
        sepOut.reset();
        for (String dv : dvs) {
            sepOut.append(dv);
        }
        outbuf.append("\n    ));\n    protected HashMap<Integer, Object> getDefaultValue() { return m_dv; }\n");
    }

    // required fields
    ArrayList<Integer> reqs = new ArrayList<>();
    for (FieldDescriptorProto f : fields) {
        if (f.getLabel() == FieldDescriptorProto.Label.LABEL_REQUIRED) {
            reqs.add(f.getNumber());
        }
    }
    if (!reqs.isEmpty()) {
        outbuf.append("\n    private static final int[] m_reqs = new int[]{\n");
        sepOut.reset();
        for (int i = 0; i < reqs.size(); i++) {
            if (i > 0) sepOut.append(",");
            sepOut.append(reqs.get(i).toString());
        }
        outbuf.append("\n    };\n    protected int[] getRequiredFields() { return m_reqs; }\n");
    }

    // oneof
    if (helper.oneofNum != 0) {
        outbuf.append("\n    private final int[] m_oneofCase = new int[").append(helper.oneofNum).append("];\n");
        outbuf.append("    protected int[] getOneofCase() { return m_oneofCase; }\n");
        outbuf.append("    private static final HashMap<Integer, Long> m_oneofIdx = new HashMap<>(Map.of(\n");
        sepOut.reset();
        for (FieldDescriptorProto f : fields) {
            try {
                if (f.hasOneofIndex()) {
                    sepOut.append("(" + f.getNumber() + ", " + f.getOneofIndex() + "L)");
                }
            } catch (Exception ignored) {
                continue;
            }
        }
        outbuf.append("\n    ));\n    protected HashMap<Integer, Long> getOneofIndex() { return m_oneofIdx; }\n");
    }

    // clone
    outbuf.append("\n    public ").append(typeName).append(" clone() { ").append(typeName).append(" rv = new ").append(typeName).append("(); rv.m_fields = m_fieldsClone(); return rv; }\n");
    if (!helper.proto2) {
        outbuf.append("    protected boolean m_proto2() { return false; }\n");
    }

    // props
    for (FieldDescriptorProto f : fields) {
        String propType = getPropType(f);
        outbuf.append("\n    public ").append(propType).append(" get").append(capitalize(f.getName())).append("() { return get(").append(f.getNumber()).append("); }\n");
        outbuf.append("    public void set").append(capitalize(f.getName())).append("(").append(propType).append(" v) { set(").append(f.getNumber()).append(", v); }\n");
    }

    outbuf.append("}\n");

    // extend
    outbuf.append("\n// Extension for Default interface\n");
    outbuf.append("class ").append(typeName).append("Default extends ").append(typeName).append(" implements Default<").append(typeName).append("> {\n");
    outbuf.append("    public static ").append(typeName).append(" createDefault() { return new ").append(typeName).append("(); }\n");
    outbuf.append("}\n");
}

private static String capitalize(String str) {
    if (str == null || str.isEmpty()) return str;
    return str.substring(0, 1).toUpperCase() + str.substring(1);
}

