import java.util.*;

public final class Status implements Comparable<Status> {
    private static final long CONST_INIT = 0x1L;
    private static final long CONST_DECL = 0x1L << 1;
    private static final long CONST_COMMENT = 0x1L << 2;
    private static final long CONST_PROC_INST = 0x1L << 3;
    private static final long CONST_DTD = 0x1L << 4;
    private static final long CONST_ELEMENT_START = 0x1L << 5;
    private static final long CONST_ELEMENT_END = 0x1L << 6;
    private static final long CONST_ELEMENT_EMPTY = 0x1L << 7;
    private static final long CONST_ATTRIBUTE = 0x1L << 8;
    private static final long CONST_NAMESPACE = 0x1L << 9;
    private static final long CONST_TEXT = 0x1L << 10;
    private static final long CONST_CDATA = 0x1L << 11;
    private static final long CONST_ENTITY_REF = 0x1L << 12;
    private static final long CONST_MARKUP_END = 0x1L << 13;
    private static final long CONST_EOF = 0x1L << 63;

    public static final Status Init = new Status(CONST_INIT);
    public static final Status Decl = new Status(CONST_DECL);
    public static final Status Comment = new Status(CONST_COMMENT);
    public static final Status ProcInst = new Status(CONST_PROC_INST);
    public static final Status DTD = new Status(CONST_DTD);
    public static final Status ElementStart = new Status(CONST_ELEMENT_START);
    public static final Status ElementEnd = new Status(CONST_ELEMENT_END);
    public static final Status ElementEmpty = new Status(CONST_ELEMENT_EMPTY);
    public static final Status Attribute = new Status(CONST_ATTRIBUTE);
    public static final Status Namespace = new Status(CONST_NAMESPACE);
    public static final Status Text = new Status(CONST_TEXT);
    public static final Status CData = new Status(CONST_CDATA);
    public static final Status EntityRef = new Status(CONST_ENTITY_REF);
    public static final Status MarkupClose = new Status(CONST_MARKUP_END);
    public static final Status EOF = new Status(CONST_EOF);

    private final long v;

    private Status(long v) {
        this.v = v;
    }

    public Status or(Status other) {
        return new Status(this.v | other.v);
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        Status status = (Status) obj;
        return v == status.v;
    }

    @Override
    public int hashCode() {
        return Long.hashCode(v);
    }

    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder();
        boolean addPrefix = false;
        addPrefix = checkAndAppend(Init, "Init", sb, addPrefix);
        addPrefix = checkAndAppend(Decl, "Decl", sb, addPrefix);
        addPrefix = checkAndAppend(Comment, "Comment", sb, addPrefix);
        addPrefix = checkAndAppend(ProcInst, "ProcInst", sb, addPrefix);
        addPrefix = checkAndAppend(DTD, "DTD", sb, addPrefix);
        addPrefix = checkAndAppend(ElementStart, "ElementStart", sb, addPrefix);
        addPrefix = checkAndAppend(ElementEnd, "ElementEnd", sb, addPrefix);
        addPrefix = checkAndAppend(ElementEmpty, "ElementEmpty", sb, addPrefix);
        addPrefix = checkAndAppend(Attribute, "Attribute", sb, addPrefix);
        addPrefix = checkAndAppend(Namespace, "Namespace", sb, addPrefix);
        addPrefix = checkAndAppend(Text, "Text", sb, addPrefix);
        addPrefix = checkAndAppend(CData, "CData", sb, addPrefix);
        addPrefix = checkAndAppend(EntityRef, "EntityRef", sb, addPrefix);
        addPrefix = checkAndAppend(MarkupClose, "MarkupClose", sb, addPrefix);
        addPrefix = checkAndAppend(EOF, "EOF", sb, addPrefix);
        return sb.toString();
    }

    private boolean checkAndAppend(Status expect, String name, StringBuilder sb, boolean addPrefix) {
        if ((this.v & expect.v) != 0) {
            if (addPrefix) {
                sb.append(" | ");
            }
            sb.append(name);
            return true;
        }
        return false;
    }

    public void assertStatus(Status expect) {
        if (!check(expect)) {
